import type { EntityManager } from "typeorm";
import type { OutboxService } from "../../outbox/outbox.service";
import { assertLedgerLinesFinanceTenantScope, normalizeFinanceTenantId } from "./ledger-tenant-scope";
import type { LedgerJournalLine } from "./ledger-journal-line";

/**
 * Transactional outbox for **finance ledger** facts (`postDoubleEntryJournal` batches).
 * Must run on the same {@link EntityManager} as the registration / payment domain write.
 *
 * **Tenant isolation:** every line’s `tenantId` must match {@link input.tenantId} (normalized); otherwise throws before enqueue.
 */
export async function emitFinanceLedgerDoubleEntryAppliedOutbox(input: {
  manager: EntityManager;
  outboxService: OutboxService;
  tenantId: string;
  registrationId: string;
  lines: readonly LedgerJournalLine[];
  /**
   * Overrides deterministic dedupe id (default: `finance.ledger:{registrationId}:{firstLine.idempotencyKey}`).
   * Used for stable anchors such as synthetic payment-capture rows that must not collide with reversal ids.
   */
  domainEventIdOverride?: string | null;
}): Promise<void> {
  if (input.lines.length === 0) {
    return;
  }
  const tenantIdNorm = normalizeFinanceTenantId(input.tenantId);
  assertLedgerLinesFinanceTenantScope(tenantIdNorm, input.lines);
  const primary = input.lines[0]!;
  const override = input.domainEventIdOverride?.trim();
  const domainRaw =
    override !== undefined && override !== ""
      ? override
      : `finance.ledger:${input.registrationId}:${primary.idempotencyKey}`;
  const domainEventId = domainRaw.length > 128 ? domainRaw.slice(0, 128) : domainRaw;

  await input.outboxService.addEvent(input.manager, {
    tenantId: tenantIdNorm,
    aggregateType: "FinanceLedger",
    aggregateId: primary.journalId,
    eventType: "finance.ledger.double_entry_applied",
    domainEventId,
    payload: {
      entityType: "finance_ledger_journal",
      registrationId: input.registrationId,
      journalId: primary.journalId,
      lines: input.lines.map((l) => ({
        id: l.id,
        journalId: l.journalId,
        tenantId: l.tenantId,
        account: l.account,
        side: l.side,
        amount_minor: l.amount_minor,
        currency: l.currency,
        correlationId: l.correlationId,
        idempotencyKey: l.idempotencyKey,
        createdAt: l.createdAt,
        ...(l.reversesLineId !== undefined ? { reversesLineId: l.reversesLineId } : {}),
        ...(l.metadata !== undefined ? { metadata: l.metadata } : {})
      }))
    }
  });
}

import type { LedgerJournalLine } from "./ledger-journal-line";

type TwoLineJournal = {
  journalId: string;
  lines: [LedgerJournalLine, LedgerJournalLine];
};

/**
 * Makes in-memory journal lines non-mutable (shallow freeze of line + metadata object).
 * Persisted rows must additionally use INSERT-only repositories and DB forbid-UPDATE triggers.
 */
export function freezeLedgerJournalLine(line: LedgerJournalLine): LedgerJournalLine {
  if (line.metadata !== undefined) {
    Object.freeze(line.metadata);
  }
  return Object.freeze(line);
}

export function freezePostDoubleEntryJournalResult(result: TwoLineJournal): TwoLineJournal {
  const a = freezeLedgerJournalLine(result.lines[0]!);
  const b = freezeLedgerJournalLine(result.lines[1]!);
  return Object.freeze({
    journalId: result.journalId,
    lines: Object.freeze([a, b]) as [LedgerJournalLine, LedgerJournalLine]
  });
}

import type { LedgerJournalLine } from "./ledger-journal-line";

/**
 * Canonical tenant id for finance invariants (matches outbox / UUID normalization elsewhere).
 */
export function normalizeFinanceTenantId(raw: string): string {
  const t = raw.trim().toLowerCase();
  if (t.length === 0) {
    throw new Error("FINANCE_TENANT_ID_REQUIRED: tenant_id must be non-empty for finance scope");
  }
  return t;
}

/**
 * Ensures every ledger line belongs to the same workspace as the transactional envelope
 * (outbox row, reconciliation run, etc.). Prevents accidental cross-tenant joins or mixed batches.
 */
export function assertLedgerLinesFinanceTenantScope(
  envelopeTenantId: string,
  lines: readonly LedgerJournalLine[]
): void {
  const envelope = normalizeFinanceTenantId(envelopeTenantId);
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]!;
    const lineTenant = normalizeFinanceTenantId(line.tenantId);
    if (lineTenant !== envelope) {
      throw new Error(
        `FINANCE_LEDGER_TENANT_MISMATCH: line[${i}] id=${line.id} tenant_id=${lineTenant} does not match envelope tenant_id=${envelope}`
      );
    }
  }
}

import {
  LedgerEntrySchema,
  type LedgerEntry,
  type LedgerJournal,
} from "@repo/shared-contracts";
import type { LedgerJournalLineEntity } from "./entities/ledger-journal-line.entity";
import { ledgerJournalLineEntityToDomain } from "./ledger-journal-line.mapper";
import type { LedgerJournalLine } from "./ledger-journal-line";

function toIsoDateTimeString(value: unknown): string {
  if (value instanceof Date) {
    return value.toISOString();
  }
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed.length > 0) {
      return trimmed;
    }
  }
  return new Date(0).toISOString();
}

function toPositiveAmountMinorString(value: unknown): string {
  if (typeof value === "bigint") {
    return value > 0n ? value.toString() : "1";
  }
  if (typeof value === "number" && Number.isFinite(value)) {
    const n = Math.trunc(value);
    return n > 0 ? String(n) : "1";
  }
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (/^\d+$/.test(trimmed) && trimmed !== "0") {
      return trimmed;
    }
  }
  return "1";
}

function toCurrencyCode(value: unknown): string {
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed.length > 0) {
      return trimmed.toUpperCase();
    }
  }
  return "USD";
}

/**
 * Maps a domain {@link LedgerJournalLine} to the wire {@link LedgerEntry} shape (no Zod parse).
 */
export function toLedgerEntry(line: LedgerJournalLine): LedgerEntry {
  const entry: LedgerEntry = {
    id: line.id,
    journalId: line.journalId,
    tenantId: line.tenantId,
    accountId: line.account.trim(),
    side: line.side,
    amountMinor: toPositiveAmountMinorString(line.amount_minor),
    currency: toCurrencyCode(line.currency),
    correlationId: line.correlationId.trim(),
    idempotencyKey: line.idempotencyKey.trim(),
    createdAt: toIsoDateTimeString(line.createdAt),
  };
  if (line.reversesLineId !== undefined && line.reversesLineId !== null) {
    entry.reversesLineId = line.reversesLineId;
  }
  if (line.metadata !== undefined) {
    entry.metadata = line.metadata;
  }
  return entry;
}

/** Maps a persisted {@link LedgerJournalLineEntity} via the existing domain mapper. */
export function toLedgerEntryFromEntity(row: LedgerJournalLineEntity): LedgerEntry {
  return toLedgerEntry(ledgerJournalLineEntityToDomain(row));
}

/** Strict validation — throws {@link ZodError} on contract mismatch. */
export function validateLedgerEntry(entry: LedgerEntry): LedgerEntry {
  return LedgerEntrySchema.parse(entry);
}

/** Maps domain lines to {@link LedgerJournal} (used by strict enforcement before persist). */
export function toLedgerJournalContractStrict(lines: readonly LedgerJournalLine[]): LedgerJournal {
  if (lines.length === 0) {
    throw new Error("LEDGER_JOURNAL_LINES_REQUIRED: at least one line is required");
  }
  const entries = lines.map((line) => toLedgerEntry(line));
  return {
    journalId: entries[0]!.journalId,
    tenantId: entries[0]!.tenantId,
    lines: entries,
  };
}

/** Normalize `payments.amount` to a positive integer minor-unit string for ledger posting. */
export function paymentAmountToLedgerMinorString(amount: string): string {
  const normalized = amount.trim().replace(/,/g, "");
  if (/^\d+$/.test(normalized)) {
    const n = BigInt(normalized);
    if (n <= 0n) {
      throw new Error("LEDGER_PAYMENT_AMOUNT: payment.amount must be a positive integer minor string");
    }
    return n.toString();
  }
  const m = /^(\d+)\.(\d+)$/.exec(normalized);
  if (m) {
    const frac = m[2]!;
    if (!/^0+$/.test(frac)) {
      throw new Error(
        "LEDGER_PAYMENT_AMOUNT: fractional minor units are not supported for payment capture"
      );
    }
    const n = BigInt(m[1]!);
    if (n <= 0n) {
      throw new Error("LEDGER_PAYMENT_AMOUNT: payment.amount must be positive");
    }
    return n.toString();
  }
  throw new Error(`LEDGER_PAYMENT_AMOUNT: unsupported payment.amount format: ${amount}`);
}

import { createHash } from "node:crypto";

/**
 * Deterministic UUID-shaped ids so a **synthetic payment-capture journal** (same economic posting as
 * checkout / leader clearing → booking wallet) can be replayed idempotently and linked from refund
 * reversal lines via {@link LedgerJournalLine.reversesLineId}.
 */
export function stablePaymentCaptureLedgerIdentifiers(paymentId: string): {
  journalId: string;
  debitLineId: string;
  creditLineId: string;
} {
  const id = paymentId.trim();
  return {
    journalId: deterministicUuidFromSeed(`payment-ledger:journal:${id}`),
    debitLineId: deterministicUuidFromSeed(`payment-ledger:debit:${id}`),
    creditLineId: deterministicUuidFromSeed(`payment-ledger:credit:${id}`)
  };
}

function deterministicUuidFromSeed(seed: string): string {
  const h = createHash("sha256").update(seed, "utf8").digest();
  const buf = Buffer.alloc(16);
  h.copy(buf, 0, 0, 16);
  buf[6] = (buf[6]! & 0x0f) | 0x40;
  buf[8] = (buf[8]! & 0x3f) | 0x80;
  const hex = buf.toString("hex");
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
}

import type { EntityManager } from "typeorm";
import { AccountBalanceEntity } from "./entities/account-balance.entity";
import { normalizeFinanceTenantId } from "./ledger-tenant-scope";
import type { LedgerJournalLine } from "./ledger-journal-line";

/**
 * Read model snapshot for a wallet — authoritative when loaded via {@link calculateWalletBalance}.
 */
export type WalletProjection = {
  tenantId: string;
  /** Ledger account id (same convention as `LedgerJournalLine.account`). */
  ledgerAccount: string;
  /** Sum of signed `amount_minor` for included rows (minor units): credits +, debits −. */
  balance_minor: string;
  currency: string;
  asOfLineId: string | null;
  asOfCreatedAt: string | null;
  entryCount: number;
};

/**
 * Authoritative wallet balance: single-row read from `account_balances`.
 */
export async function calculateWalletBalance(
  manager: EntityManager,
  tenantId: string,
  ledgerAccount: string,
  currency: string
): Promise<WalletProjection> {
  const tenantNorm = normalizeFinanceTenantId(tenantId);
  const currencyNorm = currency.trim() || "UNK";
  const row = await manager.findOne(AccountBalanceEntity, {
    where: { tenantId: tenantNorm, account: ledgerAccount, currency: currencyNorm }
  });

  if (!row) {
    return {
      tenantId: tenantNorm,
      ledgerAccount,
      balance_minor: "0",
      currency: "",
      asOfLineId: null,
      asOfCreatedAt: null,
      entryCount: 0
    };
  }

  return {
    tenantId: tenantNorm,
    ledgerAccount,
    balance_minor: row.balanceMinor,
    currency: row.currency,
    asOfLineId: null,
    asOfCreatedAt: row.updatedAt.toISOString(),
    entryCount: -1
  };
}

/**
 * Derived balance from an in-memory line slice (non-authoritative; invoices / legacy tests).
 */
export function sumWalletBalanceFromLedgerLines(
  tenantId: string,
  ledgerAccount: string,
  lines: LedgerJournalLine[]
): WalletProjection {
  const tenantNorm = normalizeFinanceTenantId(tenantId);
  for (const line of lines) {
    if (normalizeFinanceTenantId(line.tenantId) !== tenantNorm) {
      throw new Error(
        `FINANCE_WALLET_TENANT_SCOPE: ledger line ${line.id} tenant_id does not match projection tenant_id (refuse cross-tenant aggregation)`
      );
    }
  }
  const scoped = lines
    .filter((x) => x.account === ledgerAccount)
    .sort((a, b) => a.createdAt.localeCompare(b.createdAt) || a.id.localeCompare(b.id));
  if (scoped.length === 0) {
    return {
      tenantId: tenantNorm,
      ledgerAccount,
      balance_minor: "0",
      currency: "",
      asOfLineId: null,
      asOfCreatedAt: null,
      entryCount: 0
    };
  }
  let balance = 0n;
  for (const line of scoped) {
    const a = BigInt(line.amount_minor);
    balance += line.side === "credit" ? a : -a;
  }
  const last = scoped[scoped.length - 1]!;
  return {
    tenantId: tenantNorm,
    ledgerAccount,
    balance_minor: balance.toString(),
    currency: last.currency,
    asOfLineId: last.id,
    asOfCreatedAt: last.createdAt,
    entryCount: scoped.length
  };
}

