function dedupeUuidStrings(ids: unknown[]): string[] {
  const out: string[] = [];
  const seen = new Set<string>();
  for (const x of ids) {
    if (typeof x !== "string") {
      continue;
    }
    const t = x.trim();
    if (!t || seen.has(t)) {
      continue;
    }
    seen.add(t);
    out.push(t);
  }
  return out;
}

/**
 * Collects workspace-catalog UUID references stored in trip JSONB
 * (`gear*Ids`, `tourThemeIds`, `guideLanguageIds`).
 */
export function collectWorkspaceCatalogIds(trip: TourTripDetails | null | undefined): {
  equipmentIds: string[];
  tourThemeIds: string[];
  guideLanguageIds: string[];
} {
  if (trip == null || typeof trip !== "object") {
    return { equipmentIds: [], tourThemeIds: [], guideLanguageIds: [] };
  }

  const p = trip.participation;
  const o = trip.overview;
  const l = trip.logistics;

  const gearReq = Array.isArray(p?.gearRequiredIds) ? p!.gearRequiredIds : [];
  const gearOpt = Array.isArray(p?.gearOptionalIds) ? p!.gearOptionalIds : [];

  return {
    equipmentIds: dedupeUuidStrings([...gearReq, ...gearOpt]),
    tourThemeIds: dedupeStringsSafe(o?.tourThemeIds),
    guideLanguageIds: dedupeStringsSafe(l?.guideLanguageIds),
  };
}

function dedupeStringsSafe(raw: unknown): string[] {
  return Array.isArray(raw) ? dedupeUuidStrings(raw) : [];
}

import type { TourFormProfile } from "@repo/types";
import {
  URBAN_LOGISTICS_WHITELIST_KEYS,
  isDenaliTourKind,
} from "@repo/types";

import type { CreateTourDto } from "../dto/create-tour.dto";
import type { TourEntity } from "../entities/tour.entity";
import type { WorkspaceFieldStripRules } from "../strategies/workspace.strategy.interface";
import { WorkspaceStrategyRegistry } from "../strategies/workspace.strategy.registry";
import type { TourTransportMode } from "../tour-transport-modes";
import type { TourTripDetails } from "../types/tour-trip-details.types";

/**
 * Logistics keys that remain when `urban_event` strips the logistics wizard group (dates / meet).
 *
 * Canonical single source: {@link URBAN_LOGISTICS_WHITELIST_KEYS} in `@repo/types`. This
 * `Set` wrapper exists only for the existing `.has(key)` call sites in `assert-create-tour-invariants.ts`
 * — those call sites can be migrated to the array form in Phase C without re-touching the constant.
 */
export const URBAN_LOGISTICS_WHITELIST: ReadonlySet<string> = new Set(URBAN_LOGISTICS_WHITELIST_KEYS);

/**
 * Resolves strip metadata via {@link WorkspaceStrategyRegistry}; falls back to builders if resolution fails.
 */
function loadFieldStripRules(profile: TourFormProfile): WorkspaceFieldStripRules {
  return WorkspaceStrategyRegistry.resolve(profile).getFieldStripRules();
}

/** Clears returnDate/Time for single-day Denali tours (ghost logistics). */
function stripDenaliSingleDayLogistics(td: TourTripDetails): void {
  const overview = td.overview as Record<string, unknown> | undefined;
  const kind = overview?.denaliTourKind;
  if (typeof kind === "string" && isDenaliTourKind(kind) && kind.endsWith("_day")) {
    if (td.logistics != null && typeof td.logistics === "object") {
      const log = td.logistics as Record<string, unknown>;
      delete log.returnDate;
      delete log.returnMeetingTime;
    }
  }
}

/**
 * Server mirror of web `stripInactiveTourCreateGroupsForProfile` (Phase 4): drop tripDetails branches
 * that the resolved profile does not expose. Mutates `td` in place.
 *
 * Strip deltas come from {@link WorkspaceStrategyRegistry.resolve(profile).getFieldStripRules}.
 */
export function stripTripDetailsForFormProfile(profile: TourFormProfile, td: TourTripDetails): void {
  const { strip } = loadFieldStripRules(profile);
  if (
    strip.clearsTripDetailsRoots.length === 0 &&
    strip.itineraryKeysToDelete.length === 0 &&
    strip.logisticsWhitelist == null
  ) {
    return;
  }

  const root = td as TourTripDetails & Record<string, unknown>;

  for (const key of strip.clearsTripDetailsRoots) {
    root[key] = undefined;
  }

  if (
    strip.itineraryKeysToDelete.length > 0 &&
    root.itinerary != null &&
    typeof root.itinerary === "object"
  ) {
    const it = { ...(root.itinerary as Record<string, unknown>) };
    for (const k of strip.itineraryKeysToDelete) {
      delete it[k];
    }
    root.itinerary = it as TourTripDetails["itinerary"];
  }

  if (strip.logisticsWhitelist != null) {
    if (root.logistics != null && typeof root.logistics === "object") {
      const log = root.logistics as Record<string, unknown>;
      const slim: Record<string, unknown> = {};
      for (const key of strip.logisticsWhitelist) {
        if (log[key] !== undefined) {
          slim[key] = log[key];
        }
      }
      root.logistics = slim as TourTripDetails["logistics"];
    }
  }
}

/**
 * Same as {@link stripTripDetailsForFormProfile}, plus clears root `transportModes` when
 * the strategy's `strip.clearsRootTransportModes` flag is set (e.g. `urban_event`).
 */
export function stripCreateTourDtoForFormProfile(profile: TourFormProfile, dto: CreateTourDto): void {
  const fieldStripRules = loadFieldStripRules(profile);
  const { strip, appliesDenaliSingleDayLogisticsStrip } = fieldStripRules;
  if (
    strip.clearsTripDetailsRoots.length === 0 &&
    strip.itineraryKeysToDelete.length === 0 &&
    strip.logisticsWhitelist == null &&
    !strip.clearsRootTransportModes
  ) {
    if (!appliesDenaliSingleDayLogisticsStrip || dto.tripDetails == null) {
      return;
    }
  }
  if (dto.tripDetails != null && typeof dto.tripDetails === "object") {
    stripTripDetailsForFormProfile(profile, dto.tripDetails as TourTripDetails);
  }

  if (strip.clearsRootTransportModes) {
    delete dto.transportModes;
  }

  if (appliesDenaliSingleDayLogisticsStrip && dto.tripDetails != null) {
    stripDenaliSingleDayLogistics(dto.tripDetails as TourTripDetails);
  }
}

/**
 * Persist-time strip for merged tour rows (PATCH / update paths).
 * Clears root `transportModes` when the strategy strip contract requires it.
 */
export function stripPersistedTourForFormProfile(profile: TourFormProfile, tour: TourEntity): void {
  const td = tour.details?.tripDetails;
  if (td != null && typeof td === "object") {
    stripTripDetailsForFormProfile(profile, td as TourTripDetails);
  }
  const { strip } = loadFieldStripRules(profile);
  if (strip.clearsRootTransportModes) {
    tour.transportModes = [] as TourTransportMode[];
  }
}

import type { TourTripDetails } from "../types/tour-trip-details.types";

/**
 * Deep-merge `patch` into a clone of `existing` (plain JSON).
 * - Omitted keys in `patch` leave the previous value unchanged.
 * - `null` in `patch` removes that key (useful for clearing a subgroup when clients send explicit null).
 * - Arrays are replaced in full when present in `patch`.
 */
export function mergeTourTripDetails(
  existing: TourTripDetails | null | undefined,
  patch: TourTripDetails
): TourTripDetails {
  const base: Record<string, unknown> =
    existing != null ? JSON.parse(JSON.stringify(existing)) : {};
  return mergeDeepRecord(base, patch as Record<string, unknown>) as TourTripDetails;
}

function mergeDeepRecord(
  target: Record<string, unknown>,
  patch: Record<string, unknown>
): Record<string, unknown> {
  const out: Record<string, unknown> = { ...target };
  for (const key of Object.keys(patch)) {
    const pv = patch[key];
    if (pv === undefined) {
      continue;
    }
    if (pv === null) {
      delete out[key];
      continue;
    }
    const tv = out[key];
    if (Array.isArray(pv)) {
      out[key] = pv;
      continue;
    }
    if (typeof pv === "object") {
      out[key] = mergeDeepRecord(
        typeof tv === "object" && tv !== null && !Array.isArray(tv)
          ? (tv as Record<string, unknown>)
          : {},
        pv as Record<string, unknown>
      );
      continue;
    }
    out[key] = pv;
  }
  return out;
}

import { getTourFormProfileDescriptor, type TourFormProfile } from "@repo/types";

import type { TourTripDetails } from "../types/tour-trip-details.types";

/**
 * Returns a structurally cleaned `tripDetails` JSON with mountain-only overview keys
 * (see `getTourFormProfileDescriptor(profile).invariants.mountainOverviewKeysToStripFromOverview`)
 * stripped when the resolved form profile does not allow mountain-only data. Pure: never
 * mutates the input.
 *
 * Validation contract: in the DTO these fields stay `@IsOptional()`, so they
 * silently disappear (instead of failing validation) when sent for the wrong
 * profile. This keeps the API forgiving toward older clients while still
 * enforcing the policy.
 *
 * Phase P4 (promptq.md): the legacy `applyTourTypeFieldGates(td, tourType)` helper has
 * been retired. All write paths must resolve the {@link TourFormProfile} first (server
 * does this via `resolveWorkspaceTourFormProfile`) and call this function.
 *
 * Phase P10+ housekeeping: the key list is read from the declarative profile descriptor
 * (`packages/types/src/tour-form-profile-descriptors.ts`) — parity-tested against
 * `MOUNTAIN_ONLY_TRIP_DETAILS_OVERVIEW_KEYS`.
 */
export function applyMountainOverviewFieldGatesForFormProfile(
  profile: TourFormProfile,
  tripDetails: TourTripDetails | null | undefined,
): TourTripDetails | null | undefined {
  const keysToStrip =
    getTourFormProfileDescriptor(profile).invariants.mountainOverviewKeysToStripFromOverview;
  if (tripDetails == null || keysToStrip.length === 0) {
    return tripDetails;
  }

  const overview = tripDetails.overview;
  if (!overview || typeof overview !== "object") {
    return tripDetails;
  }

  let nextOverview: Record<string, unknown> | undefined;
  for (const key of keysToStrip) {
    if ((overview as Record<string, unknown>)[key] === undefined) continue;
    if (!nextOverview) nextOverview = { ...(overview as Record<string, unknown>) };
    delete nextOverview[key];
  }

  if (!nextOverview) return tripDetails;
  const cleanedOverview = Object.keys(nextOverview).length > 0 ? nextOverview : undefined;
  return { ...tripDetails, overview: cleanedOverview as TourTripDetails["overview"] };
}

/**
 * Local audit for phone + OTP web login (`POST /api/v2/auth/web/session/otp`).
 * Run from apps/api: pnpm auth:debug-audit
 */
import * as argon2 from "argon2";
import { randomUUID } from "node:crypto";
import { DataSource, IsNull } from "typeorm";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { UserRole } from "../common/auth/user-role.enum";
import { TenantEntity } from "../modules/identity/entities/tenant.entity";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";

const EMAIL = "leader@test.com";
const PHONE = "+15551234567";
const STATIC_OTP = "1234";
const TENANT_NAME = "demo-tenant";

function assertDbEnv(): void {
  const keys = ["DATABASE_HOST", "DATABASE_USER", "DATABASE_PASSWORD", "DATABASE_NAME"] as const;
  for (const k of keys) {
    const v = process.env[k];
    if (v === undefined || v === "") {
      throw new Error(`Missing env ${k}. Use apps/api/.env (see .env.example).`);
    }
    if (k === "DATABASE_PASSWORD" && typeof v !== "string") {
      throw new Error("DATABASE_PASSWORD must be a string");
    }
  }
}

async function simulateOtpSessionChecks(params: {
  dataSource: DataSource;
  phone: string;
  otp: string;
  tenantId: string;
}): Promise<{ ok: true } | { ok: false; reason: string }> {
  if (process.env.NODE_ENV === "production") {
    return { ok: false, reason: "static OTP checks disabled in production NODE_ENV" };
  }
  if (params.otp !== STATIC_OTP) {
    return { ok: false, reason: "AUTH_UNAUTHENTICATED (OTP mismatch for non-production static policy)" };
  }
  const user = await params.dataSource
    .getRepository(UserEntity)
    .createQueryBuilder("u")
    .where("u.deleted_at IS NULL")
    .andWhere("phone_normalized(u.phone) = phone_normalized(:phone)", { phone: params.phone.trim() })
    .getOne();
  if (!user) {
    return { ok: false, reason: "AUTH_UNAUTHENTICATED (no user for normalized phone)" };
  }
  const membership = await params.dataSource.getRepository(UserTenantEntity).findOne({
    where: { userId: user.id, tenantId: params.tenantId, deletedAt: IsNull() }
  });
  if (!membership) {
    return { ok: false, reason: "TENANT_SCOPE_FORBIDDEN (no membership for tenant)" };
  }
  return { ok: true };
}

async function httpLoginSession(baseUrl: string, hostHeader: string): Promise<{
  ok: boolean;
  status?: number;
  session_token?: string;
  error?: string;
}> {
  const url = `${baseUrl.replace(/\/$/, "")}/api/v2/auth/web/session/otp`;
  const body = { phone: PHONE, otp: STATIC_OTP };
  try {
    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", Host: hostHeader },
      body: JSON.stringify(body)
    });
    const text = await res.text();
    let json: { session_token?: string } = {};
    try {
      json = JSON.parse(text) as { session_token?: string };
    } catch {
      /* ignore */
    }
    if (!res.ok) {
      return { ok: false, status: res.status, error: text.slice(0, 500) };
    }
    return { ok: true, status: res.status, session_token: json.session_token };
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return { ok: false, error: msg };
  }
}

async function run(): Promise<void> {
  assertDbEnv();

  const dataSource = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [TenantEntity, UserEntity, UserTenantEntity]
  });

  await dataSource.initialize();

  let loginStatus: "success" | "failure" = "failure";

