  process.exit(1);
});

/**
 * One-off migration: legacy `tripDetails.overview.tourTheme` string tags →
 * `workspace_tour_themes` rows and `overview.tourThemeIds`.
 *
 * Usage:
 *   pnpm --filter @apps/api migrate:tour-theme-tags
 *   pnpm --filter @apps/api migrate:tour-theme-tags -- --dry-run
 */
import { createHash } from "node:crypto";
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { emitScriptInfo } from "./script-log";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function normalizeThemeKey(raw: string): string {
  return raw.trim().toLowerCase();
}

function isNonEmptyStringTag(s: unknown): s is string {
  return typeof s === "string" && normalizeThemeKey(s).length > 0;
}

/** Trim + cap length for `workspace_tour_themes.name` (varchar 120). */
function canonicalDisplayName(firstTrimmed: string): string {
  const t = firstTrimmed.trim();
  if (t.length <= 120) {
    return t;
  }
  return `${t.slice(0, 117)}...`;
}

/**
 * ASCII-ish kebab slug from display name. Falls back to `legacy-<hex>` when empty
 * (e.g. non-Latin-only labels).
 */
function baseSlugFromName(displayName: string, normKey: string): string {
  const lower = displayName.trim().toLowerCase();
  const slug = lower
    .normalize("NFD")
    .replace(/\p{M}/gu, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 120);
  if (slug.length > 0) {
    return slug;
  }
  const h = createHash("sha256").update(normKey).digest("hex").slice(0, 14);
  return `legacy-${h}`;
}

function uniqueSlug(
  base: string,
  workspaceTaken: Set<string>,
  usedInBatch: Set<string>,
): string {
  const root = base.slice(0, 120);
  let candidate = root;
  let n = 2;
  while (workspaceTaken.has(candidate) || usedInBatch.has(candidate)) {
    const suffix = `-${n}`;
    n += 1;
    candidate = `${root.slice(0, Math.max(0, 120 - suffix.length))}${suffix}`;
  }
  usedInBatch.add(candidate);
  return candidate;
}

function filterValidUuid(ids: unknown): string[] {
  if (!Array.isArray(ids)) {
    return [];
  }
  const out: string[] = [];
  const seen = new Set<string>();
  for (const x of ids) {
    if (typeof x !== "string") {
      continue;
    }
    const t = x.trim();
    if (!UUID_RE.test(t) || seen.has(t)) {
      continue;
    }
    seen.add(t);
    out.push(t);
  }
  return out;
}

function dedupeIdsPreserveOrder(ids: string[]): string[] {
  const out: string[] = [];
  const seen = new Set<string>();
  for (const id of ids) {
    if (seen.has(id)) {
      continue;
    }
    seen.add(id);
    out.push(id);
  }
  return out;
}

type TourDetailsRow = {
  tourDetailsId: string;
  tourId: string;
  tenantId: string;
  tripDetails: Record<string, unknown>;
};

function rowHasStringTourThemes(row: TourDetailsRow): boolean {
  const overview = row.tripDetails?.overview;
  if (!overview || typeof overview !== "object" || Array.isArray(overview)) {
    return false;
  }
  const tourTheme = (overview as { tourTheme?: unknown }).tourTheme;
  if (!Array.isArray(tourTheme)) {
    return false;
  }
  return tourTheme.some((t) => isNonEmptyStringTag(t));
}

async function main(): Promise<void> {
  const dryRun = process.argv.includes("--dry-run");
  const dataSource = new DataSource(createDataSourceOptionsFromEnv());
  await dataSource.initialize();
  try {
    const rows = await dataSource.query<TourDetailsRow[]>(`
      SELECT td.id AS "tourDetailsId",
             td.tour_id AS "tourId",
             t.tenant_id AS "tenantId",
             td.trip_details AS "tripDetails"
      FROM tour_details td
      INNER JOIN tours t ON t.id = td.tour_id
      WHERE t.deleted_at IS NULL
        AND td.trip_details IS NOT NULL
        AND jsonb_typeof(td.trip_details->'overview'->'tourTheme') = 'array'
        AND jsonb_array_length(COALESCE(td.trip_details->'overview'->'tourTheme', '[]'::jsonb)) > 0
    `);

    const globalNormKeys = new Set<string>();
    for (const row of rows) {
      const overview = row.tripDetails?.overview;
      if (!overview || typeof overview !== "object" || Array.isArray(overview)) {
        continue;
      }
      const tourTheme = (overview as { tourTheme?: unknown }).tourTheme;
      if (!Array.isArray(tourTheme)) {
        continue;
      }
      for (const tag of tourTheme) {
        if (!isNonEmptyStringTag(tag)) {
          continue;
        }
        globalNormKeys.add(normalizeThemeKey(tag));
      }
    }

    const byWorkspace = new Map<string, TourDetailsRow[]>();
    for (const row of rows) {
      const list = byWorkspace.get(row.tenantId) ?? [];
      list.push(row);
      byWorkspace.set(row.tenantId, list);
    }

    let themesInserted = 0;
    let themesMatchedExistingCatalog = 0;
    let toursMigrated = 0;

    for (const [workspaceId, wsRows] of byWorkspace) {
      const firstLabel = new Map<string, string>();
      for (const row of wsRows) {
        const overview = row.tripDetails?.overview;
        if (!overview || typeof overview !== "object" || Array.isArray(overview)) {
          continue;
        }
        const tourTheme = (overview as { tourTheme?: unknown }).tourTheme;
        if (!Array.isArray(tourTheme)) {
          continue;
        }
        for (const tag of tourTheme) {
          if (!isNonEmptyStringTag(tag)) {
            continue;
          }
          const nk = normalizeThemeKey(tag);
          const trimmed = tag.trim();
          if (!firstLabel.has(nk)) {
            firstLabel.set(nk, trimmed);
          }
        }
      }

      const slugRows = (await dataSource.query(
        `SELECT id, slug FROM workspace_tour_themes WHERE workspace_id = $1`,
        [workspaceId],
      )) as { id: string; slug: string }[];
      const existingSlugToId = new Map(slugRows.map((r) => [r.slug, r.id]));
      const workspaceTaken = new Set<string>(slugRows.map((r) => r.slug));
      const batchSlugUsed = new Set<string>();
      /** Prevents two normKeys that share the same kebab `base` from mapping to the same theme id. */
      const baseSlugSlotUsed = new Set<string>();

      const normKeyToThemeId = new Map<string, string>();
      const sortedKeys = [...firstLabel.keys()].sort((a, b) => a.localeCompare(b));

      const maxRow = (await dataSource.query(
        `SELECT MAX(sort_order)::text AS m FROM workspace_tour_themes WHERE workspace_id = $1`,
        [workspaceId],
      )) as { m: string | null }[];
      const maxParsed = maxRow[0]?.m != null ? Number.parseInt(maxRow[0].m, 10) : 0;
      let nextSort = Number.isFinite(maxParsed) ? maxParsed + 1 : 0;

      for (const nk of sortedKeys) {
        const label = firstLabel.get(nk)!;
        const displayName = canonicalDisplayName(label);
        const baseSlug = baseSlugFromName(displayName, nk);

        if (existingSlugToId.has(baseSlug) && !baseSlugSlotUsed.has(baseSlug)) {
          const id = existingSlugToId.get(baseSlug)!;
          normKeyToThemeId.set(nk, id);
          baseSlugSlotUsed.add(baseSlug);
          themesMatchedExistingCatalog += 1;
          continue;
        }

        const slug = uniqueSlug(baseSlug, workspaceTaken, batchSlugUsed);
        workspaceTaken.add(slug);

        const existing = (await dataSource.query(
          `SELECT id FROM workspace_tour_themes WHERE workspace_id = $1 AND slug = $2 LIMIT 1`,
          [workspaceId, slug],
        )) as { id: string }[];
        if (existing.length > 0) {
          normKeyToThemeId.set(nk, existing[0]!.id);
          if (slug === baseSlug) {
            baseSlugSlotUsed.add(baseSlug);
          }
          themesMatchedExistingCatalog += 1;
          continue;
        }

        if (dryRun) {
          if (slug === baseSlug) {
            baseSlugSlotUsed.add(baseSlug);
          }
          themesInserted += 1;
          continue;
        }

        const inserted = (await dataSource.query(
          `
          INSERT INTO workspace_tour_themes
            (workspace_id, name, slug, description, is_active, sort_order)
          VALUES ($1, $2, $3, NULL, true, $4)
          RETURNING id
          `,
          [workspaceId, displayName, slug, nextSort],
        )) as { id: string }[];
        nextSort += 1;
        const id = inserted[0]!.id;
        normKeyToThemeId.set(nk, id);
        existingSlugToId.set(slug, id);
        if (slug === baseSlug) {
          baseSlugSlotUsed.add(baseSlug);
        }
        themesInserted += 1;
      }

      if (dryRun) {
        toursMigrated += wsRows.filter(rowHasStringTourThemes).length;
        continue;
      }

      for (const row of wsRows) {
        const trip = { ...row.tripDetails } as Record<string, unknown>;
        const overviewRaw = trip.overview;
        if (!overviewRaw || typeof overviewRaw !== "object" || Array.isArray(overviewRaw)) {
          continue;
        }
        const overview = { ...(overviewRaw as Record<string, unknown>) };
        const tourTheme = overview.tourTheme;
        if (!Array.isArray(tourTheme)) {
          continue;
        }
        const stringTags = tourTheme.filter(isNonEmptyStringTag);
        if (stringTags.length === 0) {
          continue;
        }
        const mappedIds: string[] = [];
        for (const tag of stringTags) {
          const nk = normalizeThemeKey(tag);
          const id = normKeyToThemeId.get(nk);
          if (id) {
            mappedIds.push(id);
          }
        }
        const existingIds = filterValidUuid(overview.tourThemeIds);
        const merged = dedupeIdsPreserveOrder([...mappedIds, ...existingIds]);
        overview.tourThemeIds = merged.length > 0 ? merged : undefined;
        delete overview.tourTheme;
        if (Object.keys(overview).length === 0) {
          delete trip.overview;
        } else {
          trip.overview = overview;
        }

        await dataSource.query(`UPDATE tour_details SET trip_details = $1::jsonb WHERE id = $2`, [
          JSON.stringify(trip),
          row.tourDetailsId,
        ]);
        toursMigrated += 1;
      }
    }

    emitScriptInfo(
      JSON.stringify(
        {
          dryRun,
          uniqueThemeStrings: globalNormKeys.size,
          workspacesAffected: byWorkspace.size,
          themeRowsInserted: themesInserted,
          themeRowsMatchedExistingCatalogSlug: themesMatchedExistingCatalog,
          toursMigrated,
        },
        null,
        2,
      ),
    );
  } finally {
    await dataSource.destroy();
  }
}

main().catch((error: unknown) => {
  const message = error instanceof Error ? error.stack ?? error.message : String(error);
  console.error(message);
  process.exitCode = 1;
});

/**
 * Rebuilds workspace regions + destinations for tenant subdomain `denali`.
 * Deletes all rows in `workspace_destinations` and `workspace_regions` for that tenant,
 * then inserts a large catalog (see `seed-denali-locations.catalog.ts`, generated from
 * `tools/build-denali-locations-catalog.py`). Tours with old `destination_id` become NULL
 * (FK ON DELETE SET NULL).
 *
 * Regenerate catalog: `python3 apps/api/src/scripts/tools/build-denali-locations-catalog.py`
 *
 * Run: `pnpm --filter @apps/api seed:denali-locations`
 */
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import {
  DENALI_LOCATION_BUNDLES_INTL,
  DENALI_LOCATION_BUNDLES_IRAN,
  type DenaliLocationBundle,
} from "./seed-denali-locations.catalog";
import { emitScriptInfo } from "./script-log";

type ParsedDest = { name: string; type: string | null; altitudeM: number | null };

function parseDestTokens(line: string): ParsedDest[] {
  const tokens = line.split("؛").map((s) => s.trim()).filter(Boolean);
  const out: ParsedDest[] = [];
  for (const raw of tokens) {
    const seg = raw.split("|").map((s) => s.trim());
    const name = seg[0] ?? "";
    if (!name) {
      continue;
    }
    const typePart = seg[1];
    const altPart = seg[2];
    const type = typePart && typePart.length > 0 ? typePart.slice(0, 64) : "شهر";
    let altitudeM: number | null = null;
    if (altPart !== undefined && altPart.length > 0) {
      const n = Number.parseInt(altPart, 10);
      altitudeM = Number.isFinite(n) ? n : null;
    }
    out.push({ name: name.slice(0, 255), type, altitudeM });
  }
  return out;
}

async function insertBundle(
  ds: DataSource,
  tenantId: string,
  bundle: DenaliLocationBundle,
): Promise<number> {
  const regionRows = await ds.query<Array<{ id: string }>>(
    `INSERT INTO workspace_regions (tenant_id, name, country, sort_order, is_active)
     VALUES ($1, $2, $3, $4, true)
     RETURNING id`,
    [tenantId, bundle.regionName, bundle.country, bundle.sortOrderBase],
  );
  const regionId = regionRows[0]?.id;
  if (!regionId) {
    throw new Error("INSERT workspace_regions returned no id");
  }

  const dests = parseDestTokens(bundle.destTokens);
  let n = 0;
  for (let i = 0; i < dests.length; i += 1) {
    const d = dests[i]!;
    const sort = bundle.sortOrderBase + i + 1;
    await ds.query(
      `INSERT INTO workspace_destinations
        (tenant_id, region_id, name, type, altitude_m, sort_order, is_active)
       VALUES ($1, $2, $3, $4, $5, $6, true)`,
      [tenantId, regionId, d.name, d.type, d.altitudeM, sort],
    );
    n += 1;
  }
  return n;
}

export async function seedDenaliLocations(): Promise<void> {
  const ds = new DataSource(createDataSourceOptionsFromEnv());
  await ds.initialize();
  try {
    const tenants = await ds.query<Array<{ id: string; name: string }>>(
      `SELECT id, name FROM tenants WHERE deleted_at IS NULL AND lower(trim(subdomain)) = lower(trim($1)) LIMIT 1`,
      ["denali"],
    );
    const tenant = tenants[0];
    if (!tenant) {
      console.error("No active tenant with subdomain `denali`. Create/fix subdomain first.");
      process.exitCode = 1;
      return;
    }

    const tenantId = tenant.id as string;
    emitScriptInfo(`Resolved Denali workspace id=${tenantId} name=${tenant.name}`);

    const delD = await ds.query(`DELETE FROM workspace_destinations WHERE tenant_id = $1 RETURNING id`, [tenantId]);
    const delR = await ds.query(`DELETE FROM workspace_regions WHERE tenant_id = $1 RETURNING id`, [tenantId]);
    emitScriptInfo(
      `Removed ${Array.isArray(delD) ? delD.length : 0} destination(s) and ${Array.isArray(delR) ? delR.length : 0} region(s).`,
    );

    let destTotal = 0;
    for (const b of DENALI_LOCATION_BUNDLES_IRAN) {
      destTotal += await insertBundle(ds, tenantId, b);
    }
    for (const b of DENALI_LOCATION_BUNDLES_INTL) {
      destTotal += await insertBundle(ds, tenantId, b);
    }

    emitScriptInfo(
      `Inserted ${DENALI_LOCATION_BUNDLES_IRAN.length + DENALI_LOCATION_BUNDLES_INTL.length} region(s) and ${destTotal} destination(s) for denali.`,
    );
  } finally {
    await ds.destroy();
  }
}

seedDenaliLocations().catch((error: unknown) => {
  console.error(
    "seed-denali-locations failed:",
    error instanceof Error ? error.stack ?? error.message : String(error),
  );
  process.exitCode = 1;
});

/**
 * Seeds many registration rows visible on GET /api/v2/bookings for leader@test.com.
 * Uses syntheticBookingContactPhone(leader.id) — same rule as RegistrationsService.listBookings.
 *
 * Prerequisites: DB migrated; `pnpm seed` + `pnpm seed:demo-leader-tours` (or existing tenant/tours).
 *
 * From apps/api:
 *   pnpm seed:leader-bookings
 * Optional: SEED_LEADER_BOOKINGS_COUNT=80 pnpm seed:leader-bookings
 *
 * Idempotent marker: rows use participant_note = SEED_NOTE; re-run deletes prior seeded rows for that phone+tenant then inserts fresh.
 */
import { DataSource, IsNull } from "typeorm";
import { syntheticBookingContactPhone } from "../common/security/ownership-scope";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";
import {
  RegistrationEntity,
  RegistrationPaymentStatus,
  RegistrationStatus
} from "../modules/registrations/registration.entity";
import { TourEntity } from "../modules/tours/entities/tour.entity";
import { emitScriptInfo } from "./script-log";

const LEADER_EMAIL = "leader@test.com";
const SEED_NOTE = "seed:leader-bookings-table";

const DEFAULT_COUNT = 72;

const ACTIVE_STATUSES: RegistrationStatus[] = [
  RegistrationStatus.PENDING,
  RegistrationStatus.ACCEPTED,
  RegistrationStatus.ACCEPTED_PAID
];

const TERMINAL_STATUSES: RegistrationStatus[] = [
  RegistrationStatus.REJECTED,
  RegistrationStatus.CANCELLED,
  RegistrationStatus.NO_SHOW,
  RegistrationStatus.REFUNDED
];

async function run(): Promise<void> {
  const targetCount = Number.parseInt(process.env.SEED_LEADER_BOOKINGS_COUNT ?? String(DEFAULT_COUNT), 10);
  if (!Number.isFinite(targetCount) || targetCount < 1) {
    throw new Error("SEED_LEADER_BOOKINGS_COUNT must be a positive integer");
  }

  const dataSource = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [UserEntity, UserTenantEntity, TourEntity, RegistrationEntity]
  });

  await dataSource.initialize();
  try {
    const userRepo = dataSource.getRepository(UserEntity);
    const membershipRepo = dataSource.getRepository(UserTenantEntity);
    const tourRepo = dataSource.getRepository(TourEntity);
    const regRepo = dataSource.getRepository(RegistrationEntity);

    const leader = await userRepo.findOne({
      where: { email: LEADER_EMAIL, deletedAt: IsNull() }
    });
    if (!leader) {
      throw new Error(`User not found: ${LEADER_EMAIL}. Run pnpm seed first.`);
    }

    const membership = await membershipRepo.findOne({
      where: { userId: leader.id, deletedAt: IsNull() }
    });
    if (!membership) {
      throw new Error(`No tenant membership for ${LEADER_EMAIL}.`);
    }

    const tenantId = membership.tenantId;
    const phone = syntheticBookingContactPhone(leader.id);

    const tours = await tourRepo.find({
      where: { tenantId, deletedAt: IsNull() },
      order: { createdAt: "ASC" }
    });
    if (tours.length === 0) {
      throw new Error("No tours for tenant. Run pnpm seed:demo-leader-tours first.");
    }

    const del = await regRepo
      .createQueryBuilder()
      .delete()
      .from(RegistrationEntity)
      .where("tenant_id = :tenantId", { tenantId })
      .andWhere("participant_contact_phone = :phone", { phone })
      .andWhere("participant_note = :note", { note: SEED_NOTE })
      .execute();
    emitScriptInfo(`Removed ${del.affected ?? 0} prior seeded booking row(s).`);

    /** Per tour: first row active (Pending/Accepted/AcceptedPaid); further rows terminal — matches duplicate rules for same phone. */
    const nthForTour = new Map<string, number>();

    const rows: RegistrationEntity[] = [];
    for (let i = 0; i < targetCount; i++) {
      const tour = tours[i % tours.length]!;
      const k = (nthForTour.get(tour.id) ?? 0) + 1;
      nthForTour.set(tour.id, k);

      const status: RegistrationStatus =
        k === 1 ? ACTIVE_STATUSES[i % ACTIVE_STATUSES.length]! : TERMINAL_STATUSES[i % TERMINAL_STATUSES.length]!;

      let paymentStatus: RegistrationPaymentStatus;
      switch (status) {
        case RegistrationStatus.PENDING:
          paymentStatus = RegistrationPaymentStatus.NOT_PAID;
          break;
        case RegistrationStatus.ACCEPTED:
          paymentStatus = i % 2 === 0 ? RegistrationPaymentStatus.NOT_PAID : RegistrationPaymentStatus.PARTIAL;
          break;
        case RegistrationStatus.ACCEPTED_PAID:
          paymentStatus = RegistrationPaymentStatus.PAID;
          break;
        case RegistrationStatus.REFUNDED:
          paymentStatus = RegistrationPaymentStatus.REFUNDED;
          break;
        default:
          paymentStatus = RegistrationPaymentStatus.NOT_PAID;
      }

      rows.push(
        regRepo.create({
          tenantId,
          tourId: tour.id,
          participantFullName: `دمو بوکینگ ${i + 1}`,
          participantContactPhone: phone,
          transportMode: "group_vehicle",
          entryMode: "web",
          participantNote: SEED_NOTE,
          status,
          paymentStatus,
          paidAmount:
            paymentStatus === RegistrationPaymentStatus.PAID ||
            paymentStatus === RegistrationPaymentStatus.PARTIAL
              ? "250000"
              : undefined
        })
      );
    }

    await regRepo.save(rows);
    emitScriptInfo(
      `✅ Inserted ${rows.length} registrations for ${LEADER_EMAIL} (phone ${phone}, tenant ${tenantId}). Open /bookings after login.`
    );
  } finally {
    await dataSource.destroy();
  }
}

run().catch((error: unknown) => {
  const message = error instanceof Error ? error.stack ?? error.message : String(error);
  console.error("seed-leader-bookings failed:", message);
  process.exitCode = 1;
});

import assert from "node:assert/strict";
import test from "node:test";
import { DataSource } from "typeorm";

import {
  createDefaultDraftMigratorRegistry,
  CURRENT_DRAFT_SCHEMA_VERSION,
  DENALI_CREATE_DRAFT_KEY,
} from "@repo/shared-contracts";

import { DraftConflictException } from "../../src/modules/draft-engine/draft-conflict.exception";
import { DraftEngineFacade } from "../../src/modules/draft-engine/draft-engine.facade";
import { DraftEventEntity } from "../../src/modules/draft-engine/entities/draft-event.entity";
import { DraftSnapshotEntity } from "../../src/modules/draft-engine/entities/draft-snapshot.entity";
import { PostgresDraftSnapshotStore } from "../../src/modules/draft-engine/storage/postgres-draft-snapshot.store";
import { DraftScopeResolver } from "../../src/modules/draft-engine/storage/draft-scope.resolver";
import type { RequestContextService } from "../../src/common/request-context/request-context.service";
import type { AuditLogService } from "../../src/common/audit/audit-log.service";

test("DraftEngineFacade integration (requires DATABASE_URL)", async (t) => {
  const url = process.env.DATABASE_URL;
  if (!url) {
    t.skip("DATABASE_URL not set");
    return;
  }

  const workspaceId = "00000000-0000-4000-8000-000000000098";
  const userId = "00000000-0000-4000-8000-000000000099";
  const draftKey = `integration-${Date.now().toString(36)}`;

  const dataSource = new DataSource({
    type: "postgres",
    url,
    entities: [DraftSnapshotEntity, DraftEventEntity],
    synchronize: false,
    logging: false,
  });
  await dataSource.initialize();

  const repo = dataSource.getRepository(DraftSnapshotEntity);
  const draftEventRepo = dataSource.getRepository(DraftEventEntity);
  const store = new PostgresDraftSnapshotStore(repo);
  const requestContext = {
    resolveEffectiveTenantId: () => workspaceId,
    getUserId: () => userId,
    tryGetCorrelationId: () => "integration-trace-id",
    tryGetRequestId: () => "integration-trace-id",
  } as unknown as RequestContextService;
  const scopeResolver = new DraftScopeResolver(requestContext);
  const facade = new DraftEngineFacade(
    store,
    scopeResolver,
    createDefaultDraftMigratorRegistry(),
    { logEvent: async () => undefined } as unknown as AuditLogService,
    draftEventRepo,
    requestContext,
  );

  try {
    await repo.delete({ workspaceId, userId, draftKey });

    const created = await facade.upsertForMember(workspaceId, draftKey, {
      data: { form: { title: "Integration" }, currentStepIndex: 0 },
      version: 0,
      schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
      lastModified: Date.now(),
    });
    assert.equal(created.version, 1);
    assert.equal(created.schemaVersion, CURRENT_DRAFT_SCHEMA_VERSION);

    const loaded = await facade.findForMember(workspaceId, draftKey);
    assert.ok(loaded);
    assert.equal(loaded.version, 1);
    assert.equal((loaded.data as { form?: { title?: string } }).form?.title, "Integration");

    await repo.update(
      { workspaceId, userId, draftKey },
      { data: { broken: true } as never },
    );
    const migrated = await facade.findForMember(workspaceId, draftKey);
    assert.ok(migrated);
    assert.equal(migrated.schemaVersion, CURRENT_DRAFT_SCHEMA_VERSION);
    assert.equal((migrated.data as { currentStepIndex?: number }).currentStepIndex, 0);

    const bumped = await facade.upsertForMember(workspaceId, draftKey, {
      data: { form: { title: "v2" }, currentStepIndex: 1 },
      version: migrated!.version,
      schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
      lastModified: Date.now(),
    });
    assert.equal(bumped.version, 2);

    const raceVersion = bumped.version;
    const results = await Promise.allSettled([
      facade.upsertForMember(workspaceId, draftKey, {
        data: { form: { title: "race-a" }, currentStepIndex: 0 },
        version: raceVersion,
        schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
        lastModified: Date.now(),
      }),
      facade.upsertForMember(workspaceId, draftKey, {
        data: { form: { title: "race-b" }, currentStepIndex: 0 },
        version: raceVersion,
        schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
        lastModified: Date.now(),
      }),
    ]);
    const fulfilled = results.filter((r) => r.status === "fulfilled");
    const rejected = results.filter((r) => r.status === "rejected");
    assert.equal(fulfilled.length, 1, "exactly one concurrent upsert should succeed");
    assert.equal(rejected.length, 1, "exactly one concurrent upsert should conflict");
    const failure = rejected[0];
    assert.equal(failure.status, "rejected");
    assert.ok(
      failure.reason instanceof DraftConflictException,
      "loser must receive DraftConflictException",
    );
  } finally {
    await repo.delete({ workspaceId, userId, draftKey });
    await dataSource.destroy();
  }
});

test("DraftEngineFacade legacy schema_version 1 → loadDraft → saveDraft (requires DATABASE_URL)", async (t) => {
  const url = process.env.DATABASE_URL;
  if (!url) {
    t.skip("DATABASE_URL not set");
    return;
  }

  const workspaceId = "00000000-0000-4000-8000-000000000097";
  const userId = "00000000-0000-4000-8000-000000000099";
  const draftKey = DENALI_CREATE_DRAFT_KEY;

  const dataSource = new DataSource({
    type: "postgres",
    url,
    entities: [DraftSnapshotEntity, DraftEventEntity],
    synchronize: false,
    logging: false,
  });
  await dataSource.initialize();

  const repo = dataSource.getRepository(DraftSnapshotEntity);
  const draftEventRepo = dataSource.getRepository(DraftEventEntity);
  const store = new PostgresDraftSnapshotStore(repo);
  const requestContext = {
    resolveEffectiveTenantId: () => workspaceId,
    getUserId: () => userId,
    tryGetCorrelationId: () => "integration-trace-id",
    tryGetRequestId: () => "integration-trace-id",
  } as unknown as RequestContextService;
  const scopeResolver = new DraftScopeResolver(requestContext);
  const facade = new DraftEngineFacade(
    store,
    scopeResolver,
    createDefaultDraftMigratorRegistry(),
    { logEvent: async () => undefined } as unknown as AuditLogService,
    draftEventRepo,
    requestContext,
  );

  try {
    await repo.delete({ workspaceId, userId, draftKey });

    await repo.insert({
      workspaceId,
      userId,
      draftKey,
      data: { legacyTitle: "old" },
      version: 1,
      schemaVersion: 1,
      lastModified: String(Date.now()),
    });

    const loaded = await facade.loadDraft(workspaceId, draftKey);
    assert.ok(loaded);
    assert.equal(loaded.schemaVersion, CURRENT_DRAFT_SCHEMA_VERSION);
    assert.equal(loaded.data.currentStepIndex, 0);
    assert.deepEqual(loaded.data.form, {});

    const saved = await facade.saveDraft(workspaceId, draftKey, {
      data: { form: { title: "after-migration" }, currentStepIndex: 1 },
      version: loaded.version,
      schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
      lastModified: Date.now(),
    });
    assert.equal(saved.version, 2);
    assert.equal((saved.data as { form?: { title?: string } }).form?.title, "after-migration");
  } finally {
    await repo.delete({ workspaceId, userId, draftKey });
    await dataSource.destroy();
  }
});

import React from "react";
