"use client";

import { useMutation } from "@tanstack/react-query";
import { useEffect, useMemo, useRef, useState } from "react";

import type { BookingAggregatePaymentStatus } from "@/lib/booking-transition-policy";
import {
  getAllowedBookingTransitions,
  getAllowedPaymentTransitions,
  isTerminalBookingState,
  isTerminalPaymentState,
} from "@/lib/booking-transition-policy";
import type { LeaderRegistrationRow } from "@/lib/hooks/useLeaderTourRegistrations";
import {
  updateRegistrationPayment,
  updateRegistrationStatus,
} from "@/lib/services/registrations.service";

import type { RegistrationPaymentStatus, RegistrationStatus } from "@repo/types";

const PUBLIC_PATCH_PAYMENT: ReadonlySet<string> = new Set(["NotPaid", "Partial", "Paid"]);

function uniqueOrdered<T extends string>(items: readonly T[]): T[] {
  const seen = new Set<T>();
  const out: T[] = [];
  for (const x of items) {
    if (seen.has(x)) continue;
    seen.add(x);
    out.push(x);
  }
  return out;
}

function persistPaymentWire(reg: LeaderRegistrationRow): BookingAggregatePaymentStatus {
  return reg.paymentStatus as BookingAggregatePaymentStatus;
}

function paymentSaveIsNoOp(
  reg: LeaderRegistrationRow,
  payDraft: Record<string, RegistrationPaymentStatus>,
  amountDraftRecord: Record<string, string>,
): boolean {
  const effectivePayment = payDraft[reg.id] ?? reg.paymentStatus;
  if (effectivePayment !== reg.paymentStatus) return false;
  const raw = amountDraftRecord[reg.id]?.trim();
  const persistedAmt = reg.paidAmount?.trim() ?? "";
  const draftEmpty = raw === undefined || raw === "";
  const persistedEmpty = persistedAmt === "";
  if (draftEmpty && persistedEmpty) return true;
  if (draftEmpty || persistedEmpty) return false;
  const a = Number(raw);
  const b = Number(persistedAmt);
  return Number.isFinite(a) && Number.isFinite(b) && a === b;
}

export function useLeaderReviewState(
  rows: LeaderRegistrationRow[],
  visibleRows: LeaderRegistrationRow[],
  onRefreshData: () => Promise<void>,
) {
  const [statusDraft, setStatusDraft] = useState<Record<string, RegistrationStatus>>({});
  const [payDraft, setPayDraft] = useState<Record<string, RegistrationPaymentStatus>>({});
  const [amountDraft, setAmountDraft] = useState<Record<string, string>>({});

  const statusMutation = useMutation({
    mutationFn: async ({
      id,
      targetStatus,
      expected_row_version,
    }: {
      id: string;
      targetStatus: RegistrationStatus;
      expected_row_version: number;
    }) => updateRegistrationStatus(id, { targetStatus, expected_row_version }),
    onSuccess: async () => {
      await onRefreshData();
    },
  });

  const paymentMutation = useMutation({
    mutationFn: async (args: {
      id: string;
      paymentStatus: RegistrationPaymentStatus;
      paidAmount?: number;
      expected_row_version: number;
    }) =>
      updateRegistrationPayment(args.id, {
        paymentStatus: args.paymentStatus,
        paidAmount: args.paidAmount,
        expected_row_version: args.expected_row_version,
      }),
    onSuccess: async () => {
      await onRefreshData();
    },
  });

  const statusPendingRowId = statusMutation.isPending ? statusMutation.variables?.id ?? null : null;
  const paymentPendingRowId = paymentMutation.isPending ? paymentMutation.variables?.id ?? null : null;

  const prevStatusMutationStatusRef = useRef(statusMutation.status);
  useEffect(() => {
    const prev = prevStatusMutationStatusRef.current;
    const cur = statusMutation.status;
    if (prev === "pending" && (cur === "success" || cur === "error")) {
      const id = statusMutation.variables?.id;
      if (id) {
        setStatusDraft((d) => {
          const next = { ...d };
          delete next[id];
          return next;
        });
      }
    }
    prevStatusMutationStatusRef.current = cur;
  }, [statusMutation.status, statusMutation.variables?.id]);

  const prevPaymentMutationStatusRef = useRef(paymentMutation.status);
  useEffect(() => {
    const prev = prevPaymentMutationStatusRef.current;
    const cur = paymentMutation.status;
    if (prev === "pending" && (cur === "success" || cur === "error")) {
      const id = paymentMutation.variables?.id;
      if (id) {
        setPayDraft((d) => {
          const next = { ...d };
          delete next[id];
          return next;
        });
        setAmountDraft((d) => {
          const next = { ...d };
          delete next[id];
          return next;
        });
      }
    }
    prevPaymentMutationStatusRef.current = cur;
  }, [paymentMutation.status, paymentMutation.variables?.id]);

  useEffect(() => {
    const ids = new Set(rows.map((r) => r.id));
    setStatusDraft((d) => {
      let changed = false;
      const next = { ...d };
      for (const k of Object.keys(next)) {
        if (!ids.has(k)) {
          delete next[k];
          changed = true;
        }
      }
      return changed ? next : d;
    });
    setPayDraft((d) => {
      let changed = false;
      const next = { ...d };
      for (const k of Object.keys(next)) {
        if (!ids.has(k)) {
          delete next[k];
          changed = true;
        }
      }
      return changed ? next : d;
    });
    setAmountDraft((d) => {
      let changed = false;
      const next = { ...d };
      for (const k of Object.keys(next)) {
        if (!ids.has(k)) {
          delete next[k];
          changed = true;
        }
      }
      return changed ? next : d;
    });
  }, [rows]);

  useEffect(() => {
    setStatusDraft((d) => {
      let changed = false;
      const next = { ...d };
      for (const reg of rows) {
        const draft = next[reg.id];
        if (draft === undefined || draft === reg.status) continue;
        const allowed = getAllowedBookingTransitions(reg.status);
        if (!allowed.includes(draft)) {
          delete next[reg.id];
          changed = true;
        }
      }
      return changed ? next : d;
    });
  }, [rows]);

  const paymentSaveIsNoOpForRow = (row: LeaderRegistrationRow) => paymentSaveIsNoOp(row, payDraft, amountDraft);

  function statusFor(r: LeaderRegistrationRow): RegistrationStatus {
    return statusDraft[r.id] ?? r.status;
  }

  function paymentFor(r: LeaderRegistrationRow): RegistrationPaymentStatus {
    return payDraft[r.id] ?? r.paymentStatus;
  }

  function canQuickTransition(reg: LeaderRegistrationRow, target: RegistrationStatus): boolean {
    if (isTerminalBookingState(reg.status)) return false;
    return getAllowedBookingTransitions(reg.status).includes(target);
  }

  function registrationStatusOptions(reg: LeaderRegistrationRow): RegistrationStatus[] {
    const persisted = reg.status;
    const draft = statusFor(reg);
    if (isTerminalBookingState(persisted)) {
      return uniqueOrdered([draft, persisted]);
    }
    const allowed = [...getAllowedBookingTransitions(persisted)];
    const legal = new Set<RegistrationStatus>([persisted, ...allowed]);
    return uniqueOrdered([persisted, draft, ...allowed]).filter((s) => legal.has(s));
  }

  function paymentStatusOptions(reg: LeaderRegistrationRow): RegistrationPaymentStatus[] {
    const persistedWire = persistPaymentWire(reg);
    const persistedPublic = reg.paymentStatus as RegistrationPaymentStatus;
    const draft = paymentFor(reg);
    if (isTerminalBookingState(reg.status) || isTerminalPaymentState(persistedWire)) {
      return uniqueOrdered([draft, persistedPublic]);
    }
    const patchAllowed = [...getAllowedPaymentTransitions(persistedWire, reg.status)].filter(
      (p): p is RegistrationPaymentStatus => PUBLIC_PATCH_PAYMENT.has(p),
    );
    const legal = new Set<RegistrationPaymentStatus>([persistedPublic, ...patchAllowed]);
    return uniqueOrdered([persistedPublic, draft, ...patchAllowed]).filter((s) => legal.has(s));
  }

  const statusMutationErrorMessage = useMemo(
    () => (statusMutation.error instanceof Error ? statusMutation.error.message : null),
    [statusMutation.error],
  );
  const paymentMutationErrorMessage = useMemo(
    () => (paymentMutation.error instanceof Error ? paymentMutation.error.message : null),
    [paymentMutation.error],
  );

  return {
    statusDraft,
    payDraft,
    amountDraft,
    statusPendingRowId,
    paymentPendingRowId,
    statusFor,
    paymentFor,
    canQuickTransition,
    registrationStatusOptions,
    paymentStatusOptions,
    paymentSaveIsNoOpForRow,
    statusMutation,
    paymentMutation,
    statusMutationErrorMessage,
    paymentMutationErrorMessage,
    setStatusDraft: (id: string, next: RegistrationStatus) => setStatusDraft((d) => ({ ...d, [id]: next })),
    setPayDraft: (id: string, next: RegistrationPaymentStatus) => setPayDraft((d) => ({ ...d, [id]: next })),
    setAmountDraft: (id: string, next: string) => setAmountDraft((d) => ({ ...d, [id]: next })),
    onApplyStatus: (id: string, targetStatus: RegistrationStatus) => {
      const row = rows.find((r) => r.id === id) ?? visibleRows.find((r) => r.id === id);
      if (!row) return;
      if (isTerminalBookingState(row.status)) return;
      if (statusPendingRowId === row.id) return;
      statusMutation.mutate({
        id,
        targetStatus,
        expected_row_version: row.rowVersion,
      });
    },
    onSavePayment: (id: string, nextStatus: RegistrationPaymentStatus, rawAmount: string) => {
      const row = rows.find((r) => r.id === id) ?? visibleRows.find((r) => r.id === id);
      if (!row) return;
      if (isTerminalBookingState(row.status) || isTerminalPaymentState(persistPaymentWire(row))) return;
      if (paymentPendingRowId === row.id) return;
      const raw = rawAmount.trim();
      const paidAmount = raw === "" ? undefined : Number(raw);
      paymentMutation.mutate({
        id,
        paymentStatus: nextStatus,
        expected_row_version: row.rowVersion,
        ...(typeof paidAmount === "number" && !Number.isNaN(paidAmount) ? { paidAmount } : {}),
      });
    },
    statusMutationIsErrorForRow: (id: string) => Boolean(statusMutation.isError && statusMutation.variables?.id === id),
    paymentMutationIsErrorForRow: (id: string) =>
      Boolean(paymentMutation.isError && paymentMutation.variables?.id === id),
    isTerminalBookingState,
    isTerminalPaymentStateForRow: (row: LeaderRegistrationRow) => isTerminalPaymentState(persistPaymentWire(row)),
  };
}

"use client";

import type { TourDetailAccessLevel, TourDetailViewHints, TourDto } from "@repo/types";
import { useTranslations } from "next-intl";
import type { ReactNode } from "react";

import { Card, CardBody, CardHeader, CardTitle } from "@tour/ui";

import {
  TourDetailLockedContent,
  type TourDetailLockedReason,
  type TourDetailLockedVariant,
} from "@/components/tours/TourDetailLockedContent";
import {
  labelExperienceLevel,
  labelFitnessLevel,
  labelGenderRestriction,
} from "@/features/tours/wizard/participationLabels";
import styles from "./tour-detail-client.module.css";

type Props = {
  tour: TourDto;
  accessLevel?: TourDetailAccessLevel;
  viewHints?: TourDetailViewHints;
  showRegister?: boolean;
  onRegister?: () => void;
};

function formatTransportModesList(modes: TourDto["transportModes"] | undefined): string | undefined {
  if (!modes?.length) return undefined;
  return modes.map((m) => TRANSPORT_LABELS[m] ?? m).join("، ");
}

const TRANSPORT_LABELS: Record<string, string> = {
  plane: "هواپیما",
  train: "قطار",
  bus: "اتوبوس",
  midibus: "میدل‌باس",
  private_car: "خودرو شخصی",
};

function trimStr(v: unknown): string {
  return typeof v === "string" ? v.trim() : "";
}

function MetaRow({ term, children }: { term: string; children: ReactNode }) {
  if (children == null || children === false) return null;
  if (typeof children === "string" && children.trim() === "") return null;
  return (
    <div className={styles.field}>
      <dt className={styles.term}>{term}</dt>
      <dd className={styles.def}>{children}</dd>
    </div>
  );
}

function Subheading({ children }: { children: ReactNode }) {
  return (
    <h4
      style={{
        margin: "var(--space-4) 0 var(--space-2)",
        fontSize: "var(--text-small-size)",
        fontWeight: 600,
        color: "var(--color-text-primary)",
      }}
    >
      {children}
    </h4>
  );
}

export function TourTripDetailsPanel({
  tour,
  accessLevel = "GUEST",
  viewHints = { gpsUnlocked: false, gpsUnlockAt: null },
  showRegister = false,
  onRegister,
}: Props) {
  const t = useTranslations("tours");
  const tAcc = useTranslations("tours.new");
  const tDenali = useTranslations("tours.denali");

  const isGuest = accessLevel === "GUEST";
  const isPurchased = accessLevel === "PURCHASED_USER";
  const showGpsLocked = isPurchased && !viewHints.gpsUnlocked;

  const td = tour.details?.tripDetails;
  if (td == null || typeof td !== "object" || Array.isArray(td)) {
    return null;
  }

  const overview =
    td.overview != null && typeof td.overview === "object" && !Array.isArray(td.overview)
      ? (td.overview as Record<string, unknown>)
      : undefined;
  const logistics =
    td.logistics != null && typeof td.logistics === "object" && !Array.isArray(td.logistics)
      ? (td.logistics as Record<string, unknown>)
      : undefined;
  const participation =
    td.participation != null && typeof td.participation === "object" && !Array.isArray(td.participation)
      ? (td.participation as Record<string, unknown>)
      : undefined;
  const policies =
    td.policies != null && typeof td.policies === "object" && !Array.isArray(td.policies)
      ? (td.policies as Record<string, unknown>)
      : undefined;
  const itinerary =
    td.itinerary != null && typeof td.itinerary === "object" && !Array.isArray(td.itinerary)
      ? (td.itinerary as Record<string, unknown>)
      : undefined;

  const shortIntro = trimStr(overview?.shortIntro);
  const denaliTourKindRaw = trimStr(overview?.denaliTourKind);
  const denaliTourKindLabel = denaliTourKindRaw
    ? tDenali(`tourKind.${denaliTourKindRaw}` as "tourKind.mountain_day")
    : "";
  const privateCarModeRaw = trimStr(logistics?.privateCarMode);
  const privateCarModeLabel = privateCarModeRaw
    ? tDenali(`transport.privateCarMode.${privateCarModeRaw}` as "transport.privateCarMode.car_share_fixed_dong")
    : "";
  const difficultyRating =
    typeof overview?.difficultyLevel === "number" && Number.isFinite(overview.difficultyLevel)
      ? overview.difficultyLevel
      : undefined;
  const elevationGainMeters =
    typeof overview?.elevationGainMeters === "number" && Number.isFinite(overview.elevationGainMeters)
      ? overview.elevationGainMeters
      : undefined;
  const itineraryOutline = trimStr(itinerary?.outline);
  const programNotes = trimStr(itinerary?.programNotes);
  const gatheringPoints = logistics?.gatheringPoints;
  const hasGatheringPoints =
    Array.isArray(gatheringPoints) && gatheringPoints.length > 0;
  const departureDate = trimStr(logistics?.departureDate);
  const returnDate = trimStr(logistics?.returnDate);
  const departureMeetingTime = trimStr(logistics?.departureMeetingTime);
  const returnMeetingTime = trimStr(logistics?.returnMeetingTime);
  const meetingPoint = trimStr(logistics?.meetingPoint);
  const returnPoint = trimStr(logistics?.returnPoint);
  const transportationNotes = trimStr(logistics?.transportationNotes);
  const accommodationNotes = trimStr(logistics?.accommodationNotes);
  const mealNotes = trimStr(logistics?.mealNotes);
  const primaryTransportMode = trimStr(logistics?.primaryTransportMode);
  const transportModesSummary = formatTransportModesList(tour.transportModes);
  const fuelShareToman =
    typeof logistics?.fuelShareToman === "number" && Number.isFinite(logistics.fuelShareToman)
      ? logistics.fuelShareToman
      : undefined;
  const leaderProvidesInsurance = logistics?.leaderProvidesInsurance === true;
  const leaderInsuranceNotes = trimStr(logistics?.leaderInsuranceNotes);
  const groupSizeMin =
    typeof logistics?.groupSizeMin === "number" && Number.isFinite(logistics.groupSizeMin)
      ? logistics.groupSizeMin
      : undefined;
  const groupSizeMax =
    typeof logistics?.groupSizeMax === "number" && Number.isFinite(logistics.groupSizeMax)
      ? logistics.groupSizeMax
      : undefined;

  const accommodationSlugs = Array.isArray(logistics?.accommodationTypes)
    ? (logistics!.accommodationTypes as unknown[]).filter((x): x is string => typeof x === "string" && x.trim() !== "")
    : [];

  const requirements = trimStr(participation?.requirements);
  const technicalSkillRequired = trimStr(participation?.technicalSkillRequired);
  const minimumAge =
    typeof participation?.minimumAge === "number" && Number.isFinite(participation.minimumAge)
      ? participation.minimumAge
      : undefined;
  const genderRestriction = trimStr(participation?.genderRestriction);
  const experienceLevel = trimStr(participation?.experienceLevel);
  const fitnessLevel = trimStr(participation?.fitnessLevel);
  const sportsInsuranceRequired = participation?.sportsInsuranceRequired === true;
  const registrationNationalIdRequired = participation?.registrationNationalIdRequired === true;
  const skillsRequired = Array.isArray(participation?.skillsRequired)
    ? (participation!.skillsRequired as unknown[]).filter((x): x is string => typeof x === "string" && x.trim() !== "")
    : [];
  const documentsRequired = Array.isArray(participation?.documentsRequired)
    ? (participation!.documentsRequired as unknown[]).filter((x): x is string => typeof x === "string" && x.trim() !== "")
    : [];

  const cancellationPolicy = trimStr(policies?.cancellationPolicy);
  const refundPolicy = trimStr(policies?.refundPolicy);
  const attendanceRules = trimStr(policies?.attendanceRules);
  const safetyPolicy = trimStr(policies?.safetyPolicy);
  const weatherPolicy = trimStr(policies?.weatherPolicy);
  const reservationRules = trimStr(policies?.reservationRules);

  const segmentActivities = itinerary?.segmentActivities;
  const dayPlans = itinerary?.dayPlans;

  let itineraryBody: ReactNode = null;
  if (Array.isArray(segmentActivities) && segmentActivities.length > 0) {
    itineraryBody = (
      <ul className={styles.equipmentList}>
        {segmentActivities.map((day, idx) => {
          if (!day || typeof day !== "object") return null;
          const d = day as Record<string, unknown>;
          const title = trimStr(d.title) || `${t("detail_itineraryDay")} ${typeof d.dayNumber === "number" ? d.dayNumber : idx + 1}`;
          const desc = trimStr(d.description);
          return (
            <li key={`seg-${idx}`}>
              <strong>{title}</strong>
              {desc ? <> — {desc}</> : null}
            </li>
          );
        })}
      </ul>
    );
  } else if (Array.isArray(dayPlans) && dayPlans.length > 0) {
    itineraryBody = (
      <ul className={styles.equipmentList}>
        {dayPlans.map((row, idx) => {
          if (!row || typeof row !== "object") return null;
          const d = row as Record<string, unknown>;
          const dayNum = typeof d.day === "number" ? d.day : idx + 1;
          const title = trimStr(d.title) || `${t("detail_itineraryDay")} ${dayNum}`;
          const desc = trimStr(d.description);
          return (
            <li key={`dp-${idx}`}>
              <strong>{title}</strong>
              {desc ? <> — {desc}</> : null}
            </li>
          );
        })}
      </ul>
    );
  }

  const accommodationLabels =
    accommodationSlugs.length > 0
      ? accommodationSlugs.map((slug) => tAcc(`trip_accommodation_${slug}` as Parameters<typeof tAcc>[0])).join("، ")
      : "";

  const hasGuestLogisticsDates =
    isGuest && (departureDate || returnDate || departureMeetingTime || returnMeetingTime);

  const hasLogisticsBlock =
    hasGuestLogisticsDates ||
    (!isGuest &&
      (departureDate ||
        returnDate ||
        departureMeetingTime ||
        returnMeetingTime ||
        meetingPoint ||
        returnPoint ||
        primaryTransportMode ||
        tour.transportModes.length > 1 ||
        fuelShareToman != null ||
        accommodationLabels ||
        accommodationNotes ||
        transportationNotes ||
        mealNotes ||
        leaderProvidesInsurance ||
        leaderInsuranceNotes ||
        groupSizeMin != null ||
        groupSizeMax != null));

  const hasParticipationBlock =
    requirements ||
    technicalSkillRequired ||
    minimumAge != null ||
    genderRestriction ||
    experienceLevel ||
    fitnessLevel ||
    sportsInsuranceRequired ||
    registrationNationalIdRequired ||
    skillsRequired.length > 0 ||
    documentsRequired.length > 0;

  const hasPoliciesBlock =
    cancellationPolicy ||
    refundPolicy ||
    attendanceRules ||
    safetyPolicy ||
    weatherPolicy ||
    reservationRules;

  const hasItineraryBlock = itineraryBody != null;
  const hasProgramNotesBlock = programNotes.length > 0;

  const renderLocked = (
    reason: TourDetailLockedReason,
    variant: TourDetailLockedVariant,
    options?: { unlockAt?: string | null; withRegisterCta?: boolean },
  ) => (
    <TourDetailLockedContent
      reason={reason}
      variant={variant}
      unlockAt={options?.unlockAt}
      onRegister={onRegister}
      showRegister={Boolean(showRegister && options?.withRegisterCta && variant === "guest")}
    />
  );

  const showLogisticsSection =
    hasGuestLogisticsDates || hasLogisticsBlock || isGuest || showGpsLocked;

  const hasDenaliOverview =
