function discountSliderValue(discountInput: string): number {
  const trimmed = discountInput.trim();
  if (trimmed === "") return 0;
  const parsed = Number(trimmed);
  if (!Number.isInteger(parsed) || parsed < 0) return 0;
  if (parsed > 100) return 100;
  return parsed;
}

type RewardsFormSnapshot = {
  discountInput: string;
  loyaltyClub: "" | WorkspaceLoyaltyClubBadgeId;
  selectableLeader: boolean;
  labelsDraft: string[];
};

export type WorkspaceUserRewardsModalProps = {
  open: boolean;
  user: WorkspaceUserDto | null;
  onClose: () => void;
  onSaved?: () => void | Promise<void>;
};

export function WorkspaceUserRewardsModal({
  open,
  user,
  onClose,
  onSaved
}: WorkspaceUserRewardsModalProps): JSX.Element | null {
  const toast = useAppToast();
  const [activeTab, setActiveTab] = useState<RewardsTabId>("privileges");
  const [discountInput, setDiscountInput] = useState("");
  const [loyaltyClub, setLoyaltyClub] = useState<"" | WorkspaceLoyaltyClubBadgeId>("");
  const [selectableLeader, setSelectableLeader] = useState(false);
  const [labelsDraft, setLabelsDraft] = useState<string[]>([]);
  const [labelInput, setLabelInput] = useState("");
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const rewardsMutation = useMutation({
    mutationFn: async ({
      targetUser,
      form
    }: {
      targetUser: WorkspaceUserDto;
      form: RewardsFormSnapshot;
    }) => {
      const trimmed = form.discountInput.trim();
      let permanentDiscountPercentage: number | null | undefined;
      if (trimmed !== "") {
        const parsed = Number(trimmed);
        if (!Number.isInteger(parsed) || parsed < 0 || parsed > 100) {
          throw new Error(copy.discountValidationError);
        }
        permanentDiscountPercentage = parsed;
      } else if (
        targetUser.permanentDiscountPercentage !== undefined &&
        targetUser.permanentDiscountPercentage !== null
      ) {
        permanentDiscountPercentage = null;
      }

      const preservedNonLoyalty = (targetUser.rewardBadges ?? []).filter(
        (b): b is WorkspaceRewardBadgeId =>
          (NON_LOYALTY_BADGES as readonly string[]).includes(b)
      );
      const badges: WorkspaceRewardBadgeId[] = [...preservedNonLoyalty];
      if (form.loyaltyClub) {
        badges.push(form.loyaltyClub);
      }

      return postWorkspaceUserRewards(targetUser.id, {
        permanentDiscountPercentage,
        badges,
        isSelectableLeader: form.selectableLeader,
        labels: form.labelsDraft
      });
    },
    onSuccess: async () => {
      toast.success({ message: copy.savedToast });
      await onSaved?.();
      onClose();
    },
    onError: (err: unknown) => {
      const message =
        err instanceof ApiError
          ? err.message
          : err instanceof Error
            ? err.message
            : copy.saveErrorFallback;
      setErrorMessage(message);
      toast.error({ message });
    }
  });

  const isPending = rewardsMutation.isPending;
  const hydratedUserIdRef = useRef<string | null>(null);

  useEffect(() => {
    if (!open) {
      hydratedUserIdRef.current = null;
      setActiveTab("privileges");
      return;
    }
    if (!user) {
      return;
    }
    if (hydratedUserIdRef.current === user.id) {
      return;
    }
    hydratedUserIdRef.current = user.id;
    const discount =
      user.permanentDiscountPercentage !== undefined && user.permanentDiscountPercentage !== null
        ? String(user.permanentDiscountPercentage)
        : "";
    setDiscountInput(discount);
    setLoyaltyClub(loyaltyFromUser(user));
    setSelectableLeader(Boolean(user.isSelectableLeader));
    setLabelsDraft([...(user.labels ?? [])]);
    setLabelInput("");
    setErrorMessage(null);
    rewardsMutation.reset();
  }, [open, rewardsMutation, user]);

  const tripHistoryQuery = useQuery({
    queryKey: ["workspace-user-booking-summary", user?.id],
    queryFn: () => getWorkspaceUserBookingSummary(user!.id),
    enabled: open && activeTab === "trips" && Boolean(user?.id)
  });

  const canSubmit = useMemo(() => !isPending && Boolean(user?.id), [isPending, user?.id]);
  const discountSlider = discountSliderValue(discountInput);

  const handleClose = useCallback(() => {
    if (isPending) return;
    onClose();
  }, [isPending, onClose]);

  const handleSubmit = useCallback(() => {
    if (!user || !canSubmit) return;
    setErrorMessage(null);
    rewardsMutation.mutate({
      targetUser: user,
      form: { discountInput, loyaltyClub, selectableLeader, labelsDraft }
    });
  }, [canSubmit, discountInput, labelsDraft, loyaltyClub, rewardsMutation, selectableLeader, user]);

  const addLabel = useCallback(() => {
    const next = labelInput.trim();
    if (!next || labelsDraft.includes(next) || labelsDraft.length >= 32) {
      return;
    }
    setLabelsDraft((prev) => [...prev, next]);
    setLabelInput("");
  }, [labelInput, labelsDraft]);

  const removeLabel = useCallback((label: string) => {
    setLabelsDraft((prev) => prev.filter((l) => l !== label));
  }, []);

  if (!user) {
    return null;
  }

  const tabPanelId = (tab: RewardsTabId) => `rewards-tabpanel-${tab}-${user.id}`;
  const tabButtonId = (tab: RewardsTabId) => `rewards-tab-${tab}-${user.id}`;

  return (
    <Modal
      open={open}
      onClose={handleClose}
      title={copy.title}
      panelClassName={styles.rewardsModalPanelWide}
      footer={
        activeTab === "privileges" ? (
          <>
            <Button type="button" variant="ghost" disabled={isPending} onClick={handleClose}>
              {copy.cancelButton}
            </Button>
            <Button type="button" variant="primary" disabled={!canSubmit} onClick={handleSubmit}>
              {isPending ? copy.savingButton : copy.saveButton}
            </Button>
          </>
        ) : (
          <Button type="button" variant="ghost" disabled={isPending} onClick={handleClose}>
            {copy.cancelButton}
          </Button>
        )
      }
    >
      <div className={styles.rewardsModalBody} dir="rtl" aria-busy={isPending}>
        <div role="tablist" aria-label={copy.title} className={styles.rewardsModalTabs}>
          <button
            type="button"
            role="tab"
            id={tabButtonId("privileges")}
            aria-selected={activeTab === "privileges"}
            aria-controls={tabPanelId("privileges")}
            className={
              activeTab === "privileges"
                ? `${styles.rewardsModalTab} ${styles.rewardsModalTabActive}`
                : styles.rewardsModalTab
            }
            disabled={isPending}
            onClick={() => setActiveTab("privileges")}
          >
            {copy.tabPrivileges}
          </button>
          <button
            type="button"
            role="tab"
            id={tabButtonId("trips")}
            aria-selected={activeTab === "trips"}
            aria-controls={tabPanelId("trips")}
            className={
              activeTab === "trips"
                ? `${styles.rewardsModalTab} ${styles.rewardsModalTabActive}`
                : styles.rewardsModalTab
            }
            disabled={isPending}
            onClick={() => setActiveTab("trips")}
          >
            {copy.tabTripHistory}
          </button>
        </div>

        {activeTab === "privileges" ? (
          <div
            role="tabpanel"
            id={tabPanelId("privileges")}
            aria-labelledby={tabButtonId("privileges")}
          >
            <p className={styles.rewardsModalIntro}>
              {copy.description.replace("{name}", user.name)}
            </p>
            <FormField label={copy.discountLabel} description={copy.discountHint}>
              <div className={styles.rewardsDiscountControls}>
                <Input
                  type="number"
                  min={0}
                  max={100}
                  step={1}
                  inputMode="numeric"
                  value={discountInput}
                  disabled={isPending}
                  placeholder={copy.discountPlaceholder}
                  onChange={(e) => setDiscountInput(e.target.value)}
                />
                <input
                  type="range"
                  className={styles.rewardsDiscountSlider}
                  min={0}
                  max={100}
                  step={1}
                  value={discountSlider}
                  disabled={isPending}
                  aria-label={copy.discountSliderAriaLabel}
                  onChange={(e) => setDiscountInput(e.target.value)}
                />
              </div>
            </FormField>
            <FormField label={copy.selectableLeaderLabel} description={copy.selectableLeaderHint}>
              <div className={styles.rewardsLeaderSwitchRow}>
                <button
                  type="button"
                  role="switch"
                  className={styles.rewardsLeaderSwitch}
                  aria-checked={selectableLeader}
                  aria-label={copy.selectableLeaderLabel}
                  disabled={isPending}
                  onClick={() => setSelectableLeader((prev) => !prev)}
                >
                  <span className={styles.rewardsLeaderSwitchTrack} aria-hidden>
                    <span className={styles.rewardsLeaderSwitchThumb} />
                  </span>
                </button>
                <span className={styles.rewardsLeaderSwitchLabel}>{copy.selectableLeaderLabel}</span>
              </div>
            </FormField>
            <FormField label={copy.loyaltyClubLabel} description={copy.loyaltyClubHint}>
              <Select
                value={loyaltyClub}
                disabled={isPending}
                onChange={(e) =>
                  setLoyaltyClub(e.target.value as "" | WorkspaceLoyaltyClubBadgeId)
                }
              >
                <option value="">{copy.loyaltyClubNone}</option>
                {WORKSPACE_LOYALTY_CLUB_BADGE_IDS.map((tier) => (
                  <option key={tier} value={tier}>
                    {LOYALTY_TIER_LABELS[tier]}
                  </option>
                ))}
              </Select>
            </FormField>
            <FormField label={copy.labelsLabel} description={copy.labelsHint}>
              <div className={styles.rewardsLabelsEditor}>
                <div className={styles.rewardsLabelsInputRow}>
                  <Input
                    value={labelInput}
                    disabled={isPending}
                    placeholder={copy.labelsInputPlaceholder}
                    onChange={(e) => setLabelInput(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") {
                        e.preventDefault();
                        addLabel();
                      }
                    }}
                  />
                  <Button type="button" variant="secondary" disabled={isPending} onClick={addLabel}>
                    {copy.labelsAddButton}
                  </Button>
                </div>
                {labelsDraft.length > 0 ? (
                  <div className={styles.rewardsLabelChips}>
                    {labelsDraft.map((label) => (
                      <span key={label} className={styles.rewardsLabelChip}>
                        {label}
                        <button
                          type="button"
                          className={styles.rewardsLabelChipRemove}
                          aria-label={copy.labelsRemoveAria.replace("{label}", label)}
                          disabled={isPending}
                          onClick={() => removeLabel(label)}
                        >
                          ×
                        </button>
                      </span>
                    ))}
                  </div>
                ) : null}
              </div>
            </FormField>
            {errorMessage ? (
              <p className={styles.rewardsModalError} role="alert">
                {errorMessage}
              </p>
            ) : null}
          </div>
        ) : (
          <div
            role="tabpanel"
            id={tabPanelId("trips")}
            aria-labelledby={tabButtonId("trips")}
          >
            {tripHistoryQuery.isLoading ? (
              <p className={styles.tripHistoryPlaceholder}>{copy.tripHistoryLoading}</p>
            ) : tripHistoryQuery.isError ? (
              <p className={styles.tripHistoryPlaceholder} role="alert">
                {copy.tripHistoryError}
              </p>
            ) : (tripHistoryQuery.data?.trips?.length ?? 0) === 0 ? (
              <p className={styles.tripHistoryPlaceholder}>{copy.tripHistoryEmpty}</p>
            ) : (
              <table className={styles.tripHistoryTable}>
                <thead>
                  <tr>
                    <th scope="col">{copy.tripColumnTour}</th>
                    <th scope="col">{copy.tripColumnDeparture}</th>
                    <th scope="col">{copy.tripColumnRegistration}</th>
                    <th scope="col">{copy.tripColumnPayment}</th>
                  </tr>
                </thead>
                <tbody>
                  {tripHistoryQuery.data!.trips.map((trip, index) => (
                    <tr key={`${trip.tourTitle}-${trip.departureDate ?? ""}-${index}`}>
                      <td>{trip.tourTitle}</td>
                      <td>{formatDepartureDateFa(trip.departureDate)}</td>
                      <td>
                        <span className={styles.tripHistoryStatusBadge}>
                          {formatRegistrationStatusFa(trip.registrationStatus)}
                        </span>
                      </td>
                      <td>
                        <span className={styles.tripHistoryStatusBadge}>
                          {formatPaymentStatusFa(trip.paymentStatus)}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}
      </div>
    </Modal>
  );
}

const STORAGE_KEY = "users-invite-name-notes";

type NotesMap = Record<string, string>;

function readMap(): NotesMap {
  if (typeof window === "undefined") {
    return {};
  }
  try {
    const raw = window.sessionStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return {};
    }
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== "object") {
      return {};
    }
    return parsed as NotesMap;
  } catch {
    return {};
  }
}

function writeMap(map: NotesMap): void {
  if (typeof window === "undefined") {
    return;
  }
  window.sessionStorage.setItem(STORAGE_KEY, JSON.stringify(map));
}

export function getInviteNameNote(key: string): string | null {
  const note = readMap()[key]?.trim();
  return note && note.length > 0 ? note : null;
}

export function setInviteNameNoteForPhone(phone: string, note: string): void {
  const trimmed = note.trim();
  if (!trimmed) {
    return;
  }
  const map = readMap();
  map[`phone:${phone.trim()}`] = trimmed;
  writeMap(map);
}

export function migrateInviteNameNotePhoneToInviteId(
  phone: string,
  inviteId: string
): void {
  const map = readMap();
  const phoneKey = `phone:${phone.trim()}`;
  const existing = map[phoneKey]?.trim();
  if (existing) {
    map[`invite:${inviteId}`] = existing;
    delete map[phoneKey];
    writeMap(map);
  }
}

export function getInviteDisplayNote(inviteId: string, phone: string): string | null {
  return getInviteNameNote(`invite:${inviteId}`) ?? getInviteNameNote(`phone:${phone.trim()}`);
}

import type { ApiError } from "@/lib/api-client";

/** Backend codes for `tripDetails` workspace catalog validation (400). */
export const TENANT_CATALOG_ERROR_CODES = {
  EQUIPMENT: "INVALID_EQUIPMENT_IDS_FOR_TENANT",
  TOUR_THEMES: "INVALID_TOUR_THEME_IDS_FOR_TENANT",
  GUIDE_LANGUAGES: "INVALID_GUIDE_LANGUAGE_IDS_FOR_TENANT",
} as const;

/**
 * Keys under the next-intl namespace `tours.catalogErrors` (see messages/en.json & fa.json).
 * UI maps `error.code` → localized string via `useTranslations("tours.catalogErrors")`.
 */
export const TENANT_CATALOG_MESSAGE_KEYS = [
  "invalidEquipmentIdsTenant",
  "invalidTourThemeIdsTenant",
  "invalidGuideLanguageIdsTenant",
  "genericInvalidCatalogTenant",
] as const;

export type TenantCatalogMessageKey = (typeof TENANT_CATALOG_MESSAGE_KEYS)[number];

type ErrorEnvelope = {
  error?: {
    code?: unknown;
    invalidIds?: unknown;
  };
};

/**
 * Reads optional `invalidIds` from the API error body (`error.data` on {@link ApiError}).
 * Shape matches `{ error: { code, message, invalidIds?: string[] } }`.
 */
export function parseTenantCatalogErrorPayload(data: unknown): {
  code?: string;
  invalidIds: string[];
} {
  if (data == null || typeof data !== "object") {
    return { invalidIds: [] };
  }
  const envelope = data as ErrorEnvelope;
  const err = envelope.error;
  if (!err || typeof err !== "object") {
    return { invalidIds: [] };
  }
  const code = typeof err.code === "string" && err.code.trim() ? err.code.trim() : undefined;
  const raw = err.invalidIds;
  const invalidIds = Array.isArray(raw)
    ? raw.filter((id): id is string => typeof id === "string" && id.length > 0)
    : [];
  return { code, invalidIds };
}

/**
 * When `code` is a known tenant-catalog mismatch, returns the i18n message key; otherwise
 * matches generic `INVALID_*_IDS_FOR_TENANT` and returns the generic catalog hint key.
 */
export function getCatalogErrorMessageKey(code: string | undefined): TenantCatalogMessageKey | null {
  if (!code) {
    return null;
  }
  switch (code) {
    case TENANT_CATALOG_ERROR_CODES.EQUIPMENT:
      return "invalidEquipmentIdsTenant";
    case TENANT_CATALOG_ERROR_CODES.TOUR_THEMES:
      return "invalidTourThemeIdsTenant";
    case TENANT_CATALOG_ERROR_CODES.GUIDE_LANGUAGES:
      return "invalidGuideLanguageIdsTenant";
    default:
      if (code.startsWith("INVALID_") && code.endsWith("_IDS_FOR_TENANT")) {
        return "genericInvalidCatalogTenant";
      }
      return null;
  }
}

/** Dev-only: logs invalid catalog UUIDs without exposing them in the UI. */
export function logTenantCatalogMismatchDev(apiError: ApiError): void {
  if (process.env.NODE_ENV !== "development") {
    return;
  }
  const { invalidIds } = parseTenantCatalogErrorPayload(apiError.data);
  if (invalidIds.length > 0) {
  }
}

import { GeocodingProviderError, isProviderFailStatus } from "./geocoding-provider-error";
import { searchIranMountainLandmarks } from "./iran-mountain-landmarks";
import { fetchMapIrSearch } from "./map-ir";
import { fetchNeshanSearch } from "./neshan";
import {
  fetchNominatimReverse,
  fetchNominatimSearch,
  type GeocodingSearchResult,
} from "./nominatim";

export const GEOCODING_SEARCH_LIMIT = 6;
export const GEOCODING_FALLBACK_LOG = "GEOCODING_PROVIDER_FAIL_SWITCHING_TO_FALLBACK";

type GeocodingProviderId = "neshan" | "mapir" | "nominatim";

function resolvePrimaryProvider(): GeocodingProviderId {
  if (process.env.NESHAN_API_KEY?.trim()) {
    return "neshan";
  }
  if (process.env.MAP_IR_TOKEN?.trim()) {
    return "mapir";
  }
  return "nominatim";
}

function coordKey(result: GeocodingSearchResult): string {
  return `${result.latitude.toFixed(4)}:${result.longitude.toFixed(4)}`;
}

/** Local landmark matches first; dedupe remote rows by rounded coordinates. */
export function mergeGeocodingResults(
  local: GeocodingSearchResult[],
  remote: GeocodingSearchResult[],
  limit = GEOCODING_SEARCH_LIMIT,
): GeocodingSearchResult[] {
  const seen = new Set<string>();
  const out: GeocodingSearchResult[] = [];
  for (const row of [...local, ...remote]) {
    const key = coordKey(row);
    if (seen.has(key)) {
      continue;
    }
    seen.add(key);
    out.push(row);
    if (out.length >= limit) {
      break;
    }
  }
  return out;
}

async function fetchFromProvider(
  provider: GeocodingProviderId,
  query: string,
  limit: number,
): Promise<GeocodingSearchResult[]> {
  if (provider === "neshan") {
    const key = process.env.NESHAN_API_KEY?.trim();
    if (!key) {
      throw new GeocodingProviderError("neshan", 503);
    }
    return fetchNeshanSearch(query, key, { limit });
  }
  if (provider === "mapir") {
    const key = process.env.MAP_IR_TOKEN?.trim();
    if (!key) {
      throw new GeocodingProviderError("mapir", 503);
    }
    return fetchMapIrSearch(query, key, { limit });
  }
  return fetchNominatimSearch(query, { limit, countryCodes: "ir" });
}

function logProviderFallback(provider: GeocodingProviderId, err: unknown): void {
  const status = err instanceof GeocodingProviderError ? err.status : 0;
  if (status === 0 || isProviderFailStatus(status)) {
  }
}

async function fetchNominatimFallback(query: string, limit: number): Promise<GeocodingSearchResult[]> {
  try {
    return await fetchNominatimSearch(query, { limit, countryCodes: "ir" });
  } catch {
    return [];
  }
}

/**
 * Resilient geocoding: static Iranian mountain dictionary + optional Neshan/Map.ir primary
 * with Nominatim fallback. Never throws — callers always get a merged result array.
 */
export async function searchGeocodingWithFallback(
  query: string,
  options?: { limit?: number },
): Promise<GeocodingSearchResult[]> {
  const limit = options?.limit ?? GEOCODING_SEARCH_LIMIT;
  const local = searchIranMountainLandmarks(query, limit);
  const primary = resolvePrimaryProvider();
  let remote: GeocodingSearchResult[] = [];

  try {
    remote = await fetchFromProvider(primary, query, limit);
  } catch (err) {
    logProviderFallback(primary, err);
    if (primary !== "nominatim") {
      remote = await fetchNominatimFallback(query, limit);
    }
  }

  return mergeGeocodingResults(local, remote, limit);
}

/**
 * Reverse geocoding: gets human address from coordinates.
 */
export async function reverseGeocode(lat: number, lon: number): Promise<string | null> {
  // We can add MapIr/Neshan reverse later if needed; Nominatim is the current standard.
  return fetchNominatimReverse(lat, lon);
}

/** Nominatim (OpenStreetMap) geocoding result normalized for Denali location zones. */
export type GeocodingSearchResult = {
  displayName: string;
  addressText: string;
  latitude: number;
  longitude: number;
};

export type NominatimSearchRow = {
  display_name?: string;
  lat?: string;
  lon?: string;
};

const NOMINATIM_SEARCH_URL = "https://nominatim.openstreetmap.org/search";

export function parseNominatimRows(rows: unknown, limit = 5): GeocodingSearchResult[] {
  if (!Array.isArray(rows)) {
    return [];
  }
  const out: GeocodingSearchResult[] = [];
  for (const row of rows) {
    if (!row || typeof row !== "object") {
      continue;
    }
    const r = row as NominatimSearchRow;
    const lat = Number(r.lat);
    const lon = Number(r.lon);
    const displayName = typeof r.display_name === "string" ? r.display_name.trim() : "";
    if (!displayName || !Number.isFinite(lat) || !Number.isFinite(lon)) {
      continue;
    }
    out.push({
      displayName,
      addressText: displayName,
      latitude: lat,
      longitude: lon,
    });
    if (out.length >= limit) {
      break;
    }
  }
  return out;
}

export async function fetchNominatimSearch(
  query: string,
  options?: { limit?: number; countryCodes?: string },
): Promise<GeocodingSearchResult[]> {
  const q = query.trim();
  if (q.length < 2) {
    return [];
  }
  const limit = options?.limit ?? 5;
  const params = new URLSearchParams({
    format: "json",
    q,
    limit: String(limit),
    addressdetails: "1",
  });
  if (options?.countryCodes) {
    params.set("countrycodes", options.countryCodes);
  }
  const res = await fetch(`${NOMINATIM_SEARCH_URL}?${params.toString()}`, {
    headers: {
      Accept: "application/json",
      "User-Agent": "TourOps-Denali-Wizard/1.0 (location-picker)",
    },
    cache: "no-store",
  });
  if (!res.ok) {
    throw new Error(`nominatim_search_failed:${res.status}`);
  }
  const json = (await res.json()) as unknown;
  return parseNominatimRows(json, limit);
}

const NOMINATIM_REVERSE_URL = "https://nominatim.openstreetmap.org/reverse";

export async function fetchNominatimReverse(
  lat: number,
  lon: number,
): Promise<string | null> {
  const params = new URLSearchParams({
    format: "json",
    lat: String(lat),
    lon: String(lon),
    zoom: "18",
    addressdetails: "1",
  });
  try {
    const res = await fetch(`${NOMINATIM_REVERSE_URL}?${params.toString()}`, {
      headers: {
        Accept: "application/json",
        "User-Agent": "TourOps-Denali-Wizard/1.0 (location-picker-reverse)",
      },
      cache: "no-store",
    });
    if (!res.ok) return null;
    const json = (await res.json()) as any;
    return (json?.display_name as string) ?? null;
  } catch {
    return null;
  }
}

/**
 * Mirrors API rules for ایران کدملی validation (mirror of apps/api identity utils).
 */

const PERSIAN_ZERO = 0x06f0;
const ARABIC_INDIC_ZERO = 0x0660;

export function asciiDigitsFromNationalIdRaw(raw: string): string {
  let out = "";
  for (const ch of raw) {
    const cp = ch.codePointAt(0);
    if (cp === undefined) {
      continue;
    }
    if (cp >= PERSIAN_ZERO && cp <= PERSIAN_ZERO + 9) {
      out += String.fromCodePoint(0x30 + (cp - PERSIAN_ZERO));
      continue;
    }
    if (cp >= ARABIC_INDIC_ZERO && cp <= ARABIC_INDIC_ZERO + 9) {
      out += String.fromCodePoint(0x30 + (cp - ARABIC_INDIC_ZERO));
      continue;
    }
    if (ch >= "0" && ch <= "9") {
      out += ch;
    }
  }
  return out;
}

export function isValidIranNationalIdChecksum(digits10: string): boolean {
  if (!/^\d{10}$/.test(digits10)) {
    return false;
  }
  if (/^(\d)\1{9}$/.test(digits10)) {
    return false;
  }
  const d = digits10.split("").map((c) => Number(c));
  let sum = 0;
  for (let i = 0; i < 9; i += 1) {
    sum += d[i]! * (10 - i);
  }
  const r = sum % 11;
  const check = d[9]!;
  if (r < 2) {
    return check === r;
  }
  return check === 11 - r;
}

