    const hint =
      r === "required" ? FIELD_REQUIRED_HINT : r === "recommended" ? FIELD_RECOMMENDED_HINT : undefined;
    if (!base) return hint;
    if (!hint) return base;
    return `${base} ${hint}`;
  };
