"use client";

import { useTranslations } from "next-intl";
import type { Control, FieldValues } from "react-hook-form";
import { Controller } from "react-hook-form";

import { FormField, Select } from "@tour/ui";

import type { TourDestinationGroup } from "@/hooks/use-tour-destinations";
import type { SettingsDestinationDto } from "@/lib/settings-locations-client";

export type TourDestinationSelectFieldProps = {
  control: Control<FieldValues>;
  name: string;
  groupedRegions: TourDestinationGroup[];
  /** Current tour destination when it is inactive in Settings — shown as a disabled option. */
  inactiveSelection?: SettingsDestinationDto | null;
  error?: string;
  disabled?: boolean;
};

export function TourDestinationSelectField({
  control,
  name,
  groupedRegions,
  inactiveSelection,
  error,
  disabled,
}: TourDestinationSelectFieldProps) {
  const t = useTranslations("tours.new");

  return (
    <FormField label={t("destinationFieldLabel")} error={error}>
      <Controller
        control={control}
        name={name}
        render={({ field }) => {
          const value = typeof field.value === "string" ? field.value : field.value ?? "";
          const strVal = value === null || value === undefined ? "" : String(value);
          const inactiveId = inactiveSelection?.id;
          const inGrouped =
            strVal !== "" &&
            groupedRegions.some((g) => g.items.some((d) => d.id === strVal));
          const showInactiveOption =
            Boolean(inactiveSelection && inactiveId && strVal === inactiveId) &&
            (!inactiveSelection!.isActive || !inGrouped);

          return (
            <Select
              invalid={Boolean(error)}
              disabled={disabled}
              value={strVal}
              onChange={(e) => {
                const v = e.target.value;
                field.onChange(v === "" ? null : v);
              }}
              onBlur={field.onBlur}
              ref={field.ref}
              name={field.name}
            >
              <option value="">{t("destinationPlaceholder")}</option>
              {showInactiveOption && inactiveSelection ? (
                <option value={inactiveId} disabled>
                  {inactiveSelection.name} {t("destinationInactiveSuffix")}
                </option>
              ) : null}
              {groupedRegions.map((group) => (
                <optgroup key={group.regionId} label={group.regionName}>
                  {group.items.map((d) => (
                    <option key={d.id} value={d.id}>
                      {d.name}
                    </option>
                  ))}
                </optgroup>
              ))}
            </Select>
          );
        }}
      />
    </FormField>
  );
}

import { tryParseWorkspaceRole, WorkspaceRole } from "@repo/shared";

/**
 * # Edit-side field RBAC framework
 *
 * Extracted from `tripDetailsFieldConfig.ts` in Phase P15 (promptq.md follow-up) so the
 * three concerns that used to share that file are now in separate, single-responsibility
 * modules:
 *
 * 1. **This file** — pure RBAC + visibility/required-ness types + the
 *    {@link resolveFieldAccess} resolver. No profile-axis knowledge, no field IDs,
 *    no per-matrix data. Reusable by any Edit surface that needs role-gated read/edit
 *    semantics.
 * 2. `./editCoreFieldConfig.ts` — `core.totalCapacity` / `core.capacity` matrix +
 *    leader-rank RBAC overrides. Independent of `TourFormProfile`.
 * 3. `./tripDetailsFieldConfig.ts` — the trip-details base matrix keyed by
 *    `TourFormProfile`. Still the largest of the three; physical deletion is blocked
 *    on a path-namespace rename (Edit's flat `tripDetails.*` paths vs the wizard's
 *    nested `TourCreateFormValues` paths) that is tracked as a separate future slice.
 *
 * **Public surface:** identical to what `tripDetailsFieldConfig.ts` previously exported
 * for the RBAC layer (`FieldVisibility`, `FieldRequiredness`, `UserRole`,
 * `FieldRoleConstraint`, `FieldConfigBase`, `ResolvedFieldAccess`, `resolveFieldAccess`,
 * `normalizeFieldUserRole`). `normalizeFieldUserRole` delegates to `tryParseWorkspaceRole`
 * so persisted roles (including legacy `operator` → member) stay aligned with workspace RBAC.
 */

export type FieldVisibility = "hidden" | "readonly" | "editable";
export type FieldRequiredness = "optional" | "recommended" | "required";
export type UserRole = "guest" | "member" | "leader" | "admin";

export type FieldRoleConstraint = {
  minRoleForEdit?: UserRole;
  minRoleForView?: UserRole;
};

export type FieldConfigBase = {
  visibility: FieldVisibility;
  requiredness: FieldRequiredness;
  labelOverride?: string;
  descriptionOverride?: string;
  /**
   * Minimum workspace/JWT role thresholds (rank-based). Used by core capacity fields.
   * When `allowedRoles` / `viewOnlyRoles` are set (non-empty), list-based RBAC takes
   * precedence instead.
   */
  role?: FieldRoleConstraint;
  /**
   * Explicit allow-list for edit access when `visibility === "editable"`.
   * Omit or leave empty to keep this dimension open (subject only to `role` thresholds /
   * profile visibility).
   */
  allowedRoles?: UserRole[];
  /**
   * Roles that may see the field read-only when `visibility === "editable"`.
   * Evaluated only when list-based RBAC is active (see `allowedRoles` / `viewOnlyRoles`).
   */
  viewOnlyRoles?: UserRole[];
};

export type ResolvedFieldAccess = {
  /** Effective UI mode after global visibility + RBAC. */
  accessLevel: FieldVisibility;
  /** Same as `accessLevel` (kept for callers that already use `.visibility`). */
  visibility: FieldVisibility;
  canView: boolean;
  canEdit: boolean;
  requiredness: FieldRequiredness;
};

export function normalizeFieldUserRole(rawRole: string | null | undefined): UserRole {
  const parsed = tryParseWorkspaceRole(rawRole ?? "");
  if (!parsed) return "guest";
  if (parsed === WorkspaceRole.Owner || parsed === WorkspaceRole.Admin) return "admin";
  if (parsed === WorkspaceRole.Leader) return "leader";
  if (parsed === WorkspaceRole.Member) return "member";
  if (parsed === WorkspaceRole.Viewer) return "guest";
  return "guest";
}

function roleRank(role: UserRole): number {
  if (role === "guest") return 0;
  if (role === "member") return 1;
  if (role === "leader") return 2;
  return 3;
}

function meetsMinRole(current: UserRole, min: UserRole | undefined): boolean {
  if (!min) return true;
  return roleRank(current) >= roleRank(min);
}

function hasListBasedRbac(config: FieldConfigBase | undefined): boolean {
  const a = config?.allowedRoles;
  const v = config?.viewOnlyRoles;
  return (Array.isArray(a) && a.length > 0) || (Array.isArray(v) && v.length > 0);
}

/**
 * Resolves effective field access: profile-matrix `visibility` / `requiredness` plus
 * optional RBAC.
 * - `visibility === "hidden"` → always hidden.
 * - `visibility === "readonly"` → always readonly (no role escalation to edit).
 * - `visibility === "editable"`:
 *   - If `allowedRoles` or `viewOnlyRoles` is non-empty → list-based rules: edit if role
 *     ∈ allowedRoles, else readonly if role ∈ viewOnlyRoles, else hidden.
 *   - Else if `role.minRoleForView` / `minRoleForEdit` → rank thresholds (e.g. core
 *     capacity).
 *   - Else → editable for all roles.
 */
export function resolveFieldAccess<T extends FieldConfigBase>(
  config: T | undefined,
  viewerRole: UserRole,
): ResolvedFieldAccess {
  const visibility = config?.visibility ?? "editable";
  const requiredness = config?.requiredness ?? "optional";

  if (visibility === "hidden") {
    const level = "hidden" as const;
    return { accessLevel: level, visibility: level, canView: false, canEdit: false, requiredness };
  }
  if (visibility === "readonly") {
    const level = "readonly" as const;
    return { accessLevel: level, visibility: level, canView: true, canEdit: false, requiredness };
  }

  if (hasListBasedRbac(config)) {
    const allowed = config!.allowedRoles ?? [];
    const viewOnly = config!.viewOnlyRoles ?? [];
    if (allowed.includes(viewerRole)) {
      const level = "editable" as const;
      return { accessLevel: level, visibility: level, canView: true, canEdit: true, requiredness };
    }
    if (viewOnly.includes(viewerRole)) {
      const level = "readonly" as const;
      return { accessLevel: level, visibility: level, canView: true, canEdit: false, requiredness };
    }
    const level = "hidden" as const;
    return { accessLevel: level, visibility: level, canView: false, canEdit: false, requiredness };
  }

  const canViewByRole = meetsMinRole(viewerRole, config?.role?.minRoleForView);
  const canEditByRole = meetsMinRole(viewerRole, config?.role?.minRoleForEdit);
  if (!canViewByRole) {
    const level = "hidden" as const;
    return { accessLevel: level, visibility: level, canView: false, canEdit: false, requiredness };
  }
  if (!canEditByRole) {
    const level = "readonly" as const;
    return { accessLevel: level, visibility: level, canView: true, canEdit: false, requiredness };
  }
  const level = "editable" as const;
  return { accessLevel: level, visibility: level, canView: true, canEdit: true, requiredness };
}

import { getTourFormProfileDescriptor, type TourFormProfile } from "@repo/types";

import type { TourTripDetails } from "@/features/tours/models/tourTripDetails.schema";

/**
 * Client mirror of server `stripTripDetailsForFormProfile` for flat `TourForm` / PATCH payloads.
 * Strip deltas come from {@link getTourFormProfileDescriptor} (`descriptor.strip`).
 * Returns a cloned object; does not mutate the input.
 */
export function stripTourFormTripDetailsForFormProfile(
  profile: TourFormProfile,
  tripDetails: TourTripDetails | null | undefined,
): TourTripDetails | undefined {
  if (tripDetails == null || typeof tripDetails !== "object") {
    return tripDetails ?? undefined;
  }

  const { strip } = getTourFormProfileDescriptor(profile);
  if (
    strip.clearsTripDetailsRoots.length === 0 &&
    strip.itineraryKeysToDelete.length === 0 &&
    strip.logisticsWhitelist == null
  ) {
    return tripDetails;
  }

  const root = JSON.parse(JSON.stringify(tripDetails)) as Record<string, unknown>;

  for (const key of strip.clearsTripDetailsRoots) {
    delete root[key];
  }

  if (
    strip.itineraryKeysToDelete.length > 0 &&
    root.itinerary != null &&
    typeof root.itinerary === "object"
  ) {
    const it = { ...(root.itinerary as Record<string, unknown>) };
    for (const k of strip.itineraryKeysToDelete) {
      delete it[k];
    }
    if (Object.keys(it).length === 0) {
      delete root.itinerary;
    } else {
      root.itinerary = it;
    }
  }

  if (strip.logisticsWhitelist != null && root.logistics != null && typeof root.logistics === "object") {
    const log = root.logistics as Record<string, unknown>;
    const slim: Record<string, unknown> = {};
    for (const key of strip.logisticsWhitelist) {
      if (log[key] !== undefined) {
        slim[key] = log[key];
      }
    }
    root.logistics = slim;
  }

  return root as TourTripDetails;
}

import {
  Legacy,
  domainProfileFromTourTypeFallback,
  type TourDomainProfile,
  type TourType,
} from "@repo/types";

type EventKind = Legacy.EventKind;
const { eventKindForDomainProfile, resolveEventKindFromTourContext } = Legacy;

import {
  resolveTourFormProfileForTourFormValues,
  type ThemeRowForProfile,
} from "@/features/tours/wizard/tourWizardProfileResolve";

/**
 * Edit-side **adapter** between canonical `TourDomainProfile` (`@repo/types`) and legacy
 * `EventKind` inputs used by the trip-details matrix and telemetry.
 *
 * - `domainProfileFromEditFormValues` — same `TourDomainProfile` as `resolveTourFormProfileForTourFormValues`
 *   when a theme catalog exists; otherwise `domainProfileFromTourTypeFallback(tourType)`.
 * - `legacyEventKindFromEditFormValues` — single entry point for `resolveEventKindFromTourContext`
 *   on Edit (compatibility / no-catalog paths).
 * - `dualClassificationForEditForm` — exposes legacy vs `eventKindForDomainProfile(domainProfile)`
 *   and `agrees` for observability without changing default resolver behavior elsewhere.
 */

export type EditFormClassificationInput = {
  /** Workspace theme catalog used to look up `formProfile` for the picked theme. */
  themeCatalog: readonly ThemeRowForProfile[] | undefined;
  /** Watched form value for the commercial tour type. */
  tourType: TourType | undefined;
  /**
   * Trimmed primary theme id from `tripDetails.overview.tourThemeIds[0]`. Empty / undefined
   * means "no theme picked yet" (falls through to the tourType fallback).
   */
  mainTourThemeId: string | undefined;
  /** Watched legacy `tripDetails.overview.tripStyles[]` (drives legacy `EventKind` resolver). */
  tripStyles: readonly string[] | undefined;
};

/**
 * Canonical {@link TourDomainProfile} resolver for the Edit form. Wraps
 * {@link resolveTourFormProfileForTourFormValues} so callers see the canonical
 * alias name and never have to deal with `undefined` (we fall through to the
 * commercial-tourType default).
 */
export function domainProfileFromEditFormValues(
  input: EditFormClassificationInput,
): TourDomainProfile {
  if (input.themeCatalog && input.themeCatalog.length > 0) {
    return resolveTourFormProfileForTourFormValues({
      themeCatalog: [...input.themeCatalog],
      tourType: input.tourType,
      mainTourThemeId: input.mainTourThemeId,
    });
  }
  return domainProfileFromTourTypeFallback(input.tourType ?? null);
}

/**
 * Legacy `EventKind` resolver for Edit. Delegates to `resolveEventKindFromTourContext`.
 *
 * Phase P7 (promptq.md): the Edit resolver no longer reads this directly — it always
 * routes through `domainProfileFromEditFormValues(...) → eventKindForDomainProfile(...)`.
 * The only remaining caller is `dualClassificationForEditForm` below, which uses it to
 * compute the legacy-vs-projected `agrees` boolean for drift telemetry, and the
 * `LEGACY_EDIT_RESOLVER_ENABLED` kill switch path (single-cycle escape hatch).
 *
 * Removal target: Phase P8, alongside narrowing the `@repo/types` `EventKind` public
 * surface. Do **not** add new call sites.
 *
 * @deprecated Retained only for drift telemetry + emergency kill-switch fallback.
 */
export function legacyEventKindFromEditFormValues(
  input: Pick<EditFormClassificationInput, "tourType" | "tripStyles">,
): EventKind {
  return resolveEventKindFromTourContext({
    tourType: input.tourType,
    tripStyles: input.tripStyles ?? undefined,
  });
}

export type EditFormDualClassification = {
  /** Canonical profile for strip alignment and wizard parity flags. */
  readonly domainProfile: TourDomainProfile;
  /** Legacy matrix key from `tripDetailsFieldConfig` until that layer is profile-native. */
  readonly legacyEventKind: EventKind;
  /** `eventKindForDomainProfile(domainProfile)` — compatibility projection for convergence checks. */
  readonly projectedEventKind: EventKind;
  /**
   * `true` when legacy resolver and profile projection agree (workspace `formProfile` consistent
   * with commercial `tourType` / `tripStyles`). When `false`, telemetry records drift; default
   * Edit behavior still follows the feature-flagged resolver path.
   */
  readonly agrees: boolean;
};

/**
 * Combined classification snapshot for the Edit form. Returns both axes plus the
 * unified projection so the form can drive its existing legacy code paths while
 * carrying the canonical {@link TourDomainProfile} forward unchanged.
 */
export function dualClassificationForEditForm(
  input: EditFormClassificationInput,
): EditFormDualClassification {
  const domainProfile = domainProfileFromEditFormValues(input);
  const legacyEventKind = legacyEventKindFromEditFormValues(input);
  const projectedEventKind = eventKindForDomainProfile(domainProfile);
  return {
    domainProfile,
    legacyEventKind,
    projectedEventKind,
    agrees: legacyEventKind === projectedEventKind,
  };
}

import type { DenaliCreateWizardStepId } from "@/features/tours/wizard/denaliStepConfig";
import { getDenaliWizardSteps } from "@/features/tours/wizard/denaliStepConfig";
import { applyDenaliInvariantState } from "@/features/tours/wizard/denali/validation/denaliInvariantEngine";
import { normalizeDenaliWizardForm } from "@/features/tours/wizard/denali/validation/denaliRuleAccess";
import type { DenaliCreateTourWizardForm } from "@/features/tours/wizard/schemas/denaliCore.schema";

import type { DenaliWizardDraftSnapshot } from "./denali-adapter";

/** Phase 3 rail layout (basic → photos → program → logistics → pricing → review). */
export const DENALI_WIZARD_RAIL_LAYOUT_VERSION = 2;

/** Pre–phase 3 create wizard rail (photos last). */
export const LEGACY_DENALI_WIZARD_RAIL = [
  "denali_basic",
  "denali_program",
  "denali_logistics",
  "denali_pricing",
  "denali_photos",
  "review",
] as const satisfies readonly DenaliCreateWizardStepId[];

export function migrateDenaliDraftStepIndex(
  storedIndex: number,
  railLayoutVersion: number | undefined,
): number {
  const steps = getDenaliWizardSteps();
  const safeIndex = Number.isFinite(storedIndex) ? Math.floor(storedIndex) : 0;

  if ((railLayoutVersion ?? 1) >= DENALI_WIZARD_RAIL_LAYOUT_VERSION) {
    return Math.max(0, Math.min(safeIndex, steps.length - 1));
  }

  const legacyIndex = Math.max(0, Math.min(safeIndex, LEGACY_DENALI_WIZARD_RAIL.length - 1));
  const stepId = LEGACY_DENALI_WIZARD_RAIL[legacyIndex]!;
  const mapped = steps.indexOf(stepId);
  return mapped >= 0 ? mapped : 0;
}

/**
 * Normalizes draft form data and remaps legacy rail indices after step relocation.
 * Purges ghost fields via {@link applyDenaliInvariantState}.
 */
export function sanitizeDenaliWizardDraftSnapshot(
  snapshot: DenaliWizardDraftSnapshot,
): DenaliWizardDraftSnapshot {
  const form = applyDenaliInvariantState(
    normalizeDenaliWizardForm(snapshot.form),
  ) as DenaliCreateTourWizardForm;

  return {
    form,
    currentStepIndex: migrateDenaliDraftStepIndex(
      snapshot.currentStepIndex,
      snapshot.railLayoutVersion,
    ),
    railLayoutVersion: DENALI_WIZARD_RAIL_LAYOUT_VERSION,
  };
}

