/** Engine statuses passed into {@link applyCanonicalMvpToForm} for quiet hydration during conflict. */
export type DenaliCanonicalFormEngineStatus = Extract<
  DraftStatus,
  "IDLE" | "CONFLICT_RESOLVING" | "SYNCING" | "ERROR"
