/** Legacy keys removed from form state (derived at validation/submit instead). */
const STRIP_BASIC = new Set(["isMultiDay"]);
const STRIP_PROGRAM = new Set([
  "difficultyType",
  "mainTourThemeId",
  "secondaryTourThemeIds",
  "altitudeGainApprox",
  "itineraryOutline",
]);
const STRIP_PRICING = new Set(["includesTransportInPrice"]);
const STRIP_PARTICIPANT = new Set([
  "maximumAge",
  "experienceLevel",
  "requiredGearIds",
  "optionalGearIds",
  "medicalNotes",
  "technicalSkillNotes",
]);
const STRIP_POLICIES = new Set([
  "cancellationPolicy",
  "refundPolicy",
  "attendanceRules",
  "safetyPolicy",
  "weatherPolicy",
]);

function omitKeys<T extends Record<string, unknown>>(obj: T, keys: Set<string>): T {
  const out = { ...obj };
  for (const key of keys) {
    delete out[key];
  }
  return out;
}

/** Drops derived/deprecated fields from draft patches and legacy presets before merge. */
export function sanitizeDenaliFormPatch(
  patch: Partial<DenaliCreateTourWizardForm>,
): Partial<DenaliCreateTourWizardForm> {
  const out: Partial<DenaliCreateTourWizardForm> = { ...patch };
  if (patch.basicInfo != null) {
    out.basicInfo = omitKeys(
      patch.basicInfo as Record<string, unknown>,
      STRIP_BASIC,
    ) as DenaliCreateTourWizardForm["basicInfo"];
  }
  if (patch.programNature != null) {
    out.programNature = omitKeys(
      patch.programNature as Record<string, unknown>,
      STRIP_PROGRAM,
    ) as DenaliCreateTourWizardForm["programNature"];
  }
  if (patch.pricingPayment != null) {
    out.pricingPayment = omitKeys(
      patch.pricingPayment as Record<string, unknown>,
      STRIP_PRICING,
    ) as DenaliCreateTourWizardForm["pricingPayment"];
  }
  if (patch.participantRequirements != null) {
    out.participantRequirements = omitKeys(
      patch.participantRequirements as Record<string, unknown>,
      STRIP_PARTICIPANT,
    ) as DenaliCreateTourWizardForm["participantRequirements"];
  }
  if (patch.policies != null) {
    out.policies = omitKeys(
      patch.policies as Record<string, unknown>,
      STRIP_POLICIES,
    ) as DenaliCreateTourWizardForm["policies"];
  }
  return out;
}

import type { DenaliGearItem } from "@/features/tours/wizard/schemas/denaliGearItemSchema";

export function upsertGearItem(
  items: DenaliGearItem[] | undefined,
  id: string,
  patch: Partial<DenaliGearItem>,
): DenaliGearItem[] {
  const list = [...(items ?? [])];
  const idx = list.findIndex((row) => row.id === id);
  if (idx >= 0) {
    list[idx] = { ...list[idx]!, ...patch, id };
    return list;
  }
  return [...list, { id, isRequired: patch.isRequired ?? false }];
}

export function removeGearItem(items: DenaliGearItem[] | undefined, id: string): DenaliGearItem[] {
  return (items ?? []).filter((row) => row.id !== id);
}

export function normalizeGearItems(items: DenaliGearItem[] | undefined): DenaliGearItem[] | undefined {
  return items != null && items.length > 0 ? items : undefined;
}

/** Maps settings/preset `gearRequiredIds` + `gearOptionalIds` into wizard `gearItems`. */
export function gearCatalogIdsToGearItems(
  gearRequiredIds: string[] | undefined,
  gearOptionalIds: string[] | undefined,
): DenaliGearItem[] | undefined {
  const required = new Set((gearRequiredIds ?? []).map((id) => id.trim()).filter(Boolean));
  const optional = new Set((gearOptionalIds ?? []).map((id) => id.trim()).filter(Boolean));
  if (required.size === 0 && optional.size === 0) {
    return undefined;
  }
  const items: DenaliGearItem[] = [];
  for (const id of required) {
    items.push({ id, isRequired: true });
  }
  for (const id of optional) {
    if (!required.has(id)) {
      items.push({ id, isRequired: false });
    }
  }
  return normalizeGearItems(items);
}

export function splitGearByRequired(items: DenaliGearItem[] | undefined): {
  required: DenaliGearItem[];
  optional: DenaliGearItem[];
} {
  const required: DenaliGearItem[] = [];
  const optional: DenaliGearItem[] = [];
  const seen = new Set<string>();
  for (const row of items ?? []) {
    const id = row.id?.trim();
    if (!id || seen.has(id)) continue;
    seen.add(id);
    if (row.isRequired === true) {
      required.push(row);
    } else {
      optional.push(row);
    }
  }
  return { required, optional };
}

