export type DenaliWizardDiagnosticReport = {
  generatedAt: string;
  source: string;
  validationIssues: Array<{ path: string; message: string; code: string }>;
  gearMismatch: {
    gearItems: Array<{ id: string; isRequired: boolean }>;
    activeEquipmentCount: number;
    unmatchedGearIds: string[];
    gearIdMatchDetails: Array<{ id: string; matched: boolean }>;
  };
  requiredFieldsAfterHydration: {
    peakHeight: number | undefined;
    elevationGain: number | undefined;
    themeIds: string[];
    peakHeightPresent: boolean;
    elevationGainPresent: boolean;
    themeIdsPresent: boolean;
  };
  canonicalSnapshot: {
    title: string;
    tourType: string | undefined;
    category: string;
    duration: string;
  };
};

function activeEquipmentIds(rows: readonly SettingsEquipmentDto[] | undefined): string[] {
  return (rows ?? [])
    .filter((row) => row.isActive)
    .map((row) => row.id.trim())
    .filter(Boolean);
}

/**
 * Builds a structured diagnostic report for Denali wizard state (submit gate + gear catalog + clone fields).
 */
export function buildDenaliWizardDiagnosticReport(input: {
  form: DenaliCreateTourWizardForm;
  activeEquipment?: readonly SettingsEquipmentDto[];
  source?: string;
}): DenaliWizardDiagnosticReport {
  const { form, activeEquipment, source = "denali-wizard" } = input;
  const canonical = denaliFormToCanonical(form);
  const issues = getDenaliWizardSubmitIssues(form);
  const gearItems = (canonical.participants.gearItems ?? []).map((row) => ({
    id: row.id.trim(),
    isRequired: row.isRequired === true,
  }));
  const activeSet = new Set(activeEquipmentIds(activeEquipment));
  const gearIdMatchDetails = gearItems.map((row) => ({
    id: row.id,
    matched: activeSet.has(row.id),
  }));

  return {
    generatedAt: new Date().toISOString(),
    source,
    validationIssues: issues.map((issue) => ({
      path: issue.path.join("."),
      message: issue.message,
      code: String(issue.code),
    })),
    gearMismatch: {
      gearItems,
      activeEquipmentCount: activeSet.size,
      unmatchedGearIds: gearIdMatchDetails.filter((row) => !row.matched).map((row) => row.id),
      gearIdMatchDetails,
    },
    requiredFieldsAfterHydration: {
      peakHeight: canonical.overview?.peakHeight,
      elevationGain: canonical.metrics?.elevationGain,
      themeIds: [...(canonical.program.themeIds ?? [])],
      peakHeightPresent:
        canonical.overview?.peakHeight != null &&
        Number.isFinite(canonical.overview.peakHeight),
      elevationGainPresent:
        canonical.metrics?.elevationGain != null &&
        Number.isFinite(canonical.metrics.elevationGain),
      themeIdsPresent: (canonical.program.themeIds ?? []).length > 0,
    },
    canonicalSnapshot: {
      title: canonical.title,
      tourType: form.basicInfo.tourType,
      category: String(canonical.category),
      duration: String(canonical.duration),
    },
  };
}

/** Logs {@link buildDenaliWizardDiagnosticReport} as one JSON object (browser console or Node). */
export function logDenaliWizardDiagnosticReport(
  input: Parameters<typeof buildDenaliWizardDiagnosticReport>[0],
): DenaliWizardDiagnosticReport {
  const report = buildDenaliWizardDiagnosticReport(input);
  const _json = JSON.stringify(report, null, 2);
  if (
    typeof console !== "undefined" &&
    process.env.NEXT_PUBLIC_DENALI_WIZARD_DIAGNOSTIC === "1"
  ) {
  }
  return report;
}

import type { TourDetailDto } from "@/lib/services/tours.service";

import type { DenaliFileAsset } from "@/features/tours/wizard/schemas/denaliFileAssetSchema";

/** Wire / registry async asset reference (may omit preview `url`). */
export type AsyncAsset = {
  id?: string;
  assetId?: string;
  url?: string;
  filename?: string;
  size?: number;
  mimeType?: string;
  uploadedAt?: string;
  uploadStatus?: DenaliFileAsset["uploadStatus"];
};

function trimNonEmpty(value: unknown): string | undefined {
  if (typeof value !== "string") {
    return undefined;
  }
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : undefined;
}

function parseAsyncAssetRow(raw: unknown): AsyncAsset | null {
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
    return null;
  }
  const row = raw as Record<string, unknown>;
  const id = trimNonEmpty(row.id);
  const assetId = trimNonEmpty(row.assetId);
  const url = trimNonEmpty(row.url);
  if (!id && !assetId && !url) {
    return null;
  }
  return {
    ...(id ? { id } : {}),
    ...(assetId ? { assetId } : {}),
    ...(url ? { url } : {}),
    ...(trimNonEmpty(row.filename) ? { filename: trimNonEmpty(row.filename) } : {}),
    ...(typeof row.size === "number" && Number.isFinite(row.size) ? { size: row.size } : {}),
    ...(trimNonEmpty(row.mimeType) ? { mimeType: trimNonEmpty(row.mimeType) } : {}),
    ...(trimNonEmpty(row.uploadedAt) ? { uploadedAt: trimNonEmpty(row.uploadedAt) } : {}),
    ...(trimNonEmpty(row.uploadStatus) &&
    (row.uploadStatus === "pending" ||
      row.uploadStatus === "uploading" ||
      row.uploadStatus === "uploaded" ||
      row.uploadStatus === "failed")
      ? { uploadStatus: row.uploadStatus as DenaliFileAsset["uploadStatus"] }
      : {}),
  };
}

/** Reads gallery async assets from API `details.tripDetails.photos` before RHF mapping. */
export function readTourGalleryAsyncAssets(
  tour: Pick<TourDetailDto, "details"> | { details?: { tripDetails?: unknown } | null },
): AsyncAsset[] {
  const tripDetails = tour.details?.tripDetails;
  if (tripDetails == null || typeof tripDetails !== "object" || Array.isArray(tripDetails)) {
    return [];
  }
  const rawPhotos = (tripDetails as Record<string, unknown>).photos;
  if (!Array.isArray(rawPhotos)) {
    return [];
  }
  return rawPhotos
    .map((row) => parseAsyncAssetRow(row))
    .filter((row): row is AsyncAsset => row != null);
}

function assetLookupKeys(row: AsyncAsset): string[] {
  const keys = new Set<string>();
  const id = trimNonEmpty(row.id);
  const assetId = trimNonEmpty(row.assetId);
  if (id) {
    keys.add(id);
  }
  if (assetId) {
    keys.add(assetId);
  }
  return [...keys];
}

function toHydratedAsset(row: AsyncAsset, url: string): DenaliFileAsset | null {
  const id = trimNonEmpty(row.id) ?? trimNonEmpty(row.assetId);
  if (!id) {
    return null;
  }
  const assetId = trimNonEmpty(row.assetId) ?? id;
  return {
    id,
    url,
    filename: trimNonEmpty(row.filename) ?? "photo.jpg",
    size: typeof row.size === "number" && Number.isFinite(row.size) ? row.size : 0,
    mimeType: trimNonEmpty(row.mimeType) ?? "image/jpeg",
    uploadedAt: trimNonEmpty(row.uploadedAt) ?? new Date(0).toISOString(),
    assetId,
    uploadStatus: row.uploadStatus ?? "uploaded",
  };
}

function buildResolvedAssetIndex(photos: readonly AsyncAsset[]): Map<string, DenaliFileAsset> {
  const index = new Map<string, DenaliFileAsset>();
  for (const row of photos) {
    const url = trimNonEmpty(row.url);
    if (!url) {
      continue;
    }
    const hydrated = toHydratedAsset(row, url);
    if (!hydrated) {
      continue;
    }
    for (const key of assetLookupKeys(row)) {
      index.set(key, hydrated);
    }
    index.set(hydrated.id, hydrated);
    if (hydrated.assetId) {
      index.set(hydrated.assetId, hydrated);
    }
  }
  return index;
}

/**
 * Resolves registry async assets (possibly installId references) into full file rows for RHF/UI.
 * Rows with a preview `url` pass through; assetId-only rows inherit metadata from indexed matches.
 */
export function hydrateAsyncAssets(photos: readonly AsyncAsset[]): DenaliFileAsset[] {
  if (photos.length === 0) {
    return [];
  }

  const index = buildResolvedAssetIndex(photos);
  const seenIds = new Set<string>();
  const hydrated: DenaliFileAsset[] = [];

  for (const row of photos) {
    const directUrl = trimNonEmpty(row.url);
    let resolved =
      directUrl != null ? toHydratedAsset(row, directUrl) : null;

    if (!resolved) {
      for (const key of assetLookupKeys(row)) {
        const match = index.get(key);
        if (match) {
          resolved = {
            ...match,
            id: trimNonEmpty(row.id) ?? match.id,
            assetId: trimNonEmpty(row.assetId) ?? match.assetId ?? match.id,
            ...(trimNonEmpty(row.filename) ? { filename: trimNonEmpty(row.filename)! } : {}),
            ...(typeof row.size === "number" && Number.isFinite(row.size) ? { size: row.size } : {}),
            ...(trimNonEmpty(row.mimeType) ? { mimeType: trimNonEmpty(row.mimeType)! } : {}),
            ...(trimNonEmpty(row.uploadedAt) ? { uploadedAt: trimNonEmpty(row.uploadedAt)! } : {}),
            ...(row.uploadStatus ? { uploadStatus: row.uploadStatus } : {}),
          };
          break;
        }
      }
    }

    if (!resolved || seenIds.has(resolved.id)) {
      continue;
    }
    seenIds.add(resolved.id);
    hydrated.push(resolved);
  }

  return hydrated;
}

/**
 * Shared codegen logic for registry → rule model / path map.
 * Used by `scripts/generate-denali-wizard-config.ts` and `scripts/registry-integrity-audit.ts`.
 */

import { DENALI_FIELD_DEFINITIONS, type DenaliFieldDefinition } from "./denaliFieldRegistryData";
import { DENALI_MATRIX_CELL_TAGS, type DenaliMatrixCell } from "./denaliRuleMatrixRecipes";
import {
  DENALI_RULE_MODEL_CATEGORIES,
  DENALI_RULE_MODEL_DURATIONS,
  type DenaliRuleFieldDefinition,
  type DenaliRuleSet,
} from "../rules/denaliRuleModel.types";

export function fieldInCell(def: DenaliFieldDefinition, cell: DenaliMatrixCell): boolean {
  const cellTags = DENALI_MATRIX_CELL_TAGS[cell];
  if (cellTags == null) return false;
  if (def.inRuleModel === false) return false;
  if (def.tags.length === 0) return false;
  return def.tags.some((tag) => cellTags.includes(tag));
}

export function resolveRuleRow(
  def: DenaliFieldDefinition,
  cell: DenaliMatrixCell,
): Pick<DenaliRuleFieldDefinition, "required" | "hidden"> {
  const override = def.cellOverrides?.[cell];
  if (override) return override;

  const cellTags = DENALI_MATRIX_CELL_TAGS[cell] ?? [];

  if (def.canonicalPath === "endDateTime") {
    if (cellTags.includes("end_datetime_required")) {
      return { required: true, hidden: false };
    }
    if (cellTags.includes("end_datetime_hidden")) {
      return { required: false, hidden: true };
    }
  }

  if (
    def.canonicalPath === "program.itinerary" &&
    cellTags.includes("itinerary_visible")
  ) {
    return { required: true, hidden: false };
  }

  return def.ruleDefaults;
}

export function buildDenaliRuleSetFromRegistry(): DenaliRuleSet {
  const set = {} as DenaliRuleSet;

  for (const category of DENALI_RULE_MODEL_CATEGORIES) {
    set[category] = {} as DenaliRuleSet[typeof category];
    for (const duration of DENALI_RULE_MODEL_DURATIONS) {
      const cell = `${category}:${duration}` as DenaliMatrixCell;
      const cellTags = DENALI_MATRIX_CELL_TAGS[cell];
      if (cellTags == null) {
        set[category][duration] = null;
        continue;
      }

      const fields: DenaliRuleFieldDefinition[] = [];
      for (const def of DENALI_FIELD_DEFINITIONS) {
        if (!fieldInCell(def, cell)) continue;
        const { required, hidden } = resolveRuleRow(def, cell);
        fields.push({
          path: def.canonicalPath,
          required,
          hidden,
          step: def.stepId,
        });
      }

      fields.sort((a, b) => a.path.localeCompare(b.path));
      set[category][duration] = {
        category,
        duration,
        fields,
      };
    }
  }

  return set;
}

export function buildDenaliCanonicalMapFromRegistry(): Record<string, string> {
  const map: Record<string, string> = {};
  for (const def of DENALI_FIELD_DEFINITIONS) {
    map[def.canonicalPath] = def.rhfPath;
  }
  return map;
}

/** Canonical paths validated at submit when `contextualRequired` is set on the registry row. */
export function buildDenaliConditionallyRequiredCanonicalPathsFromRegistry(): readonly string[] {
  return DENALI_FIELD_DEFINITIONS.filter((def) => def.contextualRequired != null)
    .map((def) => def.canonicalPath)
    .sort();
}

function serializeRuleSet(ruleSet: DenaliRuleSet): string {
  const snapshot: Record<string, unknown> = {};
  for (const category of DENALI_RULE_MODEL_CATEGORIES) {
    for (const duration of DENALI_RULE_MODEL_DURATIONS) {
      const model = ruleSet[category][duration];
      const key = `${category}:${duration}`;
      snapshot[key] =
        model == null
          ? null
          : model.fields.map((f) => ({
              path: f.path,
              required: f.required,
              hidden: f.hidden,
              step: f.step,
            }));
    }
  }
  return JSON.stringify(snapshot);
}

function serializeCanonicalMap(map: Record<string, string>): string {
  const sorted = Object.keys(map)
    .sort()
    .map((key) => [key, map[key]!] as const);
  return JSON.stringify(Object.fromEntries(sorted));
}

/** Returns human-readable sync errors (empty = in sync). */
export function collectGeneratedArtifactSyncErrors(
  committedRuleSet: DenaliRuleSet,
  committedCanonicalMap: Record<string, string>,
): string[] {
  const errors: string[] = [];
  const expectedRuleSet = buildDenaliRuleSetFromRegistry();
  const expectedMap = buildDenaliCanonicalMapFromRegistry();

  if (serializeRuleSet(committedRuleSet) !== serializeRuleSet(expectedRuleSet)) {
    errors.push(
      "denaliRuleSet.generated.ts is out of sync with the registry. Run: pnpm --filter web generate:denali-wizard",
    );
  }

  if (serializeCanonicalMap(committedCanonicalMap) !== serializeCanonicalMap(expectedMap)) {
    errors.push(
      "denaliCanonicalPathMap.generated.ts is out of sync with the registry. Run: pnpm --filter web generate:denali-wizard",
    );
  }

  return errors;
}

import type { FieldPath } from "react-hook-form";

import type { DenaliCreateTourWizardForm } from "@/features/tours/wizard/schemas/denaliTourCreateFormModel";

import { DENALI_CANONICAL_TO_FORM_PATH_MAP } from "./generated/denaliCanonicalPathMap.generated";

/**
 * When no exact/longest-prefix match exists under a canonical root, map issues to the
 * same default fields as the legacy {@link canonicalZodPathToFormFieldPath} switch (values
 * are keys in {@link DENALI_CANONICAL_TO_FORM_PATH_MAP}, not hardcoded form paths).
 */
const CANONICAL_ROOT_DEFAULT_KEY: Readonly<Partial<Record<string, string>>> = {
  program: "program.themeIds",
  transport: "transport.mode",
  pricing: "pricing.paymentMode",
  participants: "participants.minimumAge",
  policies: "policies.policiesText",
};

function longestCanonicalMapKey(segments: readonly (string | number)[]): string | undefined {
  const parts = segments.map(String);
  for (let len = parts.length; len >= 1; len -= 1) {
    const key = parts.slice(0, len).join(".");
    if (Object.prototype.hasOwnProperty.call(DENALI_CANONICAL_TO_FORM_PATH_MAP, key)) {
      return key;
    }
  }
  return undefined;
}

function formPathWithSuffix(
  formBase: string,
  segments: readonly (string | number)[],
  matchedCanonicalKey: string,
): FieldPath<DenaliCreateTourWizardForm> {
  const prefixLen = matchedCanonicalKey.split(".").length;
  const suffixParts = segments.slice(prefixLen).map(String);
  if (suffixParts.length === 0) {
    return formBase as FieldPath<DenaliCreateTourWizardForm>;
  }
  return `${formBase}.${suffixParts.join(".")}` as FieldPath<DenaliCreateTourWizardForm>;
}

/**
 * Maps {@link denaliCanonicalTourSchema} issue paths → RHF paths using the registry-generated map.
 */
export function canonicalZodPathToFormFieldPath(
  path: readonly (string | number)[],
): FieldPath<DenaliCreateTourWizardForm> {
  if (path.length === 0) {
    const title = DENALI_CANONICAL_TO_FORM_PATH_MAP.title;
    return (title ?? "basicInfo.title") as FieldPath<DenaliCreateTourWizardForm>;
  }

  const exactKey = longestCanonicalMapKey(path);
  if (exactKey != null) {
    const formBase = DENALI_CANONICAL_TO_FORM_PATH_MAP[exactKey]!;
    return formPathWithSuffix(formBase, path, exactKey);
  }

  const head = String(path[0]);
  const rest = path.slice(1);
  const tail = rest.map(String).join(".");

  if (head === "program") {
    if (tail.startsWith("itinerary")) {
      const itineraryBase = DENALI_CANONICAL_TO_FORM_PATH_MAP["program.itinerary"];
      if (itineraryBase) {
        return formPathWithSuffix(itineraryBase, path, "program.itinerary");
      }
      return `programNature.${tail}` as FieldPath<DenaliCreateTourWizardForm>;
    }
    const defaultForm = DENALI_CANONICAL_TO_FORM_PATH_MAP["program.themeIds"];
    if (defaultForm) {
      return defaultForm as FieldPath<DenaliCreateTourWizardForm>;
    }
  }

  const defaultCanonical = CANONICAL_ROOT_DEFAULT_KEY[head];
  if (defaultCanonical != null) {
    const defaultForm = DENALI_CANONICAL_TO_FORM_PATH_MAP[defaultCanonical];
    if (defaultForm) {
      return defaultForm as FieldPath<DenaliCreateTourWizardForm>;
    }
  }

  return (tail.length > 0 ? `${head}.${tail}` : head) as FieldPath<DenaliCreateTourWizardForm>;
}

