        if (!old) {
          return old;
        }
        return old.filter((row) => row.id !== id);
      });
      return { previous };
    },
    onError: (_err, _id, ctx) => {
      if (ctx?.previous) {
        queryClient.setQueryData(settingsGuideLanguagesKeys.list(tenantId ?? ""), ctx.previous);
      }
    },
    onSettled: async () => {
