export type ResolvedField = DenaliFieldSpec & {
  canonical: string;
  formPath: string;
  step: string;
  registryKnown: boolean;
};

// ---------------------------------------------------------------------------
// CLI
// ---------------------------------------------------------------------------
type CliOptions = {
  fieldsPath?: string;
  dryRun: boolean;
  prune: boolean;
  skipTests: boolean;
  logFile: string;
};

function parseArgs(argv: string[]): CliOptions {
  const opts: CliOptions = {
    dryRun: false,
    prune: false,
    skipTests: false,
    logFile: LOG_FILE_DEFAULT,
  };
  for (const arg of argv) {
    if (arg.startsWith("--fields=")) opts.fieldsPath = arg.slice("--fields=".length);
    else if (arg === "--dry-run") opts.dryRun = true;
    else if (arg === "--prune") opts.prune = true;
    else if (arg === "--skip-tests") opts.skipTests = true;
    else if (arg.startsWith("--log=")) opts.logFile = arg.slice("--log=".length);
  }
  return opts;
}

// ---------------------------------------------------------------------------
// Logging
// ---------------------------------------------------------------------------
let logStream: string[] = [];

function log(tag: string, message: string): void {
  const line = `[${tag}] ${message}`;
  logStream.push(line);
}

function flushLog(logFile: string): void {
  const header = `\n--- Denali field update ${new Date().toString()} ---\n`;
  fs.appendFileSync(path.join(REPO_ROOT, logFile), header + logStream.join("\n") + "\n");
}

function fail(tag: string, message: string): never {
  log(tag, `ERROR: ${message}`);
  throw new Error(message);
}

// ---------------------------------------------------------------------------
// Manifest parsing (JSON + minimal YAML for `fields:` lists)
// ---------------------------------------------------------------------------
function parseSimpleYamlFields(text: string): Manifest {
  const fields: DenaliFieldSpec[] = [];
  const lines = text.split(/\r?\n/);
  let current: Partial<DenaliFieldSpec> | null = null;
  let inFields = false;

  const set = (key: string, raw: string) => {
    if (!current) return;
    const v = raw.trim().replace(/^["']|["']$/g, "");
    switch (key) {
      case "name":
        current.name = v;
        break;
      case "tab":
        current.tab = v;
        break;
      case "type":
        current.type = v as DenaliFieldType;
        break;
      case "required":
        current.required = v === "true";
        break;
      case "read-only":
      case "readOnly":
        current.readOnly = v === "true";
        break;
      case "conditional":
        current.conditional = v === "null" ? null : v;
        break;
      case "default":
        current.default = v === "null" ? null : v;
        break;
      default:
        break;
    }
  };

  for (const line of lines) {
    if (/^fields:\s*$/.test(line)) {
      inFields = true;
      continue;
    }
    if (!inFields) continue;
    const item = line.match(/^\s*-\s*$/);
    const kv = line.match(/^\s+([a-zA-Z-]+):\s*(.*)$/);
    if (line.match(/^\s*-\s*name:/)) {
      if (current?.name) fields.push(current as DenaliFieldSpec);
      const name = line.replace(/^\s*-\s*name:\s*/, "").trim();
      current = { name, tab: "", type: "string", required: false, readOnly: false };
      continue;
    }
    if (item && current?.name) {
      fields.push(current as DenaliFieldSpec);
      current = { name: "", tab: "", type: "string", required: false, readOnly: false };
      continue;
    }
    if (kv && current) set(kv[1], kv[2]);
  }
  if (current?.name) fields.push(current as DenaliFieldSpec);
  return { fields };
}

function loadManifest(fieldsPath?: string): Manifest {
  const raw = fieldsPath
    ? fs.readFileSync(path.resolve(REPO_ROOT, fieldsPath), "utf-8")
    : DEFAULT_MANIFEST_YAML;
  const trimmed = raw.trim();
  if (fieldsPath?.endsWith(".json") || trimmed.startsWith("{")) {
    return JSON.parse(trimmed) as Manifest;
  }
  return parseSimpleYamlFields(raw);
}

// ---------------------------------------------------------------------------
// Field resolution
// ---------------------------------------------------------------------------
function resolveField(spec: DenaliFieldSpec): ResolvedField {
  if (!TAB_CONFIG[spec.tab]) {
    fail("Manifest", `Unknown tab "${spec.tab}" on field "${spec.name}". Use: ${Object.keys(TAB_CONFIG).join(", ")}`);
  }
  const tab = TAB_CONFIG[spec.tab];
  const reg = FIELD_REGISTRY[spec.name];
  const canonical = reg?.canonical ?? spec.name;
  const formLeaf = reg?.formLeaf ?? spec.name;
  const formPath = `${tab.formSection}.${formLeaf}`;
  return {
    ...spec,
    canonical,
    formPath,
    step: tab.step,
    registryKnown: reg != null,
  };
}

function readExistingCanonicalPaths(filePath: string): string[] {
  const content = fs.readFileSync(path.join(REPO_ROOT, filePath), "utf-8");
  const m = content.match(/DENALI_WIZARD_CANONICAL_FIELD_PATHS = new Set\(\[([\s\S]*?)\]\)/);
  if (!m) return [];
  return [...m[1].matchAll(/"([^"]+)"/g)].map((x) => x[1]);
}

function buildCanonicalPathSet(fields: ResolvedField[], prune: boolean, existing: string[]): string[] {
  const fromManifest = fields.map((f) => f.canonical);
  const merged = prune ? fromManifest : [...new Set([...existing, ...fromManifest])];
  return merged.sort();
}

function _buildFormPathMapEntries(fields: ResolvedField[]): string[] {
  const lines: string[] = [];
  const seen = new Set<string>();
  for (const f of fields) {
    if (seen.has(f.canonical)) continue;
    seen.add(f.canonical);
    lines.push(`  "${f.canonical}": "${f.formPath}",`);
  }
  return lines;
}

// ---------------------------------------------------------------------------
// Idempotent file patching
// ---------------------------------------------------------------------------
function syncCanonicalFieldPathsSet(
  paths: string[],
  dryRun: boolean,
): { changed: boolean; content: string } {
  const filePath = path.join(REPO_ROOT, PATHS.ruleRequired);
  const content = fs.readFileSync(filePath, "utf-8");
  const body = paths.map((p) => `  "${p}",`).join("\n");
  const nextBlock = `export const DENALI_WIZARD_CANONICAL_FIELD_PATHS = new Set([\n${body}\n]);`;
  const pattern = /export const DENALI_WIZARD_CANONICAL_FIELD_PATHS = new Set\(\[[\s\S]*?\]\);/;
  if (!pattern.test(content)) fail("Patch", "DENALI_WIZARD_CANONICAL_FIELD_PATHS block missing");
  const next = content.replace(pattern, nextBlock);
  const changed = next !== content;
  if (changed && !dryRun) fs.writeFileSync(filePath, next, "utf-8");
  return { changed, content: next };
}

function syncCanonicalToFormMap(
  fields: ResolvedField[],
  dryRun: boolean,
): { changed: boolean } {
  const filePath = path.join(REPO_ROOT, PATHS.ruleRequired);
  const content = fs.readFileSync(filePath, "utf-8");
  const existing = content.match(
    /const CANONICAL_TO_FORM_PATH_MAP: Record<string, string> = \{([\s\S]*?)\};/,
  );
  if (!existing) fail("Patch", "CANONICAL_TO_FORM_PATH_MAP block missing");

  const mapBody = existing[1];
  const mapEntries = new Map<string, string>();
  for (const m of mapBody.matchAll(/"([^"]+)":\s*"([^"]+)",/g)) {
    mapEntries.set(m[1], m[2]);
  }
  for (const f of fields) {
    mapEntries.set(f.canonical, f.formPath);
  }
  const sortedKeys = [...mapEntries.keys()].sort();
  const newBody = sortedKeys.map((k) => `  "${k}": "${mapEntries.get(k)}",`).join("\n");
  const nextMap = `const CANONICAL_TO_FORM_PATH_MAP: Record<string, string> = {\n${newBody}\n};`;
  const next = content.replace(
    /const CANONICAL_TO_FORM_PATH_MAP: Record<string, string> = \{[\s\S]*?\};/,
    nextMap,
  );
  const changed = next !== content;
  if (changed && !dryRun) fs.writeFileSync(filePath, next, "utf-8");
  return { changed };
}

// ---------------------------------------------------------------------------
// Layer verification (read-only checks; logs warnings for manual follow-up)
// ---------------------------------------------------------------------------
function readRepoFile(rel: string): string {
  return fs.readFileSync(path.join(REPO_ROOT, rel), "utf-8");
}

function verifyCanonicalModel(fields: ResolvedField[]): boolean {
  log("Canonical", "Verifying DenaliCanonicalTourModel + denaliCanonicalFromForm...");
  const model = readRepoFile(PATHS.canonicalModel);
  const fromForm = readRepoFile(PATHS.canonicalFromForm);
  let ok = true;
  for (const f of fields) {
    const key = FIELD_REGISTRY[f.name]?.canonicalInterfaceKey ?? f.canonical.split(".").pop() ?? f.name;
    const topLevel = !f.canonical.includes(".");
    if (topLevel) {
      if (!new RegExp(`\\b${key}\\b`).test(model)) {
        log("Canonical", `Warning: top-level "${key}" not found in interface (field "${f.name}")`);
        ok = false;
      }
    } else {
      const [section, leaf] = f.canonical.split(".");
      if (!model.includes(`${section}:`) || !model.includes(`${leaf}`)) {
        log("Canonical", `Warning: nested "${f.canonical}" may be missing in interface`);
        ok = false;
      }
    }
    if (FIELD_REGISTRY[f.name]?.adapterNeedle && !fromForm.includes(f.canonical.split(".").pop()!)) {
      // soft check on fromForm mapping
    }
  }
  return ok;
}

function verifyRules(fields: ResolvedField[]): boolean {
  log("Rules", "Verifying denaliRuleModel path definitions...");
  const model = readRepoFile(PATHS.ruleModel);
  let ok = true;
  for (const f of fields) {
    const needle = `path: "${f.canonical}"`;
    if (!model.includes(needle)) {
      log(
        "Rules",
        `Warning: ${needle} not in denaliRuleModel — add a DenaliRuleFieldDefinition constant and include it in denaliRuleSet spreads (field "${f.name}").`,
      );
      ok = false;
    }
  }
  return ok;
}

function verifyNormalization(fields: ResolvedField[]): boolean {
  log("Normalization", "Verifying ghost-field registry drives normalizeDenaliWizardForm...");
  const access = readRepoFile(PATHS.ruleAccess);
  let ok = true;
  if (!access.includes("export function normalizeDenaliWizardForm")) {
    fail("Normalization", "normalizeDenaliWizardForm missing");
  }
  if (!access.includes("DENALI_WIZARD_CANONICAL_FIELD_PATHS")) {
    log("Normalization", "Warning: rule access should iterate DENALI_WIZARD_CANONICAL_FIELD_PATHS");
    ok = false;
  }
  for (const f of fields) {
    if (!access.includes(f.canonical) && !access.includes(f.formPath)) {
      log("Normalization", `Info: "${f.name}" relies on generic path clearing via canonical set`);
    }
  }
  return ok;
}

function verifyUiSync(fields: ResolvedField[]): boolean {
  log("UI Sync", "Verifying applyCanonicalMvpToForm / denaliCanonicalToForm...");
  const adapter = readRepoFile(PATHS.formAdapter);
  let ok = true;
  if (!adapter.includes("export function applyCanonicalMvpToForm")) {
    fail("UI Sync", "applyCanonicalMvpToForm missing");
  }
  for (const f of fields) {
    const needle = FIELD_REGISTRY[f.name]?.adapterNeedle ?? f.formPath.split(".")[1];
    if (needle && !adapter.includes(needle)) {
      log("UI Sync", `Warning: adapter may not sync "${f.name}" (look for "${needle}")`);
      ok = false;
    }
  }
  return ok;
}

function verifyProjection(fields: ResolvedField[]): boolean {
  log("Projection", "Verifying buildDenaliCreateTourPayloadProjection...");
  const proj = readRepoFile(PATHS.projection);
  let ok = true;
  if (!proj.includes("export function buildDenaliCreateTourPayloadProjection")) {
    fail("Projection", "projection function missing");
  }
  if (!proj.includes("const tripDetails = {")) {
    log("Projection", "Warning: tripDetails builder block not found");
    ok = false;
  }
  for (const f of fields) {
    const needle = FIELD_REGISTRY[f.name]?.projectionNeedle;
    if (needle && !proj.includes(needle)) {
      log("Projection", `Warning: projection may not map "${f.name}" (expected ref "${needle}")`);
      ok = false;
    }
  }
  return ok;
}

// ---------------------------------------------------------------------------
// Run existing gates + tests
// ---------------------------------------------------------------------------
function runNodeGate(scriptName: string): void {
  const script = path.join(REPO_ROOT, TEMPLATES_DIR, scriptName);
  log("Gate", `Running ${scriptName}...`);
  const r = spawnSync("node", [script], { cwd: REPO_ROOT, encoding: "utf-8" });
  if (r.stdout) process.stdout.write(r.stdout);
  if (r.stderr) process.stderr.write(r.stderr);
  if (r.status !== 0) fail("Gate", `${scriptName} exited with code ${r.status}`);
}

function runUnitTests(): void {
  log("Test", "Running apps/web unit tests (pnpm test)...");
  const r = spawnSync("pnpm", ["test"], { cwd: path.join(REPO_ROOT, "apps/web"), encoding: "utf-8", shell: true });
  if (r.stdout) process.stdout.write(r.stdout);
  if (r.stderr) process.stderr.write(r.stderr);
  if (r.status !== 0) fail("Test", `Unit tests failed (exit ${r.status})`);
}

function runE2ETests(): void {
  log("Test", "Running Denali negative invariant E2E...");
  const spec = "test/e2e/denali-negative-invariants.e2e-spec.ts";
  const r = spawnSync("node", ["--import", "tsx", "--test", spec], {
    cwd: path.join(REPO_ROOT, "apps/api"),
    encoding: "utf-8",
  });
  if (r.stdout) process.stdout.write(r.stdout);
  if (r.stderr) process.stderr.write(r.stderr);
  if (r.status !== 0) fail("Test", `E2E tests failed (exit ${r.status})`);
}

// ---------------------------------------------------------------------------
// Main pipeline
// ---------------------------------------------------------------------------
function main(): void {
  const opts = parseArgs(process.argv.slice(2));
  logStream = [];

  log("Pipeline", `Denali field update started (dryRun=${opts.dryRun}, prune=${opts.prune})`);

  const manifest = loadManifest(opts.fieldsPath);
  if (!manifest.fields?.length) fail("Manifest", "No fields in manifest");

  const resolved = manifest.fields.map(resolveField);
  log("Manifest", `Loaded ${resolved.length} field(s): ${resolved.map((f) => f.name).join(", ")}`);

  for (const f of resolved) {
    if (!f.registryKnown) {
      log(
        "Manifest",
        `Warning: "${f.name}" is not in FIELD_REGISTRY — canonical path defaults to "${f.canonical}"; extend run-denali-field-update.ts registry.`,
      );
    }
    if (f.conditional) {
      log(
        "Manifest",
        `Info: conditional visibility for "${f.name}" (${f.conditional}) must be implemented in denaliRuleModel / denaliUIAdapter manually.`,
      );
    }
    if (f.readOnly) {
      log("Manifest", `Info: read-only "${f.name}" — enforce in UI step components, not auto-patched.`);
    }
  }

  // Phase 1 — Registry sync (idempotent)
  log("Apply", "Phase 1: Sync DENALI_WIZARD_CANONICAL_FIELD_PATHS + form path map");
  const existing = readExistingCanonicalPaths(PATHS.ruleRequired);
  const pathSet = buildCanonicalPathSet(resolved, opts.prune, existing);
  const { changed: pathsChanged } = syncCanonicalFieldPathsSet(pathSet, opts.dryRun);
  const { changed: mapChanged } = syncCanonicalToFormMap(resolved, opts.dryRun);
  const changeVerb = opts.dryRun ? "would update" : "updated";
  log("Apply", `Registry paths: ${pathSet.length} (${pathsChanged ? changeVerb : "unchanged"})`);
  log("Apply", `Form path map: ${mapChanged ? changeVerb : "unchanged"}`);

  // Phase 2 — Layer verification
  log("Verify", "Phase 2: Cross-layer presence checks");
  const layerOk =
    verifyCanonicalModel(resolved) &&
    verifyRules(resolved) &&
    verifyNormalization(resolved) &&
    verifyUiSync(resolved) &&
    verifyProjection(resolved);

  if (!layerOk) {
    log(
      "Verify",
      "Some layers need manual edits (see warnings). Registry sync still applied where safe.",
    );
  }

  // Phase 3 — CI gates
  log("CI", "Phase 3: Static gates");
  const gates = [
    "check-canonical-gate.ts",
    "check-rules-gate.ts",
    "check-normalization-gate.ts",
    "check-projection-gate.ts",
    "check-ui-sync-gate.ts",
  ];
  for (const g of gates) runNodeGate(g);

  // Phase 4 — Tests
  if (!opts.skipTests && !opts.dryRun) {
    log("CI", "Phase 4: Unit + E2E tests");
    runUnitTests();
    runE2ETests();
  } else if (opts.dryRun) {
    log("CI", "Phase 4: Skipped (dry-run)");
  } else {
    log("CI", "Phase 4: Skipped (--skip-tests)");
  }

  flushLog(opts.logFile);
  log("Pipeline", "COMPLETED successfully");
  process.exit(0);
}

try {
  main();
} catch (err) {
  const msg = err instanceof Error ? err.message : String(err);
  log("Pipeline", `FAILED: ${msg}`);
  try {
    flushLog(process.argv.find((a) => a.startsWith("--log="))?.slice(6) ?? LOG_FILE_DEFAULT);
  } catch {
    /* ignore */
  }
  process.exit(1);
}

const PERSIAN_ZERO = 0x06f0;
const ARABIC_INDIC_ZERO = 0x0660;

export function asciiDigitsFromNationalIdRaw(raw: string): string {
  let out = "";
  for (const ch of raw) {
    const cp = ch.codePointAt(0);
    if (cp === undefined) {
      continue;
    }
    if (cp >= PERSIAN_ZERO && cp <= PERSIAN_ZERO + 9) {
      out += String.fromCodePoint(0x30 + (cp - PERSIAN_ZERO));
      continue;
    }
    if (cp >= ARABIC_INDIC_ZERO && cp <= ARABIC_INDIC_ZERO + 9) {
      out += String.fromCodePoint(0x30 + (cp - ARABIC_INDIC_ZERO));
      continue;
    }
    if (ch >= "0" && ch <= "9") {
      out += ch;
    }
  }
  return out;
}

export function isValidIranNationalIdChecksum(digits10: string): boolean {
  if (!/^\d{10}$/.test(digits10)) {
    return false;
  }
  if (/^(\d)\1{9}$/.test(digits10)) {
    return false;
  }
  const d = digits10.split("").map((c) => Number(c));
  let sum = 0;
  for (let i = 0; i < 9; i += 1) {
    sum += d[i]! * (10 - i);
  }
  const remainder = sum % 11;
  const check = remainder < 2 ? remainder : 11 - remainder;
  return check === d[9];
}

import {
  CURRENT_DRAFT_SCHEMA_VERSION,
  DRAFT_SNAPSHOT_DEFAULT_SCHEMA_VERSION,
  type DraftSnapshot,
} from "./draft-snapshot.contract";

export type DraftMigrationResult<TData = Record<string, unknown>> = {
  readonly snapshot: DraftSnapshot<TData>;
  readonly upgraded: boolean;
};

export type DraftMigrator<TData = Record<string, unknown>> = (
  _data: unknown,
  _fromSchemaVersion: number,
) => { data: TData; toSchemaVersion: number };

export const DENALI_CREATE_DRAFT_KEY = "denali-create";

/** Pre–phase 3 Denali create wizard rail (photos last). */
const LEGACY_DENALI_WIZARD_RAIL = [
  "denali_basic",
  "denali_program",
  "denali_logistics",
  "denali_pricing",
  "denali_photos",
  "review",
] as const;

/** Phase 3 Denali create wizard rail (content + gallery on step 2). */
const CURRENT_DENALI_WIZARD_RAIL = [
  "denali_basic",
  "denali_photos",
  "denali_program",
  "denali_logistics",
  "denali_pricing",
  "review",
] as const;

export const DENALI_WIZARD_RAIL_LAYOUT_VERSION = 2;

function migrateDenaliDraftStepIndex(
  storedIndex: number,
  railLayoutVersion: number | undefined,
): number {
  const safeIndex = Number.isFinite(storedIndex) ? Math.floor(storedIndex) : 0;

  if ((railLayoutVersion ?? 1) >= DENALI_WIZARD_RAIL_LAYOUT_VERSION) {
    return Math.max(0, Math.min(safeIndex, CURRENT_DENALI_WIZARD_RAIL.length - 1));
  }

  const legacyIndex = Math.max(0, Math.min(safeIndex, LEGACY_DENALI_WIZARD_RAIL.length - 1));
  const stepId = LEGACY_DENALI_WIZARD_RAIL[legacyIndex]!;
  const mapped = CURRENT_DENALI_WIZARD_RAIL.indexOf(stepId);
  return mapped >= 0 ? mapped : 0;
}

/** Minimal safe Denali wizard draft blob when legacy rows are incomplete. */
export const migrateDenaliCreateDraftData: DraftMigrator = (
  data: unknown,
  _fromSchemaVersion: number,
) => {
  const record =
    data != null && typeof data === "object" && !Array.isArray(data)
      ? (data as Record<string, unknown>)
      : {};

  const form =
    record.form != null && typeof record.form === "object" && !Array.isArray(record.form)
      ? (record.form as Record<string, unknown>)
      : {};

  const stepRaw = record.currentStepIndex;
  const railLayoutRaw = record.railLayoutVersion;
  const railLayoutVersion =
    typeof railLayoutRaw === "number" && Number.isFinite(railLayoutRaw)
      ? Math.floor(railLayoutRaw)
      : 1;
  const currentStepIndex = migrateDenaliDraftStepIndex(
    typeof stepRaw === "number" && Number.isFinite(stepRaw) ? stepRaw : 0,
    railLayoutVersion,
  );

  return {
    data: {
      form,
      currentStepIndex,
      railLayoutVersion: DENALI_WIZARD_RAIL_LAYOUT_VERSION,
    } as Record<string, unknown>,
    toSchemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
  };
};

export class DraftMigratorRegistry {
  private readonly migrators = new Map<string, DraftMigrator>();

  register(draftKey: string, migrator: DraftMigrator): void {
    this.migrators.set(draftKey.trim(), migrator);
  }

  migrateEnvelope<TData = Record<string, unknown>>(
    draftKey: string,
    envelope: DraftSnapshot,
  ): DraftMigrationResult<TData> {
    const key = draftKey.trim();
    const fromVersion = Number(envelope.schemaVersion) || DRAFT_SNAPSHOT_DEFAULT_SCHEMA_VERSION;
    const migrator = this.migrators.get(key);

    if (!migrator && fromVersion >= CURRENT_DRAFT_SCHEMA_VERSION) {
      return { snapshot: envelope as DraftSnapshot<TData>, upgraded: false };
    }

    const { data, toSchemaVersion } = migrator
      ? migrator(envelope.data, fromVersion)
      : { data: envelope.data, toSchemaVersion: fromVersion };

    const upgraded =
      toSchemaVersion !== fromVersion ||
      JSON.stringify(data) !== JSON.stringify(envelope.data);

    if (!upgraded) {
      return { snapshot: envelope as DraftSnapshot<TData>, upgraded: false };
    }

    return {
      snapshot: {
        data: data as TData,
        version: envelope.version,
        schemaVersion: toSchemaVersion,
        lastModified: envelope.lastModified,
      },
      upgraded: true,
    };
  }
}

export function createDefaultDraftMigratorRegistry(): DraftMigratorRegistry {
  const registry = new DraftMigratorRegistry();
  registry.register(DENALI_CREATE_DRAFT_KEY, migrateDenaliCreateDraftData);
  return registry;
}

import type { TourFormProfile } from "@repo/types";

export interface WorkspaceInvariantViolation {
  code: string;
  message: string;
}

/**
 * Strategy/Contract for a Tour Workspace (e.g. Denali, Arctic).
 * Aligned with map.md §B1 and §Phase 3.
 */
export interface TourWorkspaceDefinition {
  readonly profile: TourFormProfile;
  readonly version: number;

  /** Roots expected in DTOs and Presets (e.g. basicInfo, programNature for Denali). */
  readonly roots: readonly string[];

  /** UI Rail hint for the web wizard. */
  readonly ui: {
    readonly wizardMode: "classic" | "denali";
  };

  /** Invariant checks (logic rules beyond simple types). */
  readonly validation: {
    readonly checkCapacity: (_capacity: number) => WorkspaceInvariantViolation | null;
    readonly checkTripDetails: (_tripDetails: any, _transportModes?: readonly string[] | null) => WorkspaceInvariantViolation | null;
  };

  /** Lifecycle contract (map.md §B4 and §Phase 4). */
  readonly lifecycle: {
    readonly initialStatus: string;
    readonly publishStatus: string;
    readonly allowedTransitions: readonly { from: string; to: string }[];
  };

  /** Workspace actions (map.md §Phase 1). */
  readonly actions?: {
    /** Apply workspace-specific invariants (normalization). */
    readonly applyInvariants?: <T>(_form: T) => T;
  };
}

import type { TourWorkspaceDefinition } from "../workspace-definition";

/**
 * Workspace Lifecycle Transition Guard (map.md §Phase 4).
 * 
 * Central authority for state transitions. Ensures that no tour
 * bypasses workspace-specific business rules during status changes.
 */

export interface LifecycleTransitionRequest {
  from: string;
  to: string;
}

/**
 * Asserts that a lifecycle transition is allowed by the workspace contract.
 * Throws an error if the transition is illegal.
 */
export function assertWorkspaceLifecycleTransition(
  workspace: TourWorkspaceDefinition,
  transition: LifecycleTransitionRequest,
): void {
  const allowed = workspace.lifecycle.allowedTransitions.some(
    (t) => t.from === transition.from && t.to === transition.to
  );

  if (!allowed) {
    throw new Error(
      `WORKSPACE_LIFECYCLE_ILLEGAL_TRANSITION: ${workspace.profile} cannot transition from ${transition.from} to ${transition.to}`
    );
  }
}

/**
 * Validates if a tour is ready for a specific status (e.g. OPEN).
 * (Placeholder for more complex readiness checks).
 */
export function assertWorkspaceStatusReadiness(
  workspace: TourWorkspaceDefinition,
  targetStatus: string,
  tourData: any
): void {
  if (targetStatus === workspace.lifecycle.publishStatus) {
    // Run full invariant check before allowing "OPEN"
    const violation = workspace.validation.checkTripDetails(
      tourData.tripDetails,
      tourData.transportModes
    );
    if (violation) {
      throw new Error(`WORKSPACE_LIFECYCLE_READINESS_FAILED: ${violation.message}`);
    }
  }
}

/**
 * Dot-path read/write helpers for plain object form values (UI-agnostic).
 */

export function readFormPath(values: unknown, path: string): unknown {
  if (values == null || path === "") return undefined;
  const segments = path.split(".").filter(Boolean);
  let current: unknown = values;
  for (const segment of segments) {
    if (current == null || typeof current !== "object") {
      return undefined;
    }
    current = (current as Record<string, unknown>)[segment];
  }
  return current;
}

export function writeFormPath<T extends Record<string, unknown>>(
  values: T,
  path: string,
  value: unknown,
): T {
  const segments = path.split(".").filter(Boolean);
  if (segments.length === 0) return values;

  const root = { ...values } as Record<string, unknown>;
  let current = root;

  for (let i = 0; i < segments.length - 1; i += 1) {
    const key = segments[i]!;
    const next = current[key];
    const branch =
      next != null && typeof next === "object" && !Array.isArray(next)
        ? { ...(next as Record<string, unknown>) }
        : {};
    current[key] = branch;
    current = branch;
  }

  current[segments[segments.length - 1]!] = value;
  return root as T;
}

/** Stable JSON key for dependency snapshots (lookup cache invalidation). */
export function snapshotFormValues(
  values: unknown,
  dependencyPaths: readonly string[],
): string {
  const bag: Record<string, unknown> = {};
  for (const path of dependencyPaths) {
    bag[path] = readFormPath(values, path);
  }
  return JSON.stringify(bag);
}

import {
  AbilityBuilder,
  createMongoAbility,
  type ForcedSubject,
  type MongoAbility
} from "@casl/ability";
import type { WorkspaceCapability } from "./capabilities";
import { resolveEffectiveCapabilities } from "./capability-registry";
import { tryParseWorkspaceRole, WorkspaceRole } from "./workspace-roles";

/**
 * CASL actions used across Nest + Next. `manage` implies create, read, update, delete
 * on the subject (CASL built-in). `publish` is used for tour lifecycle OPEN transitions.
 */
export type WorkspaceAbilityAction =
  | "manage"
  | "create"
  | "read"
  | "update"
  | "delete"
  | "publish";

/**
 * Coarse subjects for workspace-scoped product areas. Instance-level rules (e.g. "own"
 * registration) can be layered later via subject objects.
 */
/** Typed `subject("MedicalProfile", { ownerUserId })` for `ability.can` checks. */
export type MedicalProfileSubjectRef = { ownerUserId: string } & ForcedSubject<"MedicalProfile">;
/** Typed `subject("EmergencyContact", { ownerUserId })` for `ability.can` checks. */
export type EmergencyContactSubjectRef = { ownerUserId: string } & ForcedSubject<"EmergencyContact">;

export type WorkspaceAbilitySubject =
  | "all"
  | "Workspace"
  | "WorkspaceOwnership"
  | "UserMembership"
  /** User-directory sensitive tabs (documents / receipts); owner & admin only via `manage all`. */
  | "UserDirectoryDocuments"
  /** Admin-only workspace notes about a member; owner & admin via `manage all`. */
  | "UserDirectoryInternalNotes"
  /** ICE contacts for a workspace member; leader reads broadly; member limited to own rows via field rules. */
  | "EmergencyContact"
  /** Encrypted medical/sensitive payload; decrypt only in service — never log plaintext. */
  | "MedicalProfile"
  | MedicalProfileSubjectRef
  | EmergencyContactSubjectRef
  | "Tour"
  /** Core tour fields (capacity, lifecycle, cost_context) — maps to `tour.update.core`. */
  | "TourCore"
  /** `tripDetails` JSON patch surface — maps to `tour.update.tripDetails`. */
  | "TourTripDetails"
  /** Urban/cinema pricing & logistics caps inside tripDetails (Phase 8.1). */
  | "TourTripDetailsSensitive"
  | "Registration"
  | "Payment"
  | "Reconciliation"
  /** Manual debt + receipt upload (tenant `finance` module). */
  | "FinanceManualPayment"
  /** Member receipt upload for a pending manual payment. */
  | "FinanceReceipt"
  /** Owner/admin receipt review queue. */
  | "FinanceReceiptReview"
  | "Settings"
  /** Workspace tour create wizard template (fieldRulesOverlay + canonicalData). */
  | "TourWizardTemplate"
  | "Audit"
  | "MarketingSegment";

export type AppAbility = MongoAbility<[WorkspaceAbilityAction, WorkspaceAbilitySubject]>;

/** Membership lifecycle on `user_tenants.membership_status` (uppercase in DB). */
export type UserAbilityMembershipStatus = "INVITED" | "ACTIVE" | "SUSPENDED" | (string & {});

export type UserAbilityContext = {
  id: string;
  role: string;
  status?: UserAbilityMembershipStatus | null;
  /** Optional marketing / CRM labels (not workspace system roles). */
  labels?: readonly string[] | null;
  /** Optional explicit capability grants (membership row / session hydration). */
  capabilities?: readonly string[] | null;
  /** Active tenant `enabled_modules` (Phase 6). */
  tenantModules?: readonly string[] | null;
  /** `user_tenants.membership_metadata` blob. */
  membershipMetadata?: unknown;
};

function isMembershipActive(status: UserAbilityMembershipStatus | null | undefined): boolean {
  if (status === undefined || status === null || status === "") {
    return true;
  }
  return String(status).toUpperCase() === "ACTIVE";
}

function applyInactiveGate(can: AbilityBuilder<AppAbility>["can"], cannot: AbilityBuilder<AppAbility>["cannot"]): void {
  cannot("manage", "all");
  cannot("create", "Workspace");
  cannot("update", "Workspace");
  cannot("delete", "Workspace");
  can("read", "Workspace");
}

function applyMarketingLabels(can: AbilityBuilder<AppAbility>["can"], labels: readonly string[] | null | undefined): void {
  if (labels && labels.length > 0) {
    can("read", "MarketingSegment");
  }
}

function applyMarketingCapabilityGrantsFromSet(
  can: AbilityBuilder<AppAbility>["can"],
  caps: ReadonlySet<WorkspaceCapability>,
): void {
  if (caps.has("marketing.segment.read")) {
    can("read", "MarketingSegment");
  }
}

function grantOwnerActive(can: AbilityBuilder<AppAbility>["can"]): void {
  can("manage", "all");
  can("update", "TourTripDetailsSensitive");
}

function grantAdminActive(can: AbilityBuilder<AppAbility>["can"], cannot: AbilityBuilder<AppAbility>["cannot"]): void {
  can("manage", "all");
  can("update", "TourTripDetailsSensitive");
  cannot("update", "WorkspaceOwnership");
}

function applyTourCapabilityGrantsFromSet(
  can: AbilityBuilder<AppAbility>["can"],
  caps: ReadonlySet<WorkspaceCapability>,
): void {
  if (caps.has("tour.read")) {
    can("read", "Tour");
  }
  if (caps.has("tour.create")) {
    can("create", "Tour");
  }
  if (caps.has("tour.update")) {
    can("update", "Tour");
  }
  if (caps.has("tour.publish")) {
    can("publish", "Tour");
  }
  if (caps.has("tour.update.core")) {
    can("update", "TourCore");
  }
  if (caps.has("tour.update.tripDetails")) {
    can("update", "TourTripDetails");
  }
  if (caps.has("module.form_builder")) {
    can("update", "TourTripDetailsSensitive");
  }
}

function applySettingsCapabilityGrantsFromSet(
  can: AbilityBuilder<AppAbility>["can"],
  cannot: AbilityBuilder<AppAbility>["cannot"],
  caps: ReadonlySet<WorkspaceCapability>,
): void {
  if (caps.has("settings.read")) {
    can("read", "Settings");
  }
  if (caps.has("settings.themes.manage")) {
    can("manage", "Settings");
  } else {
    cannot("manage", "Settings");
  }
  if (caps.has("settings.templates.manage")) {
    can("read", "TourWizardTemplate");
    can("update", "TourWizardTemplate");
    can("publish", "TourWizardTemplate");
  } else {
    cannot("update", "TourWizardTemplate");
    cannot("publish", "TourWizardTemplate");
  }
}

/** Tenant module capabilities merged via {@link resolveEffectiveCapabilities}. */
function applyModuleCapabilityGrantsFromSet(
  can: AbilityBuilder<AppAbility>["can"],
  caps: ReadonlySet<WorkspaceCapability>,
  workspaceRole: WorkspaceRole | null,
): void {
  if (caps.has("module.finance")) {
    can("read", "Reconciliation");
    can("read", "FinanceManualPayment");
    can("create", "FinanceReceipt");
    if (
      workspaceRole === WorkspaceRole.Owner ||
      workspaceRole === WorkspaceRole.Admin
    ) {
      can("create", "FinanceManualPayment");
      can("read", "FinanceReceiptReview");
      can("update", "FinanceReceiptReview");
    }
  }
  if (caps.has("module.form_builder")) {
    can("update", "TourTripDetails");
  }
}

function grantLeaderActive(
  can: AbilityBuilder<AppAbility>["can"],
  cannot: AbilityBuilder<AppAbility>["cannot"],
  caps: ReadonlySet<WorkspaceCapability>,
): void {
  can("read", "Workspace");
  can("read", "UserMembership");
  applyTourCapabilityGrantsFromSet(can, caps);
  applySettingsCapabilityGrantsFromSet(can, cannot, caps);
  applyModuleCapabilityGrantsFromSet(can, caps, WorkspaceRole.Leader);
  can("read", "Registration");
  can("create", "Registration");
  can("update", "Registration");
  can("read", "Payment");
  /** Payment intents for participant/leader flows (server still scopes rows). */
  can("create", "Payment");
  can("read", "Audit");
  can("read", "Reconciliation");
  can("read", "MedicalProfile");
  can("read", "EmergencyContact");
  can("update", "EmergencyContact");
  can("update", "TourTripDetailsSensitive");
  cannot("delete", "Workspace");
  cannot("update", "Workspace");
  cannot("update", "WorkspaceOwnership");
}

function grantMemberActive(
  can: AbilityBuilder<AppAbility>["can"],
  cannot: AbilityBuilder<AppAbility>["cannot"],
  userContext: UserAbilityContext,
  caps: ReadonlySet<WorkspaceCapability>,
): void {
  can("read", "Workspace");
  applyTourCapabilityGrantsFromSet(can, caps);
  applySettingsCapabilityGrantsFromSet(can, cannot, caps);
  applyModuleCapabilityGrantsFromSet(can, caps, WorkspaceRole.Member);
  can("create", "Registration");
  can("read", "Registration");
  can("update", "Registration");
  can("read", "Payment");
  can("create", "Payment");
  can("read", "MedicalProfile", { ownerUserId: userContext.id });
  can("update", "MedicalProfile", { ownerUserId: userContext.id });
  can("read", "EmergencyContact", { ownerUserId: userContext.id });
  can("update", "EmergencyContact", { ownerUserId: userContext.id });
  cannot("update", "Workspace");
  cannot("update", "WorkspaceOwnership");
  cannot("manage", "UserMembership");
}

function grantViewerActive(
  can: AbilityBuilder<AppAbility>["can"],
  cannot: AbilityBuilder<AppAbility>["cannot"],
  caps: ReadonlySet<WorkspaceCapability>,
): void {
  can("read", "Workspace");
  applyTourCapabilityGrantsFromSet(can, caps);
  applySettingsCapabilityGrantsFromSet(can, cannot, caps);
  applyModuleCapabilityGrantsFromSet(can, caps, WorkspaceRole.Viewer);
  can("read", "Registration");
  can("read", "UserMembership");
  can("read", "Payment");
  can("read", "Settings");
  cannot("create", "Tour");
  cannot("update", "Tour");
  cannot("update", "TourCore");
  cannot("update", "TourTripDetails");
  cannot("publish", "Tour");
  cannot("delete", "Tour");
}

/**
 * Builds a CASL ability for a single workspace membership context.
 * Intended for shared use in Nest (`@casl/nestjs`) and Next (`@casl/react`).
 *
 * Non-ACTIVE memberships get a minimal read-only workspace slice; product-specific
 * invite flows can tighten further when wired to controllers.
 */
export function defineAbilityFor(userContext: UserAbilityContext): AppAbility {
  const { can, cannot, build } = new AbilityBuilder<AppAbility>(createMongoAbility);

  if (!isMembershipActive(userContext.status)) {
    applyInactiveGate(can, cannot);
    applyMarketingLabels(can, userContext.labels);
    return build();
  }

  const effectiveCaps = new Set(
    resolveEffectiveCapabilities({
      role: userContext.role,
      labels: userContext.labels,
      capabilities: userContext.capabilities,
      tenantModules: userContext.tenantModules,
      membershipMetadata: userContext.membershipMetadata,
    }),
  );
  applyMarketingLabels(can, userContext.labels);
  applyMarketingCapabilityGrantsFromSet(can, effectiveCaps);

  const workspaceRole = tryParseWorkspaceRole(userContext.role);
  if (workspaceRole === WorkspaceRole.Owner || workspaceRole === WorkspaceRole.Admin) {
    applyModuleCapabilityGrantsFromSet(can, effectiveCaps, workspaceRole);
  }
  switch (workspaceRole) {
    case WorkspaceRole.Owner:
      grantOwnerActive(can);
      break;
    case WorkspaceRole.Admin:
      grantAdminActive(can, cannot);
      break;
    case WorkspaceRole.Leader:
      grantLeaderActive(can, cannot, effectiveCaps);
      break;
    case WorkspaceRole.Member:
      grantMemberActive(can, cannot, userContext, effectiveCaps);
      break;
    case WorkspaceRole.Viewer:
      grantViewerActive(can, cannot, effectiveCaps);
      break;
    default:
      cannot("manage", "all");
      can("read", "Workspace");
      break;
  }

  return build();
}

