#!/usr/bin/env node
/**
 * Tenant isolation architecture guardrails for CI.
 *
 * Checks:
 * 1) dataSource.query / this.dataSource.query in runtime API code (allowlisted paths only).
 * 1b) Allowlisted dataSource.query: first-arg SQL must be catalog/health-shaped or contain tenant binding.
 * 2) @Body() DTO classes that declare tenant_id or tenantId (client-controlled tenant) unless response-shaped / allowlisted.
 * 3) Active runtime SECURITY DEFINER usage must be documented in docs/security/security-definer.md.
 * 4) Explicit HTTP body tenant reads (req.request.body.tenantId / tenant_id, including bracket access).
 * 5) EntityManager raw SQL: manager.query( — first static SQL arg must include tenant_id/workspace_id or GUC set_config.
 * 6) createQueryBuilder: chain window must reference tenant/workspace scoping, or `// tenant-isolation:qb-exempt` above.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");
const ALLOWLIST_PATH = path.join(__dirname, "tenant-isolation-guardrails.allowlist.json");

function readAllowlist() {
  const raw = fs.readFileSync(ALLOWLIST_PATH, "utf8");
  return JSON.parse(raw);
}

function walk(dir, acc = []) {
  if (!fs.existsSync(dir)) return acc;
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === "node_modules" || ent.name === "dist") continue;
      walk(p, acc);
    } else if (ent.isFile() && ent.name.endsWith(".ts")) {
      acc.push(p);
    }
  }
  return acc;
}

function normPosix(p) {
  return p.split(path.sep).join("/");
}

function isIgnoredPath(rel, ignored) {
  return ignored.some((prefix) => rel.startsWith(prefix.replace(/^\.\//, "")));
}

function lineNumberAt(src, idx) {
  return src.slice(0, idx).split("\n").length;
}

/** --- Check 1: dataSource.query --- */
function checkDataSourceQuery(allow) {
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const files = walk(apiRoot).map((p) => ({
    abs: p,
    rel: normPosix(path.relative(REPO_ROOT, p))
  }));

  const ignored = allow.ignoredPathsForDataSourceQuery.map((x) =>
    normPosix(x.replace(/^\.\//, ""))
  );
  const allowedFiles = new Set(allow.dataSourceQueryPaths.map(normPosix));

  const violations = [];
  const re = /\b(?:this\.)?dataSource\.query\s*\(/g;

  for (const { abs, rel } of files) {
    if (isIgnoredPath(rel, ignored)) continue;
    const text = fs.readFileSync(abs, "utf8");
    if (!re.test(text)) continue;
    re.lastIndex = 0;
    if (!allowedFiles.has(rel)) {
      violations.push(
        `[DATASOURCE_QUERY] ${rel}: uses dataSource.query — use repositories / QueryBuilder under RLS tenant binding, or add path to scripts/tenant-isolation-guardrails.allowlist.json with justification.`
      );
    }
  }
  return violations;
}

/** --- Check 1b: allowlisted dataSource.query SQL body --- */
function skipWs(s, i) {
  let j = i;
  while (j < s.length && /\s/.test(s[j])) j++;
  return j;
}

function extractFirstStringOrTemplateArg(src, openParenIdx) {
  let i = skipWs(src, openParenIdx + 1);
  if (i >= src.length) return null;
  const c = src[i];
  if (c === "`") {
    let j = i + 1;
    while (j < src.length && src[j] !== "`") j += 1;
    if (j >= src.length) return null;
    return src.slice(i + 1, j);
  }
  if (c === '"' || c === "'") {
    const quote = c;
    let j = i + 1;
    let esc = false;
    while (j < src.length) {
      if (esc) {
        esc = false;
        j += 1;
        continue;
      }
      if (src[j] === "\\") {
        esc = true;
        j += 1;
        continue;
      }
      if (src[j] === quote) {
        return src.slice(i + 1, j);
      }
      j += 1;
    }
    return null;
  }
  return null;
}

function sqlLooksSafeCatalogOrHealth(sql) {
  if (!sql || typeof sql !== "string") return false;
  const s = sql.replace(/\/\*[\s\S]*?\*\//g, " ").trim();
  if (/^\s*select\s+1\b/i.test(s)) return true;
  if (/\binformation_schema\b/i.test(s)) return true;
  if (/\bpg_catalog\b/i.test(s)) return true;
  if (/^\s*(begin|commit|rollback)\b/i.test(s)) return true;
  return false;
}

function sqlShowsTenantBinding(sql) {
  if (!sql || typeof sql !== "string") return false;
  return (
    /\btenant_id\b/i.test(sql) ||
    /\bworkspace_id\b/i.test(sql) ||
    /set_config\s*\(\s*['"]app\.tenant_id['"]/i.test(sql) ||
    /current_setting\s*\(\s*['"]app\.tenant_id['"]/i.test(sql)
  );
}

function checkAllowlistedDataSourceQuerySql(allow) {
  const violations = [];
  const allowedRel = (allow.dataSourceQueryPaths || []).map(normPosix);
  const re = /\b(?:this\.)?dataSource\.query\s*\(/g;

  for (const rel of allowedRel) {
    const abs = path.join(REPO_ROOT, rel);
    if (!fs.existsSync(abs)) continue;
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = re.exec(text)) !== null) {
      const openParen = m.index + m[0].length - 1;
      const sql = extractFirstStringOrTemplateArg(text, openParen);
      if (sql === null) {
        violations.push(
          `[RAW_SQL_TENANT] ${rel}:${lineNumberAt(text, m.index)}: dataSource.query uses non-literal SQL — add a static template/string so tenant binding can be verified, or refactor.`
        );
        continue;
      }
      if (sqlLooksSafeCatalogOrHealth(sql) || sqlShowsTenantBinding(sql)) {
        continue;
      }
      violations.push(
        `[RAW_SQL_TENANT] ${rel}:${lineNumberAt(text, m.index)}: allowlisted dataSource.query SQL lacks tenant_id/workspace_id/app.tenant_id binding and is not a catalog/health probe.`
      );
    }
  }
  return violations;
}

/** --- Check 2: Body + tenant scope fields --- */
function stripTsComments(src) {
  return src
    .replace(/\/\*[\s\S]*?\*\//g, " ")
    .replace(/\/\/[^\n]*/g, " ");
}

function iterExportClassBodies(ts) {
  const out = [];
  const re = /^export\s+class\s+(\w+)(?:\s+extends\s+[\w.<>,\s]+)?\s*\{/gm;
  let m;
  while ((m = re.exec(ts)) !== null) {
    const name = m[1];
    const openBraceIdx = m.index + m[0].length - 1;
    let depth = 0;
    for (let i = openBraceIdx; i < ts.length; i++) {
      const ch = ts[i];
      if (ch === "{") depth++;
      else if (ch === "}") {
        depth--;
        if (depth === 0) {
          out.push({ name, body: ts.slice(openBraceIdx + 1, i) });
          break;
        }
      }
    }
  }
  return out;
}

function classBodyDeclaresClientTenantScope(body) {
  const c = stripTsComments(body);
  if (/\btenant_id\b/.test(c)) return true;
  if (/\btenantId\s*[!?]?\s*:/.test(c)) return true;
  return false;
}

function extractExportedClassesWithClientTenantScope(dtoText) {
  return iterExportClassBodies(dtoText).filter((x) => classBodyDeclaresClientTenantScope(x.body));
}

function isResponseLikeClassName(name, suffixes) {
  return suffixes.some((s) => name.endsWith(s));
}

function checkBodyTenantDto(allow) {
  const modulesRoot = path.join(REPO_ROOT, "apps/api/src/modules");
  const dtoFiles = walk(modulesRoot).filter((p) => p.includes(`${path.sep}dto${path.sep}`));

  const allowBody = new Set(allow.bodyDtoAllowlist);
  const suffixes = allow.dtoResponseNameSuffixes;

  const riskyDtoNames = new Map();
  for (const abs of dtoFiles) {
    const text = fs.readFileSync(abs, "utf8");
    for (const { name } of extractExportedClassesWithClientTenantScope(text)) {
      if (allowBody.has(name)) continue;
      if (isResponseLikeClassName(name, suffixes)) continue;
      riskyDtoNames.set(name, normPosix(path.relative(REPO_ROOT, abs)));
    }
  }

  const controllerFiles = walk(modulesRoot).filter((p) => p.endsWith("controller.ts"));
  const bodyTypeRe = /@Body(?:\([^)]*\))?\s+\w+\s*:\s*(\w+)/g;
  const violations = [];

  for (const abs of controllerFiles) {
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = bodyTypeRe.exec(text)) !== null) {
      const typeName = m[1];
      if (riskyDtoNames.has(typeName)) {
        violations.push(
          `[BODY_DTO_TENANT] ${normPosix(path.relative(REPO_ROOT, abs))}: @Body() uses ${typeName} — declares tenant_id and/or tenantId (${riskyDtoNames.get(typeName)}). Tenant scope must come from Host/JWT/RLS, not client body (allowlist only with security review).`
        );
      }
    }
  }
  return violations;
}

/** --- Check: req / request body tenant --- */
function checkHttpBodyTenantAccess(allow) {
  const roots = [
    path.join(REPO_ROOT, "apps/api/src/modules"),
    path.join(REPO_ROOT, "apps/api/src/common"),
    path.join(REPO_ROOT, "apps/api/src/jobs")
  ];
  const ignored = (allow.ignoredPathsForHttpBodyTenant || [
    "apps/api/src/database/migrations/",
    "apps/api/src/scripts/",
    "apps/api/test/",
    "apps/api/dist/"
  ]).map((x) => normPosix(x.replace(/^\.\//, "")));

  const patterns = [
    { id: "HTTP_BODY.tenantId", re: /\b(?:req|request)\s*\.\s*body\s*\.\s*tenantId\b/g },
    { id: "HTTP_BODY.tenant_id", re: /\b(?:req|request)\s*\.\s*body\s*\.\s*tenant_id\b/g },
    {
      id: "HTTP_BODY['tenantId']",
      re: /\b(?:req|request)\s*\.\s*body\s*\[\s*["']tenantId["']\s*\]/g
    },
    {
      id: "HTTP_BODY['tenant_id']",
      re: /\b(?:req|request)\s*\.\s*body\s*\[\s*["']tenant_id["']\s*\]/g
    }
  ];

  const violations = [];
  for (const root of roots) {
    for (const abs of walk(root)) {
      const rel = normPosix(path.relative(REPO_ROOT, abs));
      if (isIgnoredPath(rel, ignored)) continue;
      const text = fs.readFileSync(abs, "utf8");
      for (const { id, re } of patterns) {
        re.lastIndex = 0;
        let m;
        while ((m = re.exec(text)) !== null) {
          violations.push(
            `[${id}] ${rel}:${lineNumberAt(text, m.index)}: do not read tenant scope from the HTTP body — use Host/JWT + RLS.`
          );
        }
      }
    }
  }
  return violations;
}

/** --- Check: manager.query raw SQL --- */
function checkManagerQueryTenant(allow) {
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const ignored = (allow.ignoredPathsForManagerQuery || [
    "apps/api/src/database/migrations/",
    "apps/api/src/scripts/",
    "apps/api/test/",
    "apps/api/dist/",
    "apps/api/src/database/tenant-db-context.service.ts"
  ]).map((x) => normPosix(x.replace(/^\.\//, "")));

  const violations = [];
  const re = /\bmanager\.query\s*\(/g;

  for (const abs of walk(apiRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (isIgnoredPath(rel, ignored)) continue;
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = re.exec(text)) !== null) {
      const openParen = m.index + m[0].length - 1;
      const sql = extractFirstStringOrTemplateArg(text, openParen);
      if (sql === null) {
        violations.push(
          `[MANAGER_RAW_SQL] ${rel}:${lineNumberAt(text, m.index)}: manager.query uses non-literal SQL — cannot verify tenant binding.`
        );
        continue;
      }
      if (sqlLooksSafeCatalogOrHealth(sql) || sqlShowsTenantBinding(sql)) {
        continue;
      }
      violations.push(
        `[MANAGER_RAW_SQL] ${rel}:${lineNumberAt(text, m.index)}: manager.query SQL lacks tenant_id/workspace_id/app.tenant_id binding (defense-in-depth for raw SQL).`
      );
    }
  }
  return violations;
}

const QB_TENANT_MARKERS =
  /\btenant_id\b|\btenantId\b|:tenantId|\bworkspace_id\b|\bworkspaceId\b|:workspaceId|\.tenant_id\b|\.tenantId\b/;

function queryBuilderMarkedExempt(src, qbIdx) {
  const head = src.slice(0, qbIdx);
  const lines = head.split("\n").slice(-8);
  return lines.some((ln) => ln.includes("tenant-isolation:qb-exempt"));
}

function sliceTypeormQbChain(src, qbIdx) {
  const tail = src.slice(qbIdx);
  const patterns = [
    /\.getMany\s*\(/,
    /\.getOne\s*\(/,
    /\.execute\s*\(/,
    /\.getCount\s*\(/,
    /\.getRawMany\s*[\(<]/,
    /\.getRawOne\s*[\(<]/
  ];
  let end = tail.length;
  for (const re of patterns) {
    re.lastIndex = 0;
    const m = re.exec(tail);
    if (m) {
      end = Math.min(end, m.index + m[0].length);
    }
  }
  return tail.slice(0, end);
}

function checkCreateQueryBuilderTenant(allow) {
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const ignored = (allow.ignoredPathsForQueryBuilderTenant || []).map((x) =>
    normPosix(x.replace(/^\.\//, ""))
  );
  const violations = [];
  const re = /\.createQueryBuilder\s*\(/g;

  for (const abs of walk(apiRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (isIgnoredPath(rel, ignored)) continue;
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = re.exec(text)) !== null) {
      if (queryBuilderMarkedExempt(text, m.index)) continue;
      const chain = sliceTypeormQbChain(text, m.index);
      if (!QB_TENANT_MARKERS.test(chain)) {
        violations.push(
          `[QUERY_BUILDER_TENANT] ${rel}:${lineNumberAt(text, m.index)}: TypeORM QueryBuilder chain has no tenant_id / tenantId / workspace_id predicate — add an explicit tenant/workspace filter, or place // tenant-isolation:qb-exempt on the preceding line with justification.`
        );
      }
    }
  }
  return violations;
}

/** --- Check 3: Active runtime SECURITY DEFINER registry --- */
function extractSqlTemplateLiterals(tsContent) {
  const out = [];
  const re = /(?:queryRunner|dataSource)\.query\s*\(\s*`([\s\S]*?)`\s*[,)]/g;
  let m;
  while ((m = re.exec(tsContent)) !== null) {
    out.push(m[1]);
  }
  return out;
}

function extractFunctionsWithSecurityDefiner(sql) {
  if (!/\bSECURITY\s+DEFINER\b/i.test(sql)) return [];
  const names = new Set();
  const re = /CREATE\s+(?:OR\s+REPLACE\s+)?FUNCTION\s+([a-z0-9_]+)\s*\(/gi;
  let m;
  while ((m = re.exec(sql)) !== null) {
    names.add(m[1].toLowerCase());
  }
  return [...names];
}

function parseSecurityDefinerDocFunctions(docMarkdown) {
  if (/Active runtime `SECURITY DEFINER` functions:\s*none/i.test(docMarkdown)) {
    return new Set();
  }
  const names = new Set();
  const rowRe = /`public\.([a-z0-9_]+)\(/gi;
  let m;
  while ((m = rowRe.exec(docMarkdown)) !== null) {
    names.add(m[1].toLowerCase());
  }
  return names;
}

function checkSecurityDefinerRegistry() {
  const docPath = path.join(REPO_ROOT, "docs/security/security-definer.md");
  if (!fs.existsSync(docPath)) {
    return [`[SECURITY_DEFINER_DOC] Missing ${normPosix(path.relative(REPO_ROOT, docPath))}`];
  }
  const documented = parseSecurityDefinerDocFunctions(fs.readFileSync(docPath, "utf8"));
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const fromRuntime = new Set();
  for (const abs of walk(apiRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (rel.includes("/database/migrations/")) {
      continue;
    }
    const text = fs.readFileSync(abs, "utf8");
    for (const sql of extractSqlTemplateLiterals(text)) {
      for (const fn of extractFunctionsWithSecurityDefiner(sql)) {
        fromRuntime.add(fn);
      }
    }
  }

  const violations = [];
  for (const fn of fromRuntime) {
    if (!documented.has(fn)) {
      violations.push(
        `[SECURITY_DEFINER] Active runtime SECURITY DEFINER function "${fn}" is not documented in docs/security/security-definer.md.`
      );
    }
  }

  for (const fn of documented) {
    if (!fromRuntime.has(fn)) {
      violations.push(
        `[SECURITY_DEFINER] docs/security/security-definer.md lists "${fn}" but no active runtime SECURITY DEFINER SQL was found — remove stale entry.`
      );
    }
  }

  return violations;
}

function main() {
  let allow;
  try {
    allow = readAllowlist();
  } catch (e) {
    process.exit(2);
  }

  const all = [
    ...checkDataSourceQuery(allow),
    ...checkAllowlistedDataSourceQuerySql(allow),
    ...checkBodyTenantDto(allow),
    ...checkHttpBodyTenantAccess(allow),
    ...checkManagerQueryTenant(allow),
    ...checkCreateQueryBuilderTenant(allow),
    ...checkSecurityDefinerRegistry()
  ];

  if (all.length > 0) {
    for (const _v of all) {
    }
    process.exit(1);
  }
}

main();

#!/usr/bin/env node
/**
 * Tour domain architecture guardrails for CI.
 *
 * Closes the residual hole flagged in `promptq.md` Phase P2: ESLint already forbids legacy
 * `EventKind` symbols in the wizard scope, but the **API tours module** has no static linter.
 * This script greps the api `tours` source tree and fails the build if a forbidden symbol
 * appears anywhere — defensive net for refactors that re-introduce dual classification.
 *
 * Mirrors the style of `scripts/check-tenant-isolation-guardrails.mjs`.
 *
 * Checks:
 * 1) `apps/api/src/modules/tours/**` must not import or reference any legacy `EventKind`
 *    symbol (`EventKind`, `EventKindResolverInput`, `resolveEventKindFromTourContext`,
 *    `eventKindForDomainProfile`, `domainProfileFromEventKindBestEffort`).
 * 2) `apps/web/src/features/tours/wizard/**` is already lint-guarded via `.eslintrc.json`,
 *    but this script double-checks for parity (cheap belt-and-suspenders).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const FORBIDDEN_SYMBOLS = [
  "EventKind",
  "EventKindResolverInput",
  "resolveEventKindFromTourContext",
  "eventKindForDomainProfile",
  "domainProfileFromEventKindBestEffort",
];

// Self-referential files: fitness specs that LIST the forbidden symbols as string literals.
// Excluding them is safe because each such file lives next to the rule it enforces and is
// covered by independent peer review when added.
const SELF_REFERENTIAL_FITNESS_FILES = new Set([
  "apps/api/src/modules/tours/fitness.spec.ts",
]);

const SCOPES = [
  {
    label: "apps/api tours module",
    root: path.join(REPO_ROOT, "apps/api/src/modules/tours"),
    extensions: [".ts"],
    ignoredFileSuffixes: [".d.ts"],
  },
  {
    label: "apps/web wizard scope",
    root: path.join(REPO_ROOT, "apps/web/src/features/tours/wizard"),
    extensions: [".ts", ".tsx"],
    ignoredFileSuffixes: [".d.ts"],
  },
];

function walk(dir, exts, acc = []) {
  if (!fs.existsSync(dir)) return acc;
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === "node_modules" || ent.name === "dist" || ent.name === ".next") continue;
      walk(p, exts, acc);
    } else if (ent.isFile() && exts.some((ext) => ent.name.endsWith(ext))) {
      acc.push(p);
    }
  }
  return acc;
}

function normPosix(p) {
  return p.split(path.sep).join("/");
}

// Strip line- and block- comments from TypeScript source so the symbol scan does not flag
// legitimate documentation that names the legacy symbols (e.g. recipe blocks in
// `profileRules/rules.ts`). Naive but sufficient — does not need to be lossless; we only
// care about whether a forbidden identifier appears in **code**.
function stripComments(source) {
  // Remove block comments (non-greedy).
  let out = source.replace(/\/\*[\s\S]*?\*\//g, "");
  // Remove line comments (full line or end-of-line).
  out = out.replace(/(^|[^:])\/\/.*$/gm, "$1");
  return out;
}

function scanScope({ label, root, extensions, ignoredFileSuffixes }) {
  const files = walk(root, extensions).filter(
    (p) => !ignoredFileSuffixes.some((suffix) => p.endsWith(suffix)),
  );
  const violations = [];
  for (const abs of files) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (SELF_REFERENTIAL_FITNESS_FILES.has(rel)) continue;
    const text = stripComments(fs.readFileSync(abs, "utf8"));
    for (const symbol of FORBIDDEN_SYMBOLS) {
      const re = new RegExp(`\\b${symbol}\\b`);
      if (re.test(text)) {
        violations.push({ scope: label, file: rel, symbol });
      }
    }
  }
  return violations;
}

let allViolations = [];
for (const scope of SCOPES) {
  allViolations = allViolations.concat(scanScope(scope));
}

if (allViolations.length === 0) {
  process.exit(0);
}

for (const _v of allViolations) {
}
process.exit(1);

#!/usr/bin/env node
/**
 * Phase 7 — tour RBAC / validation drift guardrails (prompt.md).
 *
 * Static parity checks (no DB):
 * 1. PATCH rank gates: @repo/types ↔ API tour-patch-field-policy ↔ web editCoreFieldConfig
 * 2. PATCH DTO coverage: every UpdateTourDto key appears in API policy matrix
 * 3. Write pipeline wiring on ToursController
 * 4. Submit-required wiring: API uses @repo/types getRequiredSubmitFieldPathsForProfile
 *
 * Run parity unit tests separately in CI (see architecture-guardrails tour-rbac-parity job).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const failures = [];

function fail(message) {
  failures.push(message);
}

function readRepo(relPath) {
  const abs = path.join(REPO_ROOT, relPath);
  if (!fs.existsSync(abs)) {
    fail(`missing file: ${relPath}`);
    return "";
  }
  return fs.readFileSync(abs, "utf8");
}

/** Extract `{ dtoKey, minRoleForEdit }` rows from TS policy tables. */
function extractPatchRankGates(source, arrayName) {
  const gates = new Map();
  const arrayStart = source.indexOf(arrayName);
  if (arrayStart < 0) {
    return gates;
  }
  const slice = source.slice(arrayStart, arrayStart + 12_000);
  const ruleRe =
    /dtoKey:\s*["']([^"']+)["'][^{]*minRoleForEdit:\s*["']([^"']+)["']/g;
  let match;
  while ((match = ruleRe.exec(slice)) !== null) {
    gates.set(match[1], match[2]);
  }
  return gates;
}

/** Web `CORE_ROLE_OVERRIDES` leader gates → wire DTO keys. */
function extractWebCoreLeaderGates(source) {
  const gates = new Map();
  const wireByEditId = {
    "core.totalCapacity": "total_capacity",
    "core.capacity": "total_capacity",
  };
  const block = source.includes("CORE_ROLE_OVERRIDES")
    ? source.slice(source.indexOf("CORE_ROLE_OVERRIDES"))
    : source;
  const re =
    /["'](core\.(?:totalCapacity|capacity))["']:\s*\{[^}]*minRoleForEdit:\s*["']([^"']+)["']/g;
  let match;
  while ((match = re.exec(block)) !== null) {
    const wireKey = wireByEditId[match[1]];
    if (wireKey) {
      gates.set(wireKey, match[2]);
    }
  }
  return gates;
}

const TOUR_PATCH_CONTRACT_REL = "packages/shared-contracts/src/tours/tour-patch-contract.ts";

function extractApiPolicyDtoKeys(source) {
  const keys = new Set();
  const arrayStart =
    source.indexOf("TOUR_PATCH_CONTRACT_RULES") >= 0
      ? source.indexOf("TOUR_PATCH_CONTRACT_RULES")
      : source.indexOf("TOUR_PATCH_FIELD_POLICY_RULES");
  if (arrayStart < 0) {
    return keys;
  }
  const slice = source.slice(arrayStart, arrayStart + 14_000);
  const re = /dtoKey:\s*["']([^"']+)["']/g;
  let match;
  while ((match = re.exec(slice)) !== null) {
    keys.add(match[1]);
  }
  return keys;
}

function extractUpdateTourDtoKeys(source) {
  const keys = new Set();
  const classMatch = source.match(/export class UpdateTourDto\s*\{([\s\S]*?)^\}/m);
  if (!classMatch) {
    return keys;
  }
  const body = classMatch[1];
  const re = /^\s{2}([a-zA-Z][\w]*)\??:/gm;
  let match;
  while ((match = re.exec(body)) !== null) {
    keys.add(match[1]);
  }
  return keys;
}

function checkPatchRankGateParity() {
  const typesSrc = readRepo("packages/types/src/tour-patch-field-policy.ts");
  const contractSrc = readRepo(TOUR_PATCH_CONTRACT_REL);
  const webSrc = readRepo("apps/web/src/features/tours/config/editCoreFieldConfig.ts");

  const typesGates = extractPatchRankGates(typesSrc, "TOUR_PATCH_FIELD_RULES");
  const apiGates = extractPatchRankGates(contractSrc, "TOUR_PATCH_CONTRACT_RULES");
  const webGates = extractWebCoreLeaderGates(webSrc);

  for (const [dtoKey, minRole] of typesGates) {
    const apiRole = apiGates.get(dtoKey);
    if (apiRole !== minRole) {
      fail(
        `[patch-rank] @repo/types ${dtoKey} minRole=${minRole} but API has ${apiRole ?? "none"}`,
      );
    }
    const webRole = webGates.get(dtoKey);
    if (webRole !== minRole) {
      fail(
        `[patch-rank] @repo/types ${dtoKey} minRole=${minRole} but web editCore maps to ${webRole ?? "none"}`,
      );
    }
  }

  for (const [dtoKey, minRole] of apiGates) {
    if (!typesGates.has(dtoKey)) {
      fail(
        `[patch-rank] API ranks ${dtoKey}@${minRole} but @repo/types TOUR_PATCH_FIELD_RULES omits it — extend types mirror`,
      );
    }
  }
}

function checkPatchDtoCoverage() {
  const dtoSrc = readRepo("apps/api/src/modules/tours/dto/update-tour.dto.ts");
  const contractSrc = readRepo(TOUR_PATCH_CONTRACT_REL);
  const dtoKeys = extractUpdateTourDtoKeys(dtoSrc);
  const policyKeys = extractApiPolicyDtoKeys(contractSrc);

  for (const key of dtoKeys) {
    if (!policyKeys.has(key)) {
      fail(`[patch-coverage] UpdateTourDto.${key} missing from TOUR_PATCH_FIELD_POLICY_RULES`);
    }
  }

  for (const key of policyKeys) {
    if (!dtoKeys.has(key)) {
      fail(`[patch-coverage] policy dtoKey ${key} not found on UpdateTourDto`);
    }
  }
}

function checkWritePipelineWiring() {
  const controller = readRepo("apps/api/src/modules/tours/tours.controller.ts");
  if (!controller.includes("assertTourPatchWritePreMerge")) {
    fail("[pipeline] ToursController.update must call assertTourPatchWritePreMerge");
  }
  if (!controller.includes("assertTourCreateWritePreMerge")) {
    fail("[pipeline] ToursController.create must call assertTourCreateWritePreMerge");
  }
  if (controller.includes("assertTourPatchAbilities(")) {
    fail("[pipeline] use assertTourPatchWritePreMerge instead of direct assertTourPatchAbilities");
  }
}

function checkSubmitRequiredWiring() {
  const apiAssert = readRepo(
    "apps/api/src/modules/tours/utils/assert-profile-required-fields-for-submit.ts",
  );
  if (!apiAssert.includes("getRequiredSubmitFieldPathsForProfile")) {
    fail("[submit-required] API assert must import getRequiredSubmitFieldPathsForProfile from @repo/types");
  }
