#!/usr/bin/env node
/**
 * Ops sign-off helper: every 4xx/5xx log line in a sample drain must include structured error_code.
 *
 * Usage:
 *   node scripts/verify-production-log-sample.mjs scripts/fixtures/production-log-sample.ndjson
 *   kubectl logs ... | node scripts/verify-production-log-sample.mjs
 *
 * Env:
 *   PRODUCTION_LOG_SAMPLE — path override when no argv
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DEFAULT_FIXTURE = path.resolve(__dirname, "fixtures/production-log-sample.ndjson");

function readInput(argvPath) {
  const file = argvPath || process.env.PRODUCTION_LOG_SAMPLE || DEFAULT_FIXTURE;
  if (file && file !== "-") {
    return fs.readFileSync(path.resolve(file), "utf8");
  }
  return fs.readFileSync(0, "utf8");
}

function httpStatusFromRecord(obj) {
  if (typeof obj.status === "number") {
    return obj.status;
  }
  if (typeof obj.status_code === "number") {
    return obj.status_code;
  }
  if (typeof obj.http_status === "number") {
    return obj.http_status;
  }
  const nested = obj.error ?? obj.err;
  if (nested && typeof nested.status === "number") {
    return nested.status;
  }
  return undefined;
}

function errorCodeFromRecord(obj) {
  if (typeof obj.error_code === "string" && obj.error_code.trim()) {
    return obj.error_code.trim();
  }
  if (obj.error && typeof obj.error.code === "string" && obj.error.code.trim()) {
    return obj.error.code.trim();
  }
  if (typeof obj.code === "string" && obj.code.trim() && obj.code !== obj.level) {
    return obj.code.trim();
  }
  return undefined;
}

function main() {
  const raw = readInput(process.argv[2]);
  const lines = raw.split("\n").map((l) => l.trim()).filter(Boolean);
  const violations = [];
  let _clientErrors = 0;
  let _serverErrors = 0;
  let _okLines = 0;

  for (let i = 0; i < lines.length; i += 1) {
    const lineNo = i + 1;
    let obj;
    try {
      obj = JSON.parse(lines[i]);
    } catch {
      violations.push(`line ${lineNo}: invalid JSON`);
      continue;
    }

    const status = httpStatusFromRecord(obj);
    if (status === undefined || status < 400) {
      _okLines += 1;
      continue;
    }
    if (status >= 500) {
      _serverErrors += 1;
    } else {
      _clientErrors += 1;
    }

    const code = errorCodeFromRecord(obj);
    if (!code || code === "UNKNOWN_ERROR") {
      violations.push(`line ${lineNo}: status=${status} missing structured error_code`);
    }
  }

  if (violations.length > 0) {
    for (const _v of violations.slice(0, 20)) {
    }
    if (violations.length > 20) {
    }
    process.exit(1);
  }

}

main();

#!/usr/bin/env npx tsx
/**
 * Diagnostic: compare registry-derived canonical Zod shape vs production
 * `denaliCanonicalTourSchema`.
 *
 * Does not modify production schemas or run in CI/build.
 *
 * Run from repo root:
 *   pnpm --dir apps/web exec tsx --tsconfig tsconfig.json ../../scripts/verify-schema-parity.ts
 */

import {
  DENALI_CANONICAL_CATEGORY_VALUES,
  DENALI_CANONICAL_DURATION_VALUES,
  DENALI_CANONICAL_TRANSPORT_MODE_VALUES,
} from "@repo/types/denali";
import { z } from "zod";

import {
  TOUR_TITLE_MAX_LENGTH,
  TOUR_TITLE_MIN_LENGTH,
} from "../apps/web/src/features/tours/models/tours-new-validation-messages";
import {
  DENALI_FIELD_DEFINITIONS,
  type DenaliFieldDefinition,
  type DenaliZodFieldKind,
} from "../apps/web/src/features/tours/wizard/denali/registry/denaliFieldRegistryData";
import { denaliGearItemSchema } from "../apps/web/src/features/tours/wizard/schemas/denaliGearItemSchema";
import {
  denaliCanonicalItineraryDayRowSchema,
  optionalApproximateReturnTimeSchema,
} from "../apps/web/src/features/tours/wizard/schemas/denaliItineraryDaySchema";
import { denaliLocationDataSchema } from "../apps/web/src/features/tours/wizard/schemas/denaliLocationDataSchema";
import { denaliCanonicalTourSchema } from "../apps/web/src/features/tours/wizard/schemas/denaliCanonicalTourSchema.unified";

const UUID_V4 = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function isParsableIsoDateTime(value: string): boolean {
  const trimmed = value.trim();
  if (!trimmed) return false;
  return !Number.isNaN(Date.parse(trimmed));
}

const denaliCanonicalCategorySchema = z.enum(DENALI_CANONICAL_CATEGORY_VALUES);
const denaliCanonicalDurationSchema = z.enum(DENALI_CANONICAL_DURATION_VALUES);
const denaliCanonicalTransportModeSchema = z.enum(DENALI_CANONICAL_TRANSPORT_MODE_VALUES);

const denaliCanonicalGearItemSchema = denaliGearItemSchema.extend({
  id: z.string().regex(UUID_V4, "شناسه تجهیزات معتبر نیست."),
});

const denaliCanonicalPhotoSchema = z
  .object({
    id: z.string().regex(UUID_V4),
    url: z.string().url(),
    filename: z.string().trim().min(1),
    size: z.number().int().min(0).max(5 * 1024 * 1024),
    mimeType: z.string().regex(/^image\/(jpeg|png|webp)$/),
    uploadedAt: z.string().trim().refine(isParsableIsoDateTime),
  })
  .strict();

const denaliCanonicalGatheringPointRowSchema = z
  .object({
    id: z.string().optional(),
    title: z.string().default(""),
    time: z.string().optional(),
    location: denaliLocationDataSchema,
  })
  .strict();

/** Registry zodKind → canonical-field Zod (mirrors denaliCanonicalTourSchema.ts). */
function zodForCanonicalKind(kind: DenaliZodFieldKind): z.ZodTypeAny {
  switch (kind) {
    case "title":
      return z
        .string()
        .trim()
        .min(TOUR_TITLE_MIN_LENGTH)
        .max(TOUR_TITLE_MAX_LENGTH);
    case "tourType":
      return denaliCanonicalCategorySchema;
    case "publishStatus":
      return z.enum(["draft", "active"]).optional();
    case "destinationId":
      return z.string().regex(UUID_V4);
    case "isoDateTime":
      return z.string().trim().refine(isParsableIsoDateTime);
    case "isoDateTimeOptional":
      return z.string().trim().optional().refine(
        (v) => v == null || v === "" || isParsableIsoDateTime(v),
      );
    case "capacityMax":
      return z.number().int().min(1).optional();
    case "optionalInt":
      return z.number().int().min(0).optional();
    case "optionalPositiveInt":
      return z.number().int().min(1).optional();
    case "stringOptional":
      return z.string().trim().optional();
    case "stringArrayDefault":
      return z.array(z.string().regex(UUID_V4)).default([]);
    case "booleanOptional":
      return z.boolean().optional();
    case "socialMediaLink":
      return z.string().trim().max(2048).optional();
    case "approximateReturnTime":
      return optionalApproximateReturnTimeSchema();
    case "difficultyLevel":
      return z.number().min(1).max(10).default(5);
    case "itinerary":
      return z.array(denaliCanonicalItineraryDayRowSchema).optional();
    case "locationData":
      return denaliLocationDataSchema.optional();
    case "gatheringPoints":
      return z.array(denaliCanonicalGatheringPointRowSchema).optional();
    case "gearItems":
      return z.array(denaliCanonicalGearItemSchema).optional();
    case "transportMode":
      return denaliCanonicalTransportModeSchema;
    case "adminCapacityApproval":
      return z.boolean().optional();
    case "photos":
      return z.array(denaliCanonicalPhotoSchema).max(10).optional();
    case "paymentMode":
      return z.enum(["offline_receipt"]);
    case "fitnessLevel":
      return z.enum(["low", "medium", "high"]).optional();
    case "minRequiredPeaks":
      return z.number().int().min(1).max(4).optional();
    default: {
      const _exhaustive: never = kind;
      return _exhaustive;
    }
  }
}

function zodForRegistryField(def: DenaliFieldDefinition): z.ZodTypeAny {
  if (def.canonicalPath === "category") {
    return denaliCanonicalCategorySchema;
  }
  if (def.canonicalPath === "duration") {
    return denaliCanonicalDurationSchema;
  }
  if (def.canonicalPath === "transport.mode") {
    return denaliCanonicalTransportModeSchema;
  }
  if (def.canonicalPath === "transport.transportCost") {
    return z.number().int().min(1).optional();
  }
  if (def.canonicalPath === "transport.dongAmount") {
    return z.number().int().min(1).optional();
  }
  if (def.canonicalPath === "transport.seatPreference") {
    return z.enum(["window", "aisle", "any"]).optional();
  }
  if (def.canonicalPath === "program.themeIds") {
    return z.array(z.string().regex(UUID_V4)).default([]);
  }
  if (def.canonicalPath === "program.shortDescription") {
    return z.string().trim().min(1);
  }
  if (def.canonicalPath === "pricing.paymentMode") {
    return z.enum(["offline_receipt"]);
  }
  if (def.canonicalPath === "pricing.basePricePerPerson") {
    return z.number().int().min(1).optional();
  }
  return zodForCanonicalKind(def.zodKind);
}

type ShapeTree = {
  fields: Map<string, z.ZodTypeAny>;
  children: Map<string, ShapeTree>;
};

function emptyTree(): ShapeTree {
  return { fields: new Map(), children: new Map() };
}

function insertField(tree: ShapeTree, canonicalPath: string, fieldSchema: z.ZodTypeAny): void {
  const parts = canonicalPath.split(".");
  let node = tree;
  for (let i = 0; i < parts.length - 1; i += 1) {
    const segment = parts[i]!;
    let child = node.children.get(segment);
    if (!child) {
      child = emptyTree();
      node.children.set(segment, child);
    }
    node = child;
  }
  const leaf = parts[parts.length - 1]!;
  node.fields.set(leaf, fieldSchema);
}

function compileTree(tree: ShapeTree, strict: boolean): z.ZodObject {
  const shape: Record<string, z.ZodTypeAny> = {};
  for (const [key, schema] of tree.fields) {
    shape[key] = schema;
  }
  for (const [key, child] of tree.children) {
    shape[key] = compileTree(child, true);
  }
  const obj = z.object(shape);
  return strict ? obj.strict() : obj;
}

const NESTED_STRICT_SECTIONS = new Set([
  "program",
  "transport",
  "pricing",
  "participants",
  "policies",
]);

/**
 * Builds a Zod object schema from {@link DENALI_FIELD_DEFINITIONS} using canonical paths
 * (same nesting as {@link denaliCanonicalTourSchema}).
 */
export function generateSchemaFromRegistry(): z.ZodObject {
  const root = emptyTree();

  for (const def of DENALI_FIELD_DEFINITIONS) {
    insertField(root, def.canonicalPath, zodForRegistryField(def));
  }

  const shape: Record<string, z.ZodTypeAny> = {};
  for (const [key, schema] of root.fields) {
    shape[key] = schema;
  }
  for (const [key, child] of root.children) {
    const strict = NESTED_STRICT_SECTIONS.has(key);
    shape[key] = compileTree(child, strict);
  }

  return z.object(shape);
}

// --- Zod introspection for deep shape comparison ---

type ZodDefLike = {
  type?: string;
  schema?: z.ZodTypeAny;
  innerType?: z.ZodTypeAny;
  in?: z.ZodTypeAny;
  out?: z.ZodTypeAny;
  element?: z.ZodTypeAny;
};

function unwrapZodType(schema: z.ZodTypeAny | undefined): z.ZodTypeAny {
  if (schema == null) {
    throw new Error("unwrapZodType: received undefined schema");
  }
  let cur: z.ZodTypeAny = schema;
  for (let guard = 0; guard < 32; guard += 1) {
    if (cur instanceof z.ZodOptional || cur instanceof z.ZodDefault || cur instanceof z.ZodNullable) {
      cur = (cur as z.ZodOptional | z.ZodDefault | z.ZodNullable)._def.innerType as z.ZodTypeAny;
      continue;
    }
    const def = cur._def as ZodDefLike;
    if (
      (def.type === "optional" || def.type === "default" || def.type === "nullable") &&
      def.innerType
    ) {
      cur = def.innerType;
      continue;
    }
    if (def.type === "pipe" && def.in) {
      cur = def.in;
      continue;
    }
    if ((def.type === "effects" || def.type === "refinement") && def.schema) {
      cur = def.schema;
      continue;
    }
    break;
  }
  return cur;
}

function getZodArrayElement(schema: z.ZodArray): z.ZodTypeAny {
  const withElement = schema as z.ZodArray & { element?: z.ZodTypeAny };
  return withElement.element ?? (schema._def as ZodDefLike).element!;
}

function isOptionalZod(schema: z.ZodTypeAny): boolean {
  let cur: z.ZodTypeAny = schema;
  for (let guard = 0; guard < 16; guard += 1) {
    if (cur instanceof z.ZodOptional || cur instanceof z.ZodDefault || cur instanceof z.ZodNullable) {
      return true;
    }
    const def = cur._def as ZodDefLike;
    if (def.type === "optional" || def.type === "default" || def.type === "nullable") {
      return true;
    }
    if (def.type === "pipe" && def.in) {
      cur = def.in;
      continue;
    }
    if ((def.type === "effects" || def.type === "refinement") && def.schema) {
      cur = def.schema;
      continue;
    }
    break;
  }
  return false;
}

function describeZodType(schema: z.ZodTypeAny): string {
  const optional = isOptionalZod(schema);
  const base = describeZodTypeCore(unwrapZodType(schema));
  return optional ? `${base}?` : base;
}

function describeZodTypeCore(schema: z.ZodTypeAny): string {
  if (schema instanceof z.ZodString) {
    return "string";
  }
  if (schema instanceof z.ZodNumber) {
    return "number";
  }
  if (schema instanceof z.ZodBoolean) {
    return "boolean";
  }
  if (schema instanceof z.ZodEnum) {
    const values = schema.options as readonly string[];
    return `enum(${values.join("|")})`;
  }
  if (schema instanceof z.ZodLiteral) {
    return `literal(${String(schema.value)})`;
  }
  if (schema instanceof z.ZodArray) {
    const inner = unwrapZodType(getZodArrayElement(schema));
    if (inner instanceof z.ZodObject) {
      return "array<object>";
    }
    return `array<${describeZodTypeCore(inner)}>`;
  }
  if (schema instanceof z.ZodObject) {
    return "object";
  }
  if (schema instanceof z.ZodUnion) {
    const options = schema._def.options as z.ZodTypeAny[];
    const parts = options.map((o) => describeZodTypeCore(unwrapZodType(o)));
    return `union(${parts.join(",")})`;
  }
  const typeName = (schema._def as { typeName?: string }).typeName ?? schema.constructor.name;
  return typeName;
}

function _resolveObjectRoot(schema: z.ZodTypeAny): z.ZodObject {
  let cur = schema;
  for (let guard = 0; guard < 16; guard += 1) {
    const unwrapped = unwrapZodType(cur);
    if (unwrapped instanceof z.ZodObject) {
      return unwrapped;
    }
    const def = cur._def as { typeName?: string; schema?: z.ZodTypeAny };
    if (def.typeName === "ZodEffects" && def.schema) {
      cur = def.schema;
      continue;
    }
    break;
  }
  throw new Error("Expected Zod object schema at root");
}

function collectFieldDescriptors(
  schema: z.ZodTypeAny,
  prefix = "",
  out = new Map<string, string>(),
): Map<string, string> {
  const obj = unwrapZodType(schema);
  if (!(obj instanceof z.ZodObject)) {
    if (prefix) {
      out.set(prefix, describeZodType(schema));
    }
    return out;
  }

  const shape = obj.shape as Record<string, z.ZodTypeAny>;
  for (const [key, child] of Object.entries(shape)) {
    const path = prefix ? `${prefix}.${key}` : key;
    const inner = unwrapZodType(child);
    if (inner instanceof z.ZodObject) {
      collectFieldDescriptors(child, path, out);
    } else if (inner instanceof z.ZodArray) {
      out.set(path, describeZodType(child));
      const element = unwrapZodType(getZodArrayElement(inner));
      if (element instanceof z.ZodObject) {
        collectFieldDescriptors(element, `${path}[]`, out);
      }
    } else {
      out.set(path, describeZodType(child));
    }
  }
  return out;
}

/** Registry-only canonical paths allowed to be absent from production submit schema. */
const REGISTRY_AHEAD_ALLOWLIST = new Set([
  "eventVariant",
  "transport.seatPreference",
]);

interface ParityMismatch {
  path: string;
  kind: "TYPE_MISMATCH" | "MISSING_IN_REGISTRY" | "MISSING_IN_PROD_SCHEMA";
  registryType?: string;
  productionType?: string;
}

function isBlockingMismatch(m: ParityMismatch): boolean {
  if (m.kind === "TYPE_MISMATCH" || m.kind === "MISSING_IN_REGISTRY") {
    return true;
  }
  if (m.kind === "MISSING_IN_PROD_SCHEMA") {
    return !REGISTRY_AHEAD_ALLOWLIST.has(m.path);
  }
  return false;
}

function partitionMismatches(mismatches: ParityMismatch[]): {
  blocking: ParityMismatch[];
  registryAhead: ParityMismatch[];
} {
  const blocking: ParityMismatch[] = [];
  const registryAhead: ParityMismatch[] = [];
  for (const m of mismatches) {
    if (isBlockingMismatch(m)) {
      blocking.push(m);
    } else if (
      m.kind === "MISSING_IN_PROD_SCHEMA" &&
      REGISTRY_AHEAD_ALLOWLIST.has(m.path)
    ) {
      registryAhead.push(m);
    }
  }
  return { blocking, registryAhead };
}

function compareDescriptorMaps(
  registryMap: Map<string, string>,
  productionMap: Map<string, string>,
): ParityMismatch[] {
  const mismatches: ParityMismatch[] = [];
  const allPaths = new Set([...registryMap.keys(), ...productionMap.keys()]);

  for (const path of [...allPaths].sort()) {
    const reg = registryMap.get(path);
    const prod = productionMap.get(path);

    if (reg == null && prod != null) {
      mismatches.push({
        path,
        kind: "MISSING_IN_REGISTRY",
        productionType: prod,
      });
      continue;
    }
    if (reg != null && prod == null) {
      mismatches.push({
        path,
        kind: "MISSING_IN_PROD_SCHEMA",
        registryType: reg,
      });
      continue;
    }
    if (reg != null && prod != null && reg !== prod) {
      mismatches.push({
        path,
        kind: "TYPE_MISMATCH",
        registryType: reg,
        productionType: prod,
      });
    }
  }

  return mismatches;
}

function printMismatchRows(kind: ParityMismatch["kind"], rows: ParityMismatch[]): void {
  if (rows.length === 0) return;
  for (const _row of rows) {
    if (kind === "TYPE_MISMATCH") {
    } else if (kind === "MISSING_IN_REGISTRY") {
    } else {
    }
  }
}

function printReport(blocking: ParityMismatch[], registryAhead: ParityMismatch[]): void {

  if (blocking.length === 0 && registryAhead.length === 0) {
    return;
  }

  if (blocking.length > 0) {
    printMismatchRows(
      "TYPE_MISMATCH",
      blocking.filter((m) => m.kind === "TYPE_MISMATCH"),
    );
    printMismatchRows(
      "MISSING_IN_REGISTRY",
      blocking.filter((m) => m.kind === "MISSING_IN_REGISTRY"),
    );
    printMismatchRows(
      "MISSING_IN_PROD_SCHEMA",
      blocking.filter((m) => m.kind === "MISSING_IN_PROD_SCHEMA"),
    );
  }

  if (registryAhead.length > 0) {
    printMismatchRows("MISSING_IN_PROD_SCHEMA", registryAhead);
  }

  if (blocking.length === 0 && registryAhead.length > 0) {
  }
}

function main(): void {
  const generated = generateSchemaFromRegistry();
  const registryMap = collectFieldDescriptors(generated);
  const productionMap = collectFieldDescriptors(denaliCanonicalTourSchema);


  const mismatches = compareDescriptorMaps(registryMap, productionMap);
  const { blocking, registryAhead } = partitionMismatches(mismatches);
  printReport(blocking, registryAhead);

  if (blocking.length > 0) {
    process.exitCode = 1;
    return;
  }
  process.exitCode = 0;
}

const invokedAsScript = process.argv[1]?.includes("verify-schema-parity");
if (invokedAsScript) {
  main();
}

#!/usr/bin/env node
/**
 * Post Phase 10–17 — Stability Lock Checklist (prompt.md).
 * Static guards + delegates to verify-phase-10-gate + run-tour-governance.
 */
import { spawnSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const failures = [];
const warnings = [];

function fail(msg) {
  failures.push(msg);
}
function warn(msg) {
  warnings.push(msg);
}

function readRepo(rel) {
  const abs = path.join(REPO_ROOT, rel);
  if (!fs.existsSync(abs)) {
    fail(`missing: ${rel}`);
    return "";
  }
  return fs.readFileSync(abs, "utf8");
}

function fileExists(rel) {
  return fs.existsSync(path.join(REPO_ROOT, rel));
}

function grepRepo(pattern, opts = {}) {
  const { excludeTests = true, excludeExample = true } = opts;
  const args = ["rg", "-l", pattern, "apps/web", "apps/api", "packages", "--glob", "!**/dist/**"];
  if (excludeTests) {
    args.push("--glob", "!**/*.spec.ts", "--glob", "!**/*.test.ts", "--glob", "!**/tests/**");
  }
  if (excludeExample) {
    args.push("--glob", "!**/.env*", "--glob", "!**/*.example");
  }
  const r = spawnSync("rg", args.slice(1), { cwd: REPO_ROOT, encoding: "utf8" });
  if (r.status === 0 && r.stdout.trim()) {
    return r.stdout.trim().split("\n");
  }
  return [];
}

function runNodeScript(name) {
  const scriptPath = path.join(REPO_ROOT, "scripts", name);
  const r = spawnSync(process.execPath, [scriptPath], {
    cwd: REPO_ROOT,
    stdio: "inherit",
    env: process.env,
  });
  if (r.status !== 0) {
    fail(`${name} exited ${r.status ?? 1}`);
  }
}


// §1 Tenant
const denaliHits = grepRepo("denali\\.localhost");
if (denaliHits.length > 0) {
  warn(`denali.localhost references (non-test): ${denaliHits.join(", ")}`);
}
if (!fileExists("apps/web/lib/tenant/runtime-tenant-context.ts")) {
  fail("missing runtime-tenant-context.ts");
}
const rtc = readRepo("apps/web/lib/tenant/runtime-tenant-context.ts");
if (!rtc.includes("x-tenant-id") || !rtc.includes("resolveTenantSlugFromHost")) {
  fail("runtime-tenant-context missing x-tenant-id or resolveTenantSlugFromHost");
}

// §8 Cookie
for (const f of [
  "apps/web/lib/auth/build-session-cookie.ts",
  "apps/web/app/api/auth/login-web-session/route.ts",
  "apps/web/app/api/auth/logout/route.ts",
]) {
  if (!fileExists(f)) fail(`missing ${f}`);
}
const loginRoute = readRepo("apps/web/app/api/auth/login-web-session/route.ts");
if (!loginRoute.includes("buildSessionCookieOptions")) {
  fail("login-web-session must use buildSessionCookieOptions");
}

// §6 Contract
for (const f of [
  "packages/shared-contracts/src/tours/tour-create-contract.ts",
  "packages/shared-contracts/src/tours/tour-patch-contract.ts",
]) {
  if (!fileExists(f)) fail(`missing ${f}`);
}

// §9 Observability
if (!fileExists("apps/api/src/common/observability/request-trace.middleware.ts")) {
  fail("missing request-trace.middleware.ts");
}
if (!fileExists("apps/api/src/common/logging/rbac-logger.ts")) {
  fail("missing rbac-logger.ts");
}

// §12 Deploy
if (!fileExists("packages/config/env-validation.ts")) {
  fail("missing packages/config/env-validation.ts");
}
const apiValidation = readRepo("apps/api/src/config/config.validation.ts");
if (!apiValidation.includes("validateDeployEnv")) {
  fail("API config.validation must call validateDeployEnv");
}

// §5 Lifecycle matrix
if (!fileExists("packages/shared/rbac/tour-lifecycle-governance.ts")) {
  fail("missing tour-lifecycle-governance.ts");
}

// §7 BFF
if (!fileExists("apps/web/lib/api/bff-fetch.ts")) {
  fail("missing bff-fetch.ts");
}

const OTP = process.env.PHASE10_OTP ?? "1234";
const MINIMAL_TOUR_BODY = {
  title: "StabilityLock TenCharMinimum",
  total_capacity: 12,
  lifecycle_status: "Draft",
  formProfile: "urban_event",
  transportModes: [],
};

function uniquePhoneForEmail(email) {
  let hash = 0;
  for (let i = 0; i < email.length; i += 1) {
    hash = (hash * 31 + email.charCodeAt(i)) >>> 0;
  }
  return `+1555${String(hash % 10_000_000).padStart(7, "0")}`;
}

function tenantWebOrigin(slug) {
  return `http://${slug}.localhost:3000`;
}

function tenantApiOrigin(slug) {
  return `http://${slug}.localhost:3001`;
}

async function apiOwnerToken(slug, email) {
  const phone = uniquePhoneForEmail(email);
  const res = await fetch(`${tenantApiOrigin(slug)}/api/v2/auth/web/session/otp`, {
    method: "POST",
    headers: {
      Host: `${slug}.localhost:3001`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ phone, otp: OTP }),
  });
  if (!res.ok) {
    throw new Error(`${slug} api login → ${res.status}`);
  }
  const body = await res.json();
  const token = typeof body.session_token === "string" ? body.session_token.trim() : "";
  if (!token) {
    throw new Error(`${slug} api login: missing session_token`);
  }
  return token;
}

async function checkSessionPersistence() {
  const slug = "ws1-rbac";
  const origin = tenantWebOrigin(slug);
  const phone = uniquePhoneForEmail("ws1-owner@test.com");
  const loginRes = await fetch(`${origin}/api/auth/login-web-session`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ phone, otp: OTP }),
  });
  if (!loginRes.ok) {
    throw new Error(`BFF login → ${loginRes.status}`);
  }
  const setCookies = loginRes.headers.getSetCookie?.() ?? [];
  const cookie = setCookies.map((c) => c.split(";")[0]).join("; ");
  if (!cookie.includes("session=")) {
    throw new Error("BFF login: missing session cookie");
  }
  for (let i = 0; i < 2; i += 1) {
    const sessionRes = await fetch(`${origin}/api/auth/session`, {
      headers: { Cookie: cookie },
      cache: "no-store",
    });
    if (!sessionRes.ok) {
      throw new Error(`GET /api/auth/session #${i + 1} → ${sessionRes.status}`);
    }
    const payload = await sessionRes.json();
    if (payload.authenticated !== true) {
      throw new Error(`session not persisted on read #${i + 1}`);
    }
  }
  const logoutRes = await fetch(`${origin}/api/auth/logout`, {
    method: "POST",
    headers: { Cookie: cookie },
  });
  if (!logoutRes.ok) {
    throw new Error(`logout → ${logoutRes.status}`);
  }
  const clearedJar = logoutRes.headers.getSetCookie?.() ?? [];
  const afterCookie =
    clearedJar.length > 0
      ? clearedJar.map((c) => c.split(";")[0]).join("; ")
      : "";
  const afterRes = await fetch(`${origin}/api/auth/session`, {
    headers: afterCookie ? { Cookie: afterCookie } : { Cookie: "session=" },
    cache: "no-store",
  });
  const afterPayload = await afterRes.json();
  if (afterPayload.authenticated === true) {
    throw new Error("logout did not clear session");
  }
}

async function checkIllegalLifecycleSkipOpen() {
  const slug = "ws1-rbac";
  const token = await apiOwnerToken(slug, "ws1-owner@test.com");
  const host = `${slug}.localhost:3001`;
  const api = tenantApiOrigin(slug);
  const { randomUUID } = await import("node:crypto");

  const createRes = await fetch(`${api}/api/v2/tours`, {
    method: "POST",
    headers: {
      Host: host,
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
      "Idempotency-Key": randomUUID(),
    },
    body: JSON.stringify(MINIMAL_TOUR_BODY),
  });
  if (createRes.status !== 201) {
    throw new Error(`CREATE draft → ${createRes.status}`);
  }
  const { id: tourId } = await createRes.json();

  const skipOpen = await fetch(`${api}/api/v2/tours/${tourId}`, {
    method: "PATCH",
    headers: {
      Host: host,
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
      "Idempotency-Key": randomUUID(),
    },
    body: JSON.stringify({ lifecycle_status: "CLOSED" }),
  });
  if (skipOpen.status !== 400) {
    const text = await skipOpen.text();
    throw new Error(`DRAFT→CLOSED expected 400, got ${skipOpen.status}: ${text.slice(0, 200)}`);
  }
  const errBody = await skipOpen.json();
  const code = errBody?.error?.code;
  const allowed = new Set(["INVALID_LIFECYCLE_TRANSITION", "STATE_TRANSITION_INVALID"]);
  if (!allowed.has(code)) {
    throw new Error(`DRAFT→CLOSED expected lifecycle error code, got ${code}`);
  }
}

function scanStrayHostSplit() {
  const allowed = new Set([
    path.join(REPO_ROOT, "apps/web/lib/tenant/runtime-tenant-context.ts"),
    path.join(REPO_ROOT, "apps/api/src/modules/tenant/tenant-host-resolver.service.ts"),
    path.join(REPO_ROOT, "packages/tenant-host/src/normalize-inbound-hostname.ts"),
  ]);
  const r = spawnSync(
    "rg",
    ["host\\.split\\(", "apps/web/lib/tenant", "apps/api/src/common/tenant", "-g", "!**/*.spec.ts"],
    { cwd: REPO_ROOT, encoding: "utf8" },
  );
  if (r.status !== 0) {
    return;
  }
  for (const line of r.stdout.trim().split("\n")) {
    if (!line) continue;
    const filePath = line.split(":")[0];
    const abs = path.isAbsolute(filePath) ? filePath : path.join(REPO_ROOT, filePath);
    if (!allowed.has(abs) && line.includes('split(".")')) {
      fail(`stray host.split("."): ${line}`);
    }
  }
}

scanStrayHostSplit();
if (!fileExists("apps/web/lib/tenant/resolve-tenant-context-helpers.ts")) {
} else {
  warn("resolve-tenant-context-helpers.ts still present");
}

runNodeScript("run-tour-governance.mjs");

async function runRuntimeChecks() {
  const apiUp =
    spawnSync("curl", ["-sf", "http://127.0.0.1:3001/health"], { encoding: "utf8" }).status === 0;
  const webUp =
    spawnSync("curl", ["-sf", "-o", "/dev/null", "http://ws1-rbac.localhost:3000/api/auth/session"], {
      encoding: "utf8",
    }).status === 0;

  if (!apiUp) {
    warn("API :3001 not up — skipping runtime lifecycle + phase-10 gate");
    return;
  }

  try {
    await checkIllegalLifecycleSkipOpen();
  } catch (e) {
    fail(`§5 lifecycle: ${e.message}`);
  }

  if (webUp) {
    try {
      await checkSessionPersistence();
    } catch (e) {
      fail(`§2 session: ${e.message}`);
    }
  } else {
    warn("Web :3000 not up — skipping BFF session persistence check");
  }

  runNodeScript("verify-phase-10-gate.mjs");
}

runRuntimeChecks().then(() => {
  if (warnings.length) {
  }
  if (failures.length) {
    process.exit(1);
  }
});

#!/usr/bin/env node
/**
 * Infrastructure sign-off — API HTTP errors must log structured `error_code` and return envelope JSON.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const FILTER_PATH = path.resolve(
  __dirname,
  "../apps/api/src/common/errors/global-exception.filter.ts",
);

function main() {
  const text = fs.readFileSync(FILTER_PATH, "utf8");
  const violations = [];

  const errorLogCalls = [...text.matchAll(/this\.loggerService\.error\s*\(\s*["'`]([^"'`]+)["'`]/g)];
  for (const match of errorLogCalls) {
    const label = match[1];
    const idx = match.index ?? 0;
    const slice = text.slice(idx, idx + 600);
    if (!slice.includes("error_code:")) {
      const line = text.slice(0, idx).split("\n").length;
      violations.push(
        `[STRUCTURED_ERROR_LOG] global-exception.filter.ts:${line} — logger "${label}" missing error_code`,
      );
    }
  }

  if (!text.includes("buildEnvelope(")) {
    violations.push("[STRUCTURED_ERROR_BODY] buildEnvelope() not used in GlobalExceptionFilter");
  }

  if (!text.includes("success: false")) {
    violations.push("[STRUCTURED_ERROR_BODY] success:false envelope shape not found");
  }

  const unknownFallback = text.match(/code:\s*["']UNKNOWN_ERROR["']/g);
  if (unknownFallback && unknownFallback.length > 2) {
    violations.push(
      "[STRUCTURED_ERROR_CODE] excessive UNKNOWN_ERROR fallbacks — map to GlobalErrorTaxonomy",
    );
  }

  if (violations.length > 0) {
    for (const _v of violations) {
    }
    process.exit(1);
  }

}

main();
